-- Poems batch 459
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-14','感懷','鮑溶','唐','御定全唐诗','yuding','','[]','宿心不覺遠，事去勞追憶。曠古川上懷，東流幾時息。',48,'御定全唐詩/json/485.json','["宿心不覺遠，事去勞追憶。曠古川上懷，東流幾時息。", "門前青山路，眼見歸不得。曉夢雲月光，過秋蘭蕙色。"]'),
('yuding-15','經秦皇墓','鮑溶','唐','御定全唐诗','yuding','','[]','左崗青虯盤，右阪白虎踞。誰識此中陵，祖龍藏身處。',96,'御定全唐詩/json/485.json','["左崗青虯盤，右阪白虎踞。誰識此中陵，祖龍藏身處。", "別為一天地，下入三泉路。珠華翔青鳥，玉影耀白兔。", "山河一易姓，萬事隨人去。白晝盜開陵，玄冬火焚樹。", "哀哉送死厚，乃為棄身具。死者不復知，回看漢文墓。"]'),
('yuding-16','將歸舊山留別孟郊','鮑溶','唐','御定全唐诗','yuding','','[]','擇木無利刃，羨魚無巧綸。如何不量力，自取中路貧。',96,'御定全唐詩/json/485.json','["擇木無利刃，羨魚無巧綸。如何不量力，自取中路貧。", "前者不厭耕，一日不離親。今來千裏外，我心不在身。", "悠悠慈母心，惟願才如人。蠶桑能幾許，衣服常著新。", "一飯吐尺絲，誰見此殷勤。別君歸耕去，持火燒車輪。"]'),
('yuding-17','留辭杜員外式方','鮑溶','唐','御定全唐诗','yuding','','[]','東風吹旅懷，鄉夢無夜無。慚見君子堂，貧思上歸途。',96,'御定全唐詩/json/485.json','["東風吹旅懷，鄉夢無夜無。慚見君子堂，貧思上歸途。", "海嶽泛念深，涓塵複何須。婆娑不在本，屈曲無弦弧。", "惻惻奉離尊，承歡獨向隅。時當鳳來日，孰用雞鳴夫。", "回首九仙門，皇家在玉壺。慚非海人別，淚下不成珠。"]'),
('yuding-18','長城','鮑溶','唐','御定全唐诗','yuding','','[]','蒙公虜生人，北築秦氏冤。禍興蕭牆內，萬里防禍根。',108,'御定全唐詩/json/485.json','["蒙公虜生人，北築秦氏冤。禍興蕭牆內，萬里防禍根。", "城成六國亡，宮闕啟千門。生人半為土，何用空中原。", "奈何家天下，骨肉尚無恩。投沙擁海水，安得久不翻。", "乘高慘人魂，寒日易黃昏。枯骨貫朽鐵，砂中如有言。", "萬古驪山下，徒悲野火燔。"]'),
('yuding-19','蔡平喜遇河陽馬判官寬話別','鮑溶','唐','御定全唐诗','yuding','','[]','從事東軍正四年，相逢且喜偃兵前。看尋狡兔翻三窟，',40,'御定全唐詩/json/485.json','["從事東軍正四年，相逢且喜偃兵前。看尋狡兔翻三窟，", "秋風蕭颯醉中別，白馬嘶霜雁叫煙。"]'),
('yuding-20','寄福州從事殷堯藩','鮑溶','唐','御定全唐诗','yuding','','[]','越嶺寒輕物象殊，海城台閣似蓬壺。幾回入市鮫綃女，',40,'御定全唐詩/json/485.json','["越嶺寒輕物象殊，海城台閣似蓬壺。幾回入市鮫綃女，", "就中靜事冥宵話，何惜雙輪訪病夫。"]'),
('yuding-21','壯士行','鮑溶','唐','御定全唐诗','yuding','','[]','西方太白高，壯士羞病死。心知報恩處，對酒歌易水。',60,'御定全唐詩/json/485.json','["西方太白高，壯士羞病死。心知報恩處，對酒歌易水。", "沙鴻嗥天末，橫劍別妻子。蘇武執節歸，班超束書起。", "山河不足重，重在遇知己。"]'),
('yuding-22','章華宮行','鮑溶','唐','御定全唐诗','yuding','','[]','煙渚南鴻呼曉群，章華宮娥怨行雲。十二巫峰仰天綠，',48,'御定全唐詩/json/485.json','["煙渚南鴻呼曉群，章華宮娥怨行雲。十二巫峰仰天綠，", "豈無一人似神女，忍使黛蛾常不伸。黛蛾不伸猶自可，"]'),
('yuding-23','倚瑟行','鮑溶','唐','御定全唐诗','yuding','','[]','金輿傳驚灞滻水，龍旗參天行殿巍。左文皇帝右慎姬，',96,'御定全唐詩/json/485.json','["金輿傳驚灞滻水，龍旗參天行殿巍。左文皇帝右慎姬，", "萬世何人不此歸，一言出口堪生老。高歌倚瑟流清悲，", "明珠為日紅亭亭，水銀為河玉為星。泉宮一閉秦國喪，", "生死茫茫不可知，視不一姓君莫悲。始皇有訓二世哲，"]'),
('yuding-24','辭輦行','鮑溶','唐','御定全唐诗','yuding','','[]','漢家代久淳風薄，帝重微行極荒樂。青娥三千奉一人，',96,'御定全唐詩/json/485.json','["漢家代久淳風薄，帝重微行極荒樂。青娥三千奉一人，", "不驚六馬緩天儀，從容鳴環前致辭。君恩如海深難竭，", "週末幽王不可宗，妾聞上聖遺休風。五更三老侍白日，", "一時節義動賢君，千年名姓香氛氳，漸台水死何傷聞。"]'),
('yuding-25','巢烏行','鮑溶','唐','御定全唐诗','yuding','','[]','烏生幾子林蕭條，雄烏求食雌守巢。夜愁風雨巢傾覆，',72,'御定全唐詩/json/485.json','["烏生幾子林蕭條，雄烏求食雌守巢。夜愁風雨巢傾覆，", "野田春盡少遺穀，尋食不得饑飛來。黃雀亦引數青雀，", "將飛不飛猶未忍，古瑟寫哀哀不盡。殺生養生複養生，"]'),
('yuding-26','姑蘇宮行','鮑溶','唐','御定全唐诗','yuding','','[]','姑蘇宮，九層金台半虛空。雕楹璿題鬥皎潔，',44,'御定全唐詩/json/485.json','["姑蘇宮，九層金台半虛空。雕楹璿題鬥皎潔，", "越王采女能水戲，仙舟如龍旌曳翠。羽蓋晴翻橘柚香，"]'),
('yuding-27','悲哉行','鮑溶','唐','御定全唐诗','yuding','','[]','促促晨複昏，死生同一源。貴年不懼老，賤老傷久存。',108,'御定全唐詩/json/485.json','["促促晨複昏，死生同一源。貴年不懼老，賤老傷久存。", "朗朗哭前歌，絳旌引幽魂。來為千金子，去臥百草根。", "黃土塞生路，悲風送回轅。金鞍舊良馬，四顧不入門。", "生結千歲念，榮華及百孫。黃金買性命，白刃酬一言。", "寧知北山下，松柏侵田園。"]'),
('yuding-28','元日早朝行','鮑溶','唐','御定全唐诗','yuding','','[]','幹元發生春為宗，盛德在天鬥建東。東方歲星大明宮，',48,'御定全唐詩/json/485.json','["幹元發生春為宗，盛德在天鬥建東。東方歲星大明宮，", "文章垂彩禮樂正，太白下直旌旗紅。旌旗不斷春風前，"]'),
('yuding-29','秋懷五首','鮑溶','唐','御定全唐诗','yuding','','[]','促促生有涯，營營意無限。無限意未申，有涯生已晚。',432,'御定全唐詩/json/485.json','["促促生有涯，營營意無限。無限意未申，有涯生已晚。", "恩榮不可恃，天道歸寸管。老如影隨人，時若車下阪。", "行者歸期盡，居人心更遠。涼風日蕭條，親戚長在眼。", "多憂知無奈，聖賢莫能免。客鳥投本枝，生生複深淺。", "秋曉客迢迢，月清風楚楚。草蟲夜侵我，唧唧床下語。", "流年白日馳，微願不我與。心如繅絲綸，輾轉多頭緒。", "憑觴散煩襟，援瑟清夜拊。回感帝子心，空堂有煙雨。", "絲減悲不減，器新聲更古。一弦有餘哀，何況二十五。", "九月夜如年，幽房勞別夢。不知別日遠，夜夜猶相送。", "玉床暗蟲響，錦席寒淚凍。明鏡失舊人，空林誤歸鳳。", "新年堪愛惜，錦字亦珍重。一念皎皎時，幽襟非所用。", "金氣白日來，疏黃滿河關。平居乏愉悅，況複身險艱。", "一憶故鄉居，一望客人還。兩心四海中，誰不傷朱顏。", "雙燕不巢樹，浮萍不出山。性命君由天，安得易其間。", "休悲砌蟲苦，此日無人閑。", "龍荒變露色，燕雁南為客。遊子聲影中，涕零念離析。", "四時如車馬，轉此今與昔。往歎在空中，存事委幽跡。", "翩翩日斂照，朗朗月系夕。物生春不留，年壯老還迫。", "天機杳何為，長壽與松柏。"]'),
('yuding-30','秋夜對月懷李正封','鮑溶','唐','御定全唐诗','yuding','','[]','援琴悵獨立，高月對秋堂。美人遠于月，徒望空景光。',108,'御定全唐詩/json/485.json','["援琴悵獨立，高月對秋堂。美人遠于月，徒望空景光。", "坐憶執手時，七弦起淒涼。平生知音少，君子安可忘。", "客意如夢寐，路岐遍四方。日遠迷所之，滿天心暗傷。", "主奉二鯉魚，中含五文章。惜無千金答，愁思盈中腸。", "此夕臨風歎，零露沾衣裳。"]'),
('yuding-31','廬山石鏡','鮑溶','唐','御定全唐诗','yuding','','[]','東岩采薇人，岩際朝見月。怪墮幽蘿間，非時更澄澈。',132,'御定全唐詩/json/485.json','["東岩采薇人，岩際朝見月。怪墮幽蘿間，非時更澄澈。", "綠蘿就玉兔，再與高鳥歇。清光照掌中，始悟石上發。", "誰傳陰陽火，鑄此天地物。深影藏半山，虛輪帶凝雪。", "早回謝公賞，今遇樵夫說。白日乘彩霞，翩翩對容發。", "我圖辨鬼魅，信美留煙闕。形神乍相逢，竟夕難取別。", "如其終身照，可化黃金骨。"]'),
('yuding-32','與峨眉山道士期盡日不至','鮑溶','唐','御定全唐诗','yuding','','[]','傾景安再中，人生有何常。胡為少君別，風馭峨眉陽。',132,'御定全唐詩/json/485.json','["傾景安再中，人生有何常。胡為少君別，風馭峨眉陽。", "結我千日期，青山故人堂。期盡師不至，望雲空燒香。", "顧慚有限身，易老白日光。懷君屢驚歎，支體安能強。", "往聞清修籙，未究服食方。瑤田有靈芝，眼見不得嘗。", "玉壺貯天地，歲月亦已長。若用壺中景，東溟又堪傷。", "寄言赤玉簫，夜夜吹清商。"]'),
('yuding-33','述德上太原嚴尚書綬','鮑溶','唐','御定全唐诗','yuding','','[]','帝命河嶽神，降靈翼軒轅。天王委管鑰，開閉秦北門。',168,'御定全唐詩/json/485.json','["帝命河嶽神，降靈翼軒轅。天王委管鑰，開閉秦北門。", "頂戴日月光，口宣雨露言。甲馬不及汗，天驕自亡魂。", "清塚入內地，黃河窮本源。風雲寢氣象，鳥獸翔旗幡。", "軍人歌無胡，長劍倚昆侖。終古鞭血地，到今耕稼繁。", "樵客天一畔，何由拜旌軒。願請執禦臣，為公動朱轓。", "豈令群荒外，尚有辜帝恩。願陳田舍歌，暫息四座喧。", "條桑去附枝，薙草絕本根。可惜漢公主，哀哀嫁烏孫。"]'),
('yuding-34','山中懷劉修','鮑溶','唐','御定全唐诗','yuding','','[]','松老秋意孤，夜涼吟風水。山人在遠道，相憶中夜起。',60,'御定全唐詩/json/485.json','["松老秋意孤，夜涼吟風水。山人在遠道，相憶中夜起。", "春光如不至，幽蘭含香死。響象離鶴情，念來一相似。", "月斜掩扉臥，又在夢魂裏。"]'),
('yuding-35','塞下','鮑溶','唐','御定全唐诗','yuding','','[]','北風號薊門，殺氣日夜興。咸陽三千里，驛馬如饑鷹。',96,'御定全唐詩/json/485.json','["北風號薊門，殺氣日夜興。咸陽三千里，驛馬如饑鷹。", "行子久去鄉，逢山不敢登。寒日慘大野，虜雲若飛鵬。", "西北防秋軍，麾幢宿層層。匈奴天未喪，戰鼓長登登。", "漢卒馬上老，繁纓空絲繩。誠知天所驕，欲罷又不能。"]'),
('yuding-36','送僧南游','鮑溶','唐','御定全唐诗','yuding','','[]','且攀隋宮柳，莫憶江南春。師有懷鄉志，未為無事人。',24,'御定全唐詩/json/485.json','["且攀隋宮柳，莫憶江南春。師有懷鄉志，未為無事人。"]'),
('yuding-37','行路難','鮑溶','唐','御定全唐诗','yuding','','[]','玉堂向夕如無人，絲竹儼然宮商死。細人何言入君耳，',48,'御定全唐詩/json/485.json','["玉堂向夕如無人，絲竹儼然宮商死。細人何言入君耳，", "華燈清凝久照夜，彩僮窈窕虛垂蘿。入宮見妒君不察，"]'),
('yuding-38','子規','鮑溶','唐','御定全唐诗','yuding','','[]','中林子規啼，雲是古蜀帝。蜀帝胡為鳥，驚急如罪戾。',252,'御定全唐詩/json/485.json','["中林子規啼，雲是古蜀帝。蜀帝胡為鳥，驚急如罪戾。", "一啼豔陽節，春色亦可替。再啼孟夏林，密葉堪委翳。", "三啼涼秋曉，百卉無生意。四啼玄冥冬，雲物慘不霽。", "芸黃壯士發，沾灑妖姬袂。悲深寒烏雛，哀掩病鶴翅。", "胡為托幽命，庇質無完毳。戚戚含至冤，卑卑忌群勢。", "吾聞鳳凰長，羽族皆受制。盍分翡翠毛，使學鸚鵡慧。", "敵怨不在弦，一哀尚能繼。那令不知休，泣血經世世。", "古風失中和，衰代因鄭衛。三歎尚淫哀，向渴嘻流涕。", "如因異聲感，樂與中腸契。至教一昏蕪，生人遂危脆。", "古意歎通近，如上青天際。荼蓼久已甘，空勞堇葵惠。", "誰聞子規苦，思與正聲計。"]'),
('yuding-39','秋夜聞鄭山人彈楚妃怨','鮑溶','唐','御定全唐诗','yuding','','[]','明月搖落夜，深堂清淨弦。中間楚妃奏，十指哀嬋娟。',96,'御定全唐詩/json/485.json','["明月搖落夜，深堂清淨弦。中間楚妃奏，十指哀嬋娟。", "寥寥夜含風，蕩蕩意如泉。寂寞物無象，依稀語空煙。", "旅人多西望，客雁難南前。由來感神事，豈為無情傳。", "容華能幾時，不再來者年。此夕河漢上，雙星含淒然。"]'),
('yuding-40','憶舊游','鮑溶','唐','御定全唐诗','yuding','','[]','憶求無何鄉，了在赤穀村。仙人居其中，將往問所存。',192,'御定全唐詩/json/485.json','["憶求無何鄉，了在赤穀村。仙人居其中，將往問所存。", "日入蒙汜宿，石煙抱山門。明月久不下，半峰照啼猿。", "堂上白鶴翁，神清心無煩。齋心侍席前，跪請長生恩。", "雲昔崆峒老，何詞受軒轅。從星使變化，任日張乾坤。", "若到舊鄉里，宛如曾討論。風移岩花氣，珠貫金經言。", "涼夜惜易盡，青煙謝晨喧。自唯腥膻體，難久留其藩。", "幾世身在夢，百年雲無根。悠悠竟何事，愚智相憂冤。", "歎息幾晚寤，蒙師招其魂。至今瑤華心，每想清水源。"]'),
('yuding-41','白露','鮑溶','唐','御定全唐诗','yuding','','[]','清蟬暫休響，豐露還移色。金飆爽晨華，玉壺增夜刻。',84,'御定全唐詩/json/485.json','["清蟬暫休響，豐露還移色。金飆爽晨華，玉壺增夜刻。", "已低疏螢焰，稍減哀蟬力。迎社促燕心，助風勞雁翼。", "一悲紈扇情，再想清淺憶。高高拜月歸，軋軋挑燈織。", "盈盈玉盤淚，何處無消息。"]'),
('yuding-42','經隱叟','鮑溶','唐','御定全唐诗','yuding','','[]','行蹋門外泉，坐披床上雲。誰將許由事，萬古留與君。',72,'御定全唐詩/json/485.json','["行蹋門外泉，坐披床上雲。誰將許由事，萬古留與君。", "虛洞閉金鎖，蠹簡藏鳥文。蘿景深的的，蕙風閑熏熏。", "餘有世上心，此來未及群。殷勤諱名姓，莫遣樵客聞。"]'),
('yuding-43','秋暮山中懷李端公益','鮑溶','唐','御定全唐诗','yuding','','[]','舊事與日遠，秋花仍舊香。前年繡衣客，此節過此堂。',144,'御定全唐詩/json/485.json','["舊事與日遠，秋花仍舊香。前年繡衣客，此節過此堂。", "侍臣不自高，笑脫繡衣裳。眠雲有餘態，入鳥不亂行。", "我恐雲嵐色，損君鞍馬光。君言此何言，且共覆前觴。", "古人重一笑，買日輕金裝。日盡秉燭遊，千年不能忘。", "君言此何言，明日皆異鄉。明日非今日，山下道路長。", "一從山下來，天地再炎涼。此中會難得，夢君馬玄黃。"]'),
('yuding-44','苦哉遠征人','鮑溶','唐','御定全唐诗','yuding','','[]','征人歌古曲，攜手上河梁。李陵死別處，窅杳玄冥鄉。',144,'御定全唐詩/json/485.json','["征人歌古曲，攜手上河梁。李陵死別處，窅杳玄冥鄉。", "憶昔從此路，連年征鬼方。久行迷漢曆，三死氈衣裳。", "百戰身且在，微功信難忘。遠承雲台議，非勢孰敢當。", "落日吊李廣，白首過河陽。閑弓失月影，勞劍無龍光。", "去日始束發，今來發成霜。虛名乃閒事，生見父母鄉。", "掩抑大風歌，裴回少年場。誠哉古人言，鳥盡良弓藏。"]'),
('yuding-45','悼豆盧策先輩','鮑溶','唐','御定全唐诗','yuding','','[]','喪車出東門，生時馬無力。何處入黃泉，嵩高山西北。',144,'御定全唐詩/json/485.json','["喪車出東門，生時馬無力。何處入黃泉，嵩高山西北。", "室人萬里外，久望君官職。今與牽衣兒，翻號死消息。", "平生江海上，我不空相識。遠客迷畏途，孤鴻傷一翼。", "行將雞黍祭，已是烏鳶食。勸酒執禦郎，行人有哀色。", "先悲三尺土，經歲哭不得。眼前雙雙流，故袂安可拭。", "一拜隔千里，生人意何極。唯有陽春曲，永播清玉德。"]'),
('yuding-46','首夏','鮑溶','唐','御定全唐诗','yuding','','[]','昨日青春去，晚峰尚含妍。雖留有餘態，脈脈防憂煎。',36,'御定全唐詩/json/485.json','["昨日青春去，晚峰尚含妍。雖留有餘態，脈脈防憂煎。", "幽人惜時節，對此感流年。"]'),
('yuding-47','寄天臺准公','鮑溶','唐','御定全唐诗','yuding','','[]','赤城橋東見月夜，佛壟寺邊行月僧。',32,'御定全唐詩/json/485.json','["赤城橋東見月夜，佛壟寺邊行月僧。", "閑蹋莓苔繞琪樹，海光清淨對心燈。"]'),
('yuding-48','送僧東游','鮑溶','唐','御定全唐诗','yuding','','[]','風流東晉後，外學入僧家。獨唱郢中雪，還遊天際霞。',48,'御定全唐詩/json/485.json','["風流東晉後，外學入僧家。獨唱郢中雪，還遊天際霞。", "雲村共香飯，水月喻秋花。景物添新致，前程詎可涯。"]'),
('yuding-49','送僧之宣城','鮑溶','唐','御定全唐诗','yuding','','[]','昔從謝太守，賓客宛陵城。有日持齋戒，高僧識姓名。',36,'御定全唐詩/json/485.json','["昔從謝太守，賓客宛陵城。有日持齋戒，高僧識姓名。", "秋風送客去，安得盡忘情。"]'),
('yuding-50','宣城北樓，昔從順陽公會于此','鮑溶','唐','御定全唐诗','yuding','','[]','詩樓郡城北，窗牖敬亭山。幾步塵埃隔，終朝世界閑。',36,'御定全唐詩/json/485.json','["詩樓郡城北，窗牖敬亭山。幾步塵埃隔，終朝世界閑。", "憑師看粉壁，名姓在其間。"]'),
('yuding-51','東高峰','鮑溶','唐','御定全唐诗','yuding','','[]','東亭最高峙，春樹繞山腰。畫裏青鸞客，雲中碧玉簫。',36,'御定全唐詩/json/485.json','["東亭最高峙，春樹繞山腰。畫裏青鸞客，雲中碧玉簫。", "秋風若西望，為我一長謠。"]'),
('yuding-52','禪定寺經院','鮑溶','唐','御定全唐诗','yuding','','[]','蓮華不朽寺，雕刻滿山根。石汗知天雨，金泥落聖言。',36,'御定全唐詩/json/485.json','["蓮華不朽寺，雕刻滿山根。石汗知天雨，金泥落聖言。", "思量施金客，千古獨消魂。"]'),
('yuding-53','範真傳侍禦累有寄，因奉酬十首','鮑溶','唐','御定全唐诗','yuding','','[]','昨日新花紅滿眼，今朝美酒綠留人。',256,'御定全唐詩/json/485.json','["昨日新花紅滿眼，今朝美酒綠留人。", "更宜明月含芳露，憑杖蕭郎夜賞春。", "白雪翦花朱蠟蒂，折花傳笑惜春人。", "請君白日留明日，一醉春光莫厭頻。", "雲髻鳳文細，對君歌少年。萬金酬一顧，可惜十千錢。", "玉管傾杯樂，春園鬥草情。野花無限意，處處逐人行。", "聞道中山酒，一杯千日醒。黃鶯似傳語，勸酒太叮嚀。", "紅袂歌聲起，因君始得聞。黃昏小垂手，與我駐浮雲。", "相勸醉年華，莫醒春日斜。春風宛陵道，萬里晉陽花。", "碧綠草縈堤，紅藍花滿溪。願君常踐蹋，莫使暗萋萋。", "萋萋巫峽雲，楚客莫留恩。歲久晉陽道，誰能向太原。", "歲酒勸屠蘇，楚聲山鷓鴣。春風入君意，千日不須臾。"]'),
('yuding-0','越女詞','鮑溶','唐','御定全唐诗','yuding','','[]','越女芙蓉妝，浣紗清淺水。忽驚春心曉，不敢思君子。',36,'御定全唐詩/json/486.json','["越女芙蓉妝，浣紗清淺水。忽驚春心曉，不敢思君子。", "君子縱我思，寧來浣溪裏。"]'),
('yuding-1','弄玉詞二首','鮑溶','唐','御定全唐诗','yuding','','[]','素女結念飛天行，白玉參差鳳凰聲，天仙借女雙翅猛。',58,'御定全唐詩/json/486.json','["素女結念飛天行，白玉參差鳳凰聲，天仙借女雙翅猛。", "五燈繞身生，入煙去無影。", "三清弄玉秦公女，嫁得天上人。瓊簫碧月喚朱雀，"]'),
('yuding-2','山行經樵翁','鮑溶','唐','御定全唐诗','yuding','','[]','我心勞我身，遠道誰與論。心如木中火，憂至常自燔。',168,'御定全唐詩/json/486.json','["我心勞我身，遠道誰與論。心如木中火，憂至常自燔。", "披訪結恩地，世人輕報恩。女無良媒識，知入何人門。", "寒日行深山，路由穀中村。田翁樵采熟，男女謳吟喧。", "借問身命謀，上言愧乾坤。時清公賦薄，力勤地利繁。", "下念草木年，坐家見重孫。舉案饋賓客，糟漿盈陶尊。", "醉閑鹿裘暖，白髮舞軒軒。仰羨太古人，餘將破行轅。", "遑遑問身事，師友難為言。離歌又行去，落日低寒泉。"]'),
('yuding-3','途中旅思二首','鮑溶','唐','御定全唐诗','yuding','','[]','喔喔雞鳴曉，蕭蕭馬辭櫪。草草名利區，居人少於客。',216,'御定全唐詩/json/486.json','["喔喔雞鳴曉，蕭蕭馬辭櫪。草草名利區，居人少於客。", "生期三萬日，童耄半虛擲。修短命半中，憂歡複相敵。", "朝提黃金爵，暮造青松宅。來往日相悲，北邙田土窄。", "峨峨西天嶽，錦繡明翠壁。中有不死鄉，千年無人跡。", "心期周太子，下馬拜虛碧。鶴駕如可從，他年執煙策。", "星出方問宿，睡眼始朦朧。天光見地色，上路車幢幢。", "時物既老大，眾山何枯空。青冥見古柏，寥朗聞疏鴻。", "獨步天地間，無因為君忠。白毛尋人憂，生此頭髮中。", "躍馬非壯歲，報恩無高功。斯言化為火，日夜焚深衷。"]'),
('yuding-4','舊鏡','鮑溶','唐','御定全唐诗','yuding','','[]','嬋娟本家鏡，與妾歸君子。每憶並照時，相逢明月裏。',108,'御定全唐詩/json/486.json','["嬋娟本家鏡，與妾歸君子。每憶並照時，相逢明月裏。", "春風忽分影，白日難依倚。珠粉不結花，玉璫寧輝耳。", "心期不可見，不保長如此。華髮一欺人，青銅化為鬼。", "良人有歸日，肯學妖桃李。瑤匣若浮雲，冥冥藏玉水。", "侍兒不遣照，恐學孤鸞死。"]'),
('yuding-5','宿悟空寺贈僧','鮑溶','唐','御定全唐诗','yuding','','[]','勞者謠燭蛾，致身何營營。雪山本師在，心地如鏡清。',84,'御定全唐詩/json/486.json','["勞者謠燭蛾，致身何營營。雪山本師在，心地如鏡清。", "往與本師別，人間買浮名。朝光畏不久，內火燒人情。", "迷路喜未遠，宿留化人城。前心宛如此，了了隨靜生。", "維持薝蔔花，卻與前心行。"]'),
('yuding-6','感興','鮑溶','唐','御定全唐诗','yuding','','[]','幽人無近跡，別易會則稀。黃鶴亦姓丁，寥寥何處飛。',108,'御定全唐詩/json/486.json','["幽人無近跡，別易會則稀。黃鶴亦姓丁，寥寥何處飛。", "時見海上山，繞雲心依依。諒無馭風術，中路愁虛歸。", "童發慕道心，壯年墮塵機。白日不饒我，如今事皆非。", "群羊化石盡，雙鳧與我違。□岳黃金富，軒轅曉霞衣。", "誰令日在眼，容色煙雲微。"]'),
('yuding-7','秋思','鮑溶','唐','御定全唐诗','yuding','','[]','楚客秋更悲，皇皇無聲地。時無無事人，我命與身異。',108,'御定全唐詩/json/486.json','["楚客秋更悲，皇皇無聲地。時無無事人，我命與身異。", "良時如飛鳥，回掌成故事。蹉跎秋定還，凝冽堅冰至。", "人生不期老，華髮誰能避。感此惜壯年，壯年少為貴。", "我生雖努力，榮途難自致。徒為擊角歌，且慚雕劍字。", "吾師罕言命，感激潛傷思。"]'),
('yuding-8','客途逢鄉人旋別','鮑溶','唐','御定全唐诗','yuding','','[]','驚鴻一斷行，天遠會無因。無因忽相會，感歎若有神。',108,'御定全唐詩/json/486.json','["驚鴻一斷行，天遠會無因。無因忽相會，感歎若有神。", "我鄉路三千，百里一主人。一宿獨何戀，何況舊鄉鄰。", "牢落歲華晏，相憐客中貧。迎霜君衣暖，與我同一身。", "誰在天日下，此生能不勤。青萍寄流水，安得長相親。", "明發更遠道，山河重苦辛。"]'),
('yuding-9','隋帝陵下','鮑溶','唐','御定全唐诗','yuding','','[]','白露沾衣隋主宮，雲亭月館楚淮東。盤龍樓艦浮冤水，',40,'御定全唐詩/json/486.json','["白露沾衣隋主宮，雲亭月館楚淮東。盤龍樓艦浮冤水，", "傷心近似驪山路，陵樹無根秋草中。"]'),
('yuding-10','洛陽春望','鮑溶','唐','御定全唐诗','yuding','','[]','五鳳樓南望洛陽，龍門回合抱蒼蒼。受朝前殿雲霞暖，',40,'御定全唐詩/json/486.json','["五鳳樓南望洛陽，龍門回合抱蒼蒼。受朝前殿雲霞暖，", "東人猶憶時巡禮，願覲元和日月光。"]'),
('yuding-11','始見二毛','鮑溶','唐','御定全唐诗','yuding','','[]','玄發迎憂光色闌，衰華因鏡強相看。百川赴海返潮易，',40,'御定全唐詩/json/486.json','["玄發迎憂光色闌，衰華因鏡強相看。百川赴海返潮易，", "顏生豈是光陰晚，余亦何人不自寬。"]'),
('yuding-12','巫山懷古','鮑溶','唐','御定全唐诗','yuding','','[]','十二峰巒鬥翠微，石煙花霧犯容輝。青春楚女妒雲老，',40,'御定全唐詩/json/486.json','["十二峰巒鬥翠微，石煙花霧犯容輝。青春楚女妒雲老，", "誰傷宋玉千年後，留得青山辨是非。"]'),
('yuding-13','郊天回','鮑溶','唐','御定全唐诗','yuding','','[]','日動蕭煙上泰壇，帝從黃道整和鑾。風前貔武回雕仗，',40,'御定全唐詩/json/486.json','["日動蕭煙上泰壇，帝從黃道整和鑾。風前貔武回雕仗，", "始知報本終朝禮，舊典時巡只自難。"]'),
('yuding-14','溫泉宮','鮑溶','唐','御定全唐诗','yuding','','[]','憶昔開元天地平，武皇十月幸華清。山蒸陰火雲三素，',40,'御定全唐詩/json/486.json','["憶昔開元天地平，武皇十月幸華清。山蒸陰火雲三素，", "仍聞老叟垂黃發，猶說龍髯縹緲情。"]'),
('yuding-15','寄歸','鮑溶','唐','御定全唐诗','yuding','','[]','塞草黃來見雁稀，隴雲白後少人歸。新絲強入未衰鬢，',40,'御定全唐詩/json/486.json','["塞草黃來見雁稀，隴雲白後少人歸。新絲強入未衰鬢，", "更看出獵相思苦，不射秋田朝雉飛。"]'),
('yuding-16','贈遠','鮑溶','唐','御定全唐诗','yuding','','[]','辛苦關西車騎官，幾年旌節客河蘭。金泥舞虎精神暗，',40,'御定全唐詩/json/486.json','["辛苦關西車騎官，幾年旌節客河蘭。金泥舞虎精神暗，", "莫勞雁足傳書信，願向淩煙閣上看。"]'),
('yuding-17','九日與友人登高','鮑溶','唐','御定全唐诗','yuding','','[]','雲木疏黃秋滿川，茱萸風裏一尊前。幾回為客逢佳節，',40,'御定全唐詩/json/486.json','["雲木疏黃秋滿川，茱萸風裏一尊前。幾回為客逢佳節，", "古來醉樂皆難得，留取窮通付上天。"]'),
('yuding-18','贈楊煉師','鮑溶','唐','御定全唐诗','yuding','','[]','柴煙衣上繡春雲，清隱山書小篆文。',32,'御定全唐詩/json/486.json','["柴煙衣上繡春雲，清隱山書小篆文。", "明月在天將鳳管，夜深吹向玉晨君。"]'),
('yuding-19','玉清壇','鮑溶','唐','御定全唐诗','yuding','','[]','上陽宮裏女，玉色楚人多。西信無因得，東游奈樂何。',24,'御定全唐詩/json/486.json','["上陽宮裏女，玉色楚人多。西信無因得，東游奈樂何。"]'),
('yuding-20','答客','鮑溶','唐','御定全唐诗','yuding','','[]','竹間深路馬驚嘶，獨入蓬門半似迷。',32,'御定全唐詩/json/486.json','["竹間深路馬驚嘶，獨入蓬門半似迷。", "勞問圃人終歲事，桔槔聲裏雨春畦。"]'),
('yuding-21','隋宮','鮑溶','唐','御定全唐诗','yuding','','[]','柳塘煙起日西斜，竹浦風回雁弄沙。',32,'御定全唐詩/json/486.json','["柳塘煙起日西斜，竹浦風回雁弄沙。", "煬帝春遊古城在，壞宮芳草滿人家。"]'),
('yuding-22','送僧文江','鮑溶','唐','御定全唐诗','yuding','','[]','吳王劍池上，禪子石房深。久慕白雲性，忽勞青玉音。',48,'御定全唐詩/json/486.json','["吳王劍池上，禪子石房深。久慕白雲性，忽勞青玉音。", "孤高知勝鶴，清雅似聞琴。此韻書珍重，煩師出定吟。"]'),
('yuding-23','古意','鮑溶','唐','御定全唐诗','yuding','','[]','重錦化為泥，翦刀誤人事。夜裁遠道書，翦破相思字。',72,'御定全唐詩/json/486.json','["重錦化為泥，翦刀誤人事。夜裁遠道書，翦破相思字。", "妾心不自信，遠道終難寄。客心固多疑，肯信非人意。", "萬里不言遠，歸書長相次。可即由此書，空房□忌諱。"]'),
('yuding-24','山中冬思二首','鮑溶','唐','御定全唐诗','yuding','','[]','山深先冬寒，敗葉與林齊。門巷非世路，何人念窮棲。',168,'御定全唐詩/json/486.json','["山深先冬寒，敗葉與林齊。門巷非世路，何人念窮棲。", "哀風破山起，夕雪誤鳴雞。巢鳥侵旦出，饑猿無聲啼。", "晨興動煙火，開雲伐冰溪。老木寒更瘦，陰雲晴亦低。", "我貧自求力，顏色常低迷。時思靈台下，遊子正淒淒。", "雪壯冰亦堅，凍澗如平地。幽人毛褐暖，笑就糟床醉。", "喚人空谷應，開火寒猿至。拾薪煮秋栗，看鼎書古字。", "忽憶南澗遊，衣巾多雲氣。露腳尋逸僧，諮量意中事。"]'),
('yuding-25','讀史','鮑溶','唐','御定全唐诗','yuding','','[]','鬼書報秦亡，天地亦雲閉。赤龍吟大野，老母哭白帝。',108,'御定全唐詩/json/486.json','["鬼書報秦亡，天地亦雲閉。赤龍吟大野，老母哭白帝。", "蒼蒼無白日，項氏徒先濟。六合已姓劉，鴻門事難制。", "坑降嬴政在，衣錦人望替。宿昔見漢兵，龍蛇滿旌棨。", "始矜山可拔，終歎騅不逝。區區亞父心，未究天人際。", "蕭張馬無汗，盛業垂千世。"]'),
('yuding-26','冬夜答客','鮑溶','唐','御定全唐诗','yuding','','[]','冬日誠可愛，不如夜漏多。幸君霜露裏，車馬犯寒過。',96,'御定全唐詩/json/486.json','["冬日誠可愛，不如夜漏多。幸君霜露裏，車馬犯寒過。", "學耕不逢年，稂莠敗黍禾。豈唯親賓散，鳥鼠移巢窠。", "獨見青松心，淩霜庇柔蘿。壯日賤若此，留恩意如何。", "因憶古丈夫，一言重山河。臨風彈楚劍，為子奏燕歌。"]'),
('yuding-27','宿吳興道中苕村','鮑溶','唐','御定全唐诗','yuding','','[]','浮客倦長道，秋深夜如年。久行惜日月，常起雞鳴前。',120,'御定全唐詩/json/486.json','["浮客倦長道，秋深夜如年。久行惜日月，常起雞鳴前。", "夕計今日程，息車在苕川。霜中水南寺，金磬泠泠然。", "疇昔此林下，歸心巢頂禪。身依寤昏寐，智月生虛圓。", "羈旅違我程，去留難雙全。觀身話往事，如夢游青天。", "明發止賓從，寄聲琴上弦。聊書越人意，此曲名思仙。"]'),
('yuding-28','代楚老酬主人','鮑溶','唐','御定全唐诗','yuding','','[]','流水為我鄉，扁舟為我宅。二毛去天遠，幾日人間客。',96,'御定全唐詩/json/486.json','["流水為我鄉，扁舟為我宅。二毛去天遠，幾日人間客。", "曈曈銜山景，渺渺翔雲跡。從時無定心，病處不暖席。", "煩君問岐路，為我生淒戚。百年衣食身，未死皆有役。", "曾傷無遺嗣，縱有複何益。終古北邙山，樵人賣松柏。"]'),
('yuding-29','沛中懷古','鮑溶','唐','御定全唐诗','yuding','','[]','煙蕪歌風台，此是赤帝鄉。赤帝今已矣，大風邈淒涼。',96,'御定全唐詩/json/486.json','["煙蕪歌風台，此是赤帝鄉。赤帝今已矣，大風邈淒涼。", "惟昔仗孤劍，十年朝八荒。人言生處樂，萬乘巡東方。", "高臺何巍巍，行殿起中央。興言萬代事，四坐沾衣裳。", "我為異代臣，酌水祀先王。撫事複懷昔，臨風獨彷徨。"]'),
('yuding-30','夏日華山別韓博士愈','鮑溶','唐','御定全唐诗','yuding','','[]','別地泰華陰，孤亭潼關口。夏日可畏時，望山易遲久。',192,'御定全唐詩/json/486.json','["別地泰華陰，孤亭潼關口。夏日可畏時，望山易遲久。", "暫因車馬倦，一逐雲先後。碧霞氣爭寒，黃鳥語相誘。", "三峰多異態，迥舉仙人手。天晴捧日輪，月夕弄星斗。", "幽疑白帝近，明見黃河走。遠心不期來，真境非吾有。", "鳥鳴草木下，日息天地右。躑躅因風松，青冥謝仙叟。", "不知無聲淚，中感一顏厚。青霄上何階，別劍空朗扣。", "故鄉此關外，身與名相守。跡比斷根蓬，憂如長飲酒。", "生離抱多恨，方寸安可受。咫尺岐路分，蒼煙蔽回首。"]'),
('yuding-31','春日言懷','鮑溶','唐','御定全唐诗','yuding','','[]','湛湛琴前酒，期自賞青春。胡為緘笑語，深念不思身。',84,'御定全唐詩/json/486.json','["湛湛琴前酒，期自賞青春。胡為緘笑語，深念不思身。", "寂寂花舞多，嚶嚶鳥言頻。心悲兄弟遠，願見相似人。", "江界田土卑，競來東作勤。歲寒虛盡力，家外無強親。", "杳窅青雲望，無途同苦辛。"]'),
('yuding-32','題吳征君岩居','鮑溶','唐','御定全唐诗','yuding','','[]','堯澤潤天下，許由心不知。真風存綿綿，常與達者期。',84,'御定全唐詩/json/486.json','["堯澤潤天下，許由心不知。真風存綿綿，常與達者期。", "有道吾不仕，有生吾不欺。澹然靈府中，獨見太古時。", "地脈發醴泉，岩根生靈芝。天文若通會，星影應離離。", "亭亭傅氏岩，何獨萬古思。"]'),
('yuding-33','雲溪竹園翁','鮑溶','唐','御定全唐诗','yuding','','[]','硠硠雲溪裏，翠竹和雲生。古泉積澗深，竦竦如刻成。',120,'御定全唐詩/json/486.json','["硠硠雲溪裏，翠竹和雲生。古泉積澗深，竦竦如刻成。", "楚客臥雲老，世間無姓名。因茲千畝業，以代雙牛耕。", "亂林不可留，寸莖不可輕。風暖鬥出地，仰齊故年莖。", "幽室結白茅，密葉羅眾清。照水寒澹蕩，對山綠崢嶸。", "蒼松含古貌，秋桂儼白英。相看受天風，深夜戛擊聲。"]'),
('yuding-34','竊覽都官李郎中和李舍人益酬張舍人弘靜夏夜寓直思聞雅琴見寄','鮑溶','唐','御定全唐诗','yuding','','[]','朝草天子奏，夜語思憂琴。因聲含香氣，其韻流水音。',72,'御定全唐詩/json/486.json','["朝草天子奏，夜語思憂琴。因聲含香氣，其韻流水音。", "仙樂朱鳳意，靈芝紫鸞心。翻然遠求友，豈獨雙歸林。", "松吹暑中冷，星花池上深。倘俾有聲樂，請以絲和金。"]'),
('yuding-35','長安言懷','鮑溶','唐','御定全唐诗','yuding','','[]','殷殷生念厚，戚戚勞者多。二時晝夜等，百歲詎幾何。',120,'御定全唐詩/json/486.json','["殷殷生念厚，戚戚勞者多。二時晝夜等，百歲詎幾何。", "日下文翰苑，側身識經過。千慮恐一失，翔陽已蹉跎。", "臨觴翦眾憂，靜寄絲桐歌。思歸繞十指，五聲不相和。", "暮天還巢翼，明日隕葉柯。高謝岩谷人，鹿衣帶女蘿。", "生不去親愛，浮名若風波。誰令不及此，親愛隔山河。"]'),
('yuding-36','秋思三首','鮑溶','唐','御定全唐诗','yuding','','[]','胡風吹雁翼，遠別無人鄉。君近雁來處，幾回斷君腸。',252,'御定全唐詩/json/486.json','["胡風吹雁翼，遠別無人鄉。君近雁來處，幾回斷君腸。", "昔奉千日書，撫心怨星霜。無書又千日，世路重茫茫。", "燕國有佳麗，蛾眉富春光。自然君歸晚，花落君空堂。", "君其若不然，歲晚雙鴛鴦。", "顧兔蝕殘月，幽光不如星。女兒晚事夫，顏色同秋螢。", "秋日邊馬思，武夫不遑甯。燕歌易水怨，劍舞蛟龍腥。", "風折連枝樹，水翻無蒂萍。立身多門戶，何必燕山銘。", "生世不如鳥，雙雙比翼翎。", "季秋天地閑，萬物生意足。我憂長於生，安得及草木。", "試從古人願，致酒歌秉燭。燕趙皆世人，詎能長似玉。", "俯憐老期近，仰視日車速。蕭颯禦風君，魂夢願相逐。", "百年夜銷半，端為重纓束。"]'),
('yuding-37','歸雁','鮑溶','唐','御定全唐诗','yuding','','[]','南國春早暖，渚蒲正月生。東風吹雁心，上下和樂聲。',133,'御定全唐詩/json/486.json','["南國春早暖，渚蒲正月生。東風吹雁心，上下和樂聲。", "繞水半空去，拂雲偕相迎。如防失群怨，預有侵夜驚。", "渺邈天外影，支離塞中鶯。自顧摧頹羽，偏感南北情。", "乍甘煙霧勞，不顧龍沙榮。雖樂未歸意，終不能自鳴。", "喜去春月滿，歸來秋風清。啼餘碧窗夢，望斷陰山行。", "不及瑤wG燕，寄身金宮楹。"]'),
('yuding-38','悲湘靈','鮑溶','唐','御定全唐诗','yuding','','[]','山上涼雲收，日斜川風止。娥皇五十弦，秋深漢江水。',132,'御定全唐詩/json/486.json','["山上涼雲收，日斜川風止。娥皇五十弦，秋深漢江水。", "初因無象外，牽感百憂裏。霜露結瑤華，煙波勞玉指。", "將隨落葉去，又繞疏蘋起。哀響雲合來，清餘桐半死。", "女顏萬歲後，豈複嬋娟子。不道神無悲，那能久如此。", "魂魄無不之，九山徒相似。沒沒竟不從，唯傷遠人耳。", "斑斑淚篁下，恐有學瑟鬼。"]'),
('yuding-39','聞蟬','鮑溶','唐','御定全唐诗','yuding','','[]','高蟬旦夕唳，景物浮涼氣。木葉漸驚年，錦字因絡緯。',84,'御定全唐詩/json/486.json','["高蟬旦夕唳，景物浮涼氣。木葉漸驚年，錦字因絡緯。", "稍斷當窗夢，更淒臨水意。清香筍蒂風，曉露蓮花淚。", "餘引未全歇，凝悲尋迥至。星井欲望河，月扇看藏笥。", "誰念因聲感，放歌寫人事。"]'),
('yuding-40','懷幽期','鮑溶','唐','御定全唐诗','yuding','','[]','清砧擊霜天外發，楚僧期到石上月。寒峰深虛獨繞盡，',48,'御定全唐詩/json/486.json','["清砧擊霜天外發，楚僧期到石上月。寒峰深虛獨繞盡，", "眼界行處不著我，天花下來惟有香，我今胡為寄他鄉。"]'),
('yuding-41','思琴高','鮑溶','唐','御定全唐诗','yuding','','[]','琴仙人，得仙去。萬古釣龍空有處，我持曲鉤思白魚。',48,'御定全唐詩/json/486.json','["琴仙人，得仙去。萬古釣龍空有處，我持曲鉤思白魚。", "仙溪綠盡含空虛，天鈞蹤跡無遺餘。燒香寄影在岩樹，"]'),
('yuding-42','得儲道士書','鮑溶','唐','御定全唐诗','yuding','','[]','嬋娟春盡暮心秋，鄰里同年半白頭。',32,'御定全唐詩/json/486.json','["嬋娟春盡暮心秋，鄰里同年半白頭。", "為問蓬萊近消息，海波平靜好東遊。"]'),
('yuding-43','寒夜吟','鮑溶','唐','御定全唐诗','yuding','','[]','九衢金吾夜行行，上宮玉漏遙分明。霜飆乘陰掃地起，',48,'御定全唐詩/json/486.json','["九衢金吾夜行行，上宮玉漏遙分明。霜飆乘陰掃地起，", "羅幕畫堂深皎潔，蘭煙對酒客幾人。獸火揚光二三月，"]'),
('yuding-44','採蓮曲二首','鮑溶','唐','御定全唐诗','yuding','','[]','弄舟朅來南塘水，荷葉映身摘蓮子。暑衣清淨鴛鴦喜，',48,'御定全唐詩/json/486.json','["弄舟朅來南塘水，荷葉映身摘蓮子。暑衣清淨鴛鴦喜，", "採蓮朅來水無風，蓮潭如鑒松如龍。夏衫短袖交斜紅，"]'),
('yuding-45','玉山謠奉送王隱者','鮑溶','唐','御定全唐诗','yuding','','[]','鳳凰城南玉山高，石腳聳立爭雄豪。攢峰胎玉氣色潤，',72,'御定全唐詩/json/486.json','["鳳凰城南玉山高，石腳聳立爭雄豪。攢峰胎玉氣色潤，", "有客師事金身仙，用金買得山中田。閑開玉水灌芝草，", "水玉丁東不可聞，冰華皎潔應如待。秋風引吾歌去來，"]'),
('yuding-46','岐路','鮑溶','唐','御定全唐诗','yuding','','[]','北風送微寒，徒侶勤遠征。憂人席不暖，殘月馬上明。',120,'御定全唐詩/json/486.json','["北風送微寒，徒侶勤遠征。憂人席不暖，殘月馬上明。", "飄飄岐路間，長見日初生。重嶂曉色淺，疏猿寒啼清。", "人間多岐路，常恐終身行。回見四方人，車輪無留聲。", "空穀亦堪隱，下田非懶耕。古人有遺訓，飽食非親榮。", "我生禮義鄉，少小見太平。聖賢猶羈旅，況複非其名。"]'),
('yuding-47','隴頭水','鮑溶','唐','御定全唐诗','yuding','','[]','隴頭水，千古不堪聞。生歸蘇屬國，死別李將軍。',34,'御定全唐詩/json/486.json','["隴頭水，千古不堪聞。生歸蘇屬國，死別李將軍。", "細響風凋草，清哀雁落雲。"]'),
('yuding-48','沙上月','鮑溶','唐','御定全唐诗','yuding','','[]','黃昏潮落南沙明，月光涵沙秋雪清。',32,'御定全唐詩/json/486.json','["黃昏潮落南沙明，月光涵沙秋雪清。", "水文不上煙不蕩，平平玉田冷空曠。"]'),
('yuding-49','贈李黯將軍','鮑溶','唐','御定全唐诗','yuding','','[]','細柳連營石塹牢，平安狼火赤星高。岩雲入角雕龍爽，',40,'御定全唐詩/json/486.json','["細柳連營石塹牢，平安狼火赤星高。岩雲入角雕龍爽，", "聖人唯有河湟恨，寰海無虞在一勞。"]'),
('yuding-50','人日陪宣州範中丞傳正與範侍禦宴','鮑溶','唐','御定全唐诗','yuding','','[]','人日春風綻早梅，謝家兄弟看花來。吳姬對客歌千曲，',40,'御定全唐詩/json/486.json','["人日春風綻早梅，謝家兄弟看花來。吳姬對客歌千曲，", "流光易去歡難得，莫厭頻頻上此台。"]'),
('yuding-51','古鑒','鮑溶','唐','御定全唐诗','yuding','','[]','古鑒含靈氣象和，蛟龍盤鼻護金波。隱山道士未曾識，',40,'御定全唐詩/json/486.json','["古鑒含靈氣象和，蛟龍盤鼻護金波。隱山道士未曾識，", "世間縱有應難比，十斛明珠酬未多。"]'),
('yuding-52','送王煉師','鮑溶','唐','御定全唐诗','yuding','','[]','聖母祠堂藥樹香，邑君承命薦椒漿。風雲大感精神地，',40,'御定全唐詩/json/486.json','["聖母祠堂藥樹香，邑君承命薦椒漿。風雲大感精神地，", "野人久會神仙事，敢奏歌鐘慶萬箱。"]'),
('yuding-53','寄張十七校書李仁行秀才','鮑溶','唐','御定全唐诗','yuding','','[]','去年八月此佳辰，池上閑閑四五人。久行月影愁迷夢，',40,'御定全唐詩/json/486.json','["去年八月此佳辰，池上閑閑四五人。久行月影愁迷夢，", "今年此日何由見，蓬戶蕭條對病身。"]'),
('yuding-54','送王損之秀才赴舉','鮑溶','唐','御定全唐诗','yuding','','[]','青門佩蘭客，淮水誓風流。名在鄉書貢，心期月殿遊。',48,'御定全唐詩/json/486.json','["青門佩蘭客，淮水誓風流。名在鄉書貢，心期月殿遊。", "平沙大河急，細雨二陵秋。感此添離恨，年光不少留。"]'),
('yuding-55','舊鏡','鮑溶','唐','御定全唐诗','yuding','','[]','團團銅鏡似潭水，心愛玉顏私自親。',32,'御定全唐詩/json/486.json','["團團銅鏡似潭水，心愛玉顏私自親。", "一經離別少年改，難與清光相見新。"]'),
('yuding-56','憶郊天','鮑溶','唐','御定全唐诗','yuding','','[]','憶向郊壇望武皇，九軍旗帳下南方。六龍日馭天行健，',40,'御定全唐詩/json/486.json','["憶向郊壇望武皇，九軍旗帳下南方。六龍日馭天行健，", "至今滿耳簫韶曲，徒羨瑤池舞鳳凰。"]'),
('yuding-57','期盡','鮑溶','唐','御定全唐诗','yuding','','[]','魚鎖生衣門不開，玉筐金月共塵埃。',32,'御定全唐詩/json/486.json','["魚鎖生衣門不開，玉筐金月共塵埃。", "青山石婦千年望，雷雨曾知來不來。"]'),
('yuding-58','晚山蟬','鮑溶','唐','御定全唐诗','yuding','','[]','山蟬秋晚妨人語，客子驚心馬亦嘶。能閱幾時新碧樹，',24,'御定全唐詩/json/486.json','["山蟬秋晚妨人語，客子驚心馬亦嘶。能閱幾時新碧樹，"]'),
('yuding-59','秋暮送裴垍員外刺婺州','鮑溶','唐','御定全唐诗','yuding','','[]','婺女星邊氣不秋，金華山水似瀛州。',32,'御定全唐詩/json/486.json','["婺女星邊氣不秋，金華山水似瀛州。", "含香太守心清淨，去與神仙日日游。"]'),
('yuding-60','寄薛膺昆季','鮑溶','唐','御定全唐诗','yuding','','[]','楚山清洛兩無期，夢裏春風玉樹枝。',32,'御定全唐詩/json/486.json','["楚山清洛兩無期，夢裏春風玉樹枝。", "何況芙蓉樓上客，海門江月亦相思。"]'),
('yuding-61','楊真人籙中像','鮑溶','唐','御定全唐诗','yuding','','[]','畫中留得清虛質，人世難逢白鶴身。',32,'御定全唐詩/json/486.json','["畫中留得清虛質，人世難逢白鶴身。", "應見茅盈哀老弟，為持金籙救生人。"]'),
('yuding-62','寄盧給事汀吳員外丹','鮑溶','唐','御定全唐诗','yuding','','[]','姓丁黃鶴遼東去，客倩仙翁海上人。',32,'御定全唐詩/json/486.json','["姓丁黃鶴遼東去，客倩仙翁海上人。", "聞道姓名多改變，只今偕是聖朝臣。"]'),
('yuding-63','懷王直秀才','鮑溶','唐','御定全唐诗','yuding','','[]','鄉無竹圃為三徑，貧寄鄰家已二年。',32,'御定全唐詩/json/486.json','["鄉無竹圃為三徑，貧寄鄰家已二年。", "惟有素風身未墜，世間開口不言錢。"]'),
('yuding-64','贈真公影堂','鮑溶','唐','御定全唐诗','yuding','','[]','舊房西壁畫支公，昨暮今晨色不同。',32,'御定全唐詩/json/486.json','["舊房西壁畫支公，昨暮今晨色不同。", "遠客閒心無處所，獨添香火望虛空。"]'),
('yuding-65','贈僧戒休','鮑溶','唐','御定全唐诗','yuding','','[]','風行露宿不知貧，明月為心又是身。',32,'御定全唐詩/json/486.json','["風行露宿不知貧，明月為心又是身。", "欲問月中無我法，無人無我問何人。"]'),
('yuding-66','秋夜懷紫閣峰僧','鮑溶','唐','御定全唐诗','yuding','','[]','滿山雨色應難見，隔澗經聲又不聞。',32,'御定全唐詩/json/486.json','["滿山雨色應難見，隔澗經聲又不聞。", "紫閣夜深多入定，石台誰為掃秋雲。"]'),
('yuding-67','酬江公見寄','鮑溶','唐','御定全唐诗','yuding','','[]','曾答雁門偈，為憐同社人。多慚惠休句，偕得此陽春。',24,'御定全唐詩/json/486.json','["曾答雁門偈，為憐同社人。多慚惠休句，偕得此陽春。"]'),
('yuding-68','送羅侍禦歸西台','鮑溶','唐','御定全唐诗','yuding','','[]','歸台新柱史，辭府舊英髦。勸酒蓮幕貴，望塵驄馬高。',48,'御定全唐詩/json/486.json','["歸台新柱史，辭府舊英髦。勸酒蓮幕貴，望塵驄馬高。", "詩情分繡段，劍彩拂霜毫。此舉關風化，誰雲別恨勞。"]'),
('yuding-69','宿水亭','鮑溶','唐','御定全唐诗','yuding','','[]','雕楹彩檻壓通波，魚鱗碧幕銜曲玉。',32,'御定全唐詩/json/486.json','["雕楹彩檻壓通波，魚鱗碧幕銜曲玉。", "夜深星月伴芙蓉，如在廣寒宮裏宿。"]'),
('yuding-70','寄峨嵋山楊煉師','鮑溶','唐','御定全唐诗','yuding','','[]','道士夜誦蕊珠經，白鶴下繞香煙聽。',32,'御定全唐詩/json/486.json','["道士夜誦蕊珠經，白鶴下繞香煙聽。", "夜移經盡人上鶴，仙風吹入秋冥冥。"]'),
('yuding-71','寄海陵韓長官','鮑溶','唐','御定全唐诗','yuding','','[]','吏散重門印不開，玉琴招鶴舞裴回。',32,'御定全唐詩/json/486.json','["吏散重門印不開，玉琴招鶴舞裴回。", "野人為此多東望，雲雨仍從海上來。"]'),
('yuding-72','淮南臥病感路群侍禦訪別','鮑溶','唐','御定全唐诗','yuding','','[]','西台禦史重難言，落木疏籬繞病魂。',32,'御定全唐詩/json/486.json','["西台禦史重難言，落木疏籬繞病魂。", "一望青雲感驄馬，款行黃草出柴門。"]'),
('yuding-73','題禪定寺集公竹院','鮑溶','唐','御定全唐诗','yuding','','[]','公門得休靜，禪寺少逢迎。任客看花醉，隨僧入竹行。',36,'御定全唐詩/json/486.json','["公門得休靜，禪寺少逢迎。任客看花醉，隨僧入竹行。", "歸時常犯夜，雲裏有經聲。"]'),
('yuding-74','風箏','鮑溶','唐','御定全唐诗','yuding','','[]','何響與天通，瑤箏掛望中。彩弦非觸指，錦瑟忽聞風。',72,'御定全唐詩/json/486.json','["何響與天通，瑤箏掛望中。彩弦非觸指，錦瑟忽聞風。", "雁柱虛連勢，鸞歌且墜空。夜和霜擊磬，晴引鳳歸桐。", "幽咽誰生怨，清泠自匪躬。秦姬收寶匣，搔首不成功。"]'),
('yuding-0','經舊游','鮑溶','唐','御定全唐诗','yuding','','[]','遊魚懷故池，倦鳥懷故窠。故山系歸念，行坐青巍峨。',108,'御定全唐詩/json/487.json','["遊魚懷故池，倦鳥懷故窠。故山系歸念，行坐青巍峨。", "羸馬經舊途，此鄉喜重過。居人無故老，倍感別日多。", "但見野中墳，累累如青螺。涼風日搖落，桑下松婆娑。", "歎息追古人，臨風傷逝波。古人無不死，歎息欲如何。", "朅來遂遠心，默默存天和。"]'),
('yuding-1','過薛舍人舊隱','鮑溶','唐','御定全唐诗','yuding','','[]','寢門來哭夜，此月小祥初。風意猶憶瑟，螢光乍近書。',48,'御定全唐詩/json/487.json','["寢門來哭夜，此月小祥初。風意猶憶瑟，螢光乍近書。", "牆蒿藏宿鳥，池月上鉤魚。徒引相思淚，涓涓東逝餘。"]'),
('yuding-2','山居','鮑溶','唐','御定全唐诗','yuding','','[]','窈窕垂澗蘿，蒙茸黃葛花。鴛鴦憐碧水，照影舞金沙。',24,'御定全唐詩/json/487.json','["窈窕垂澗蘿，蒙茸黃葛花。鴛鴦憐碧水，照影舞金沙。"]'),
('yuding-3','暮秋與裴居晦宴因見采菊花之作','鮑溶','唐','御定全唐诗','yuding','','[]','菊花低色過重陽，似憶王孫白玉觴。',32,'御定全唐詩/json/487.json','["菊花低色過重陽，似憶王孫白玉觴。", "今日王孫好收采，高天已下兩回霜。"]'),
('yuding-4','望麻姑山','鮑溶','唐','御定全唐诗','yuding','','[]','幽人往往懷麻姑，浮世悠悠仙景殊。',32,'御定全唐詩/json/487.json','["幽人往往懷麻姑，浮世悠悠仙景殊。", "自從青鳥不堪使，更得蓬萊消息無。"]'),
('yuding-5','湖上望月','鮑溶','唐','御定全唐诗','yuding','','[]','湖上清涼月更好，天邊旅人猶未歸。',32,'御定全唐詩/json/487.json','["湖上清涼月更好，天邊旅人猶未歸。", "幾見金波滿還破，草蟲聲畔露沾衣。"]'),
('yuding-6','襄陽懷古','鮑溶','唐','御定全唐诗','yuding','','[]','襄陽太守沈碑意，身後身前幾年事。',32,'御定全唐詩/json/487.json','["襄陽太守沈碑意，身後身前幾年事。", "湘江千歲未為陵，水底魚龍應識字。"]'),
('yuding-7','秋夜對月寄僧特','鮑溶','唐','御定全唐诗','yuding','','[]','憶見特公賞秋處，涼溪看月清光寒。',32,'御定全唐詩/json/487.json','["憶見特公賞秋處，涼溪看月清光寒。", "今夕深溪又相映，特公何處共團圓。"]'),
('yuding-8','望江中金山寺','鮑溶','唐','御定全唐诗','yuding','','[]','一朵蓬萊在世間，梵王宮闕翠雲間。',32,'御定全唐詩/json/487.json','["一朵蓬萊在世間，梵王宮闕翠雲間。", "近南溪水更清淺，聞道遊人未忍還。"]'),
('yuding-9','宿青牛穀梁煉師仙居','鮑溶','唐','御定全唐诗','yuding','','[]','隨雲步入青牛谷，青牛道士留我宿。',32,'御定全唐詩/json/487.json','["隨雲步入青牛谷，青牛道士留我宿。", "可憐夜久月中行，惟有壇邊一枝竹。"]'),
('yuding-10','得僧書','鮑溶','唐','御定全唐诗','yuding','','[]','身歸紫霄嶺，書下白雲來。翦筍發寒字，燒花芳夜雷。',36,'御定全唐詩/json/487.json','["身歸紫霄嶺，書下白雲來。翦筍發寒字，燒花芳夜雷。", "想隨香馭至，不假定鐘催。"]'),
('yuding-11','見袁德師侍禦說江南有仙檀花，因以戲贈','鮑溶','唐','御定全唐诗','yuding','','[]','聞說天壇花耐涼，笑風含露對秋光。',32,'御定全唐詩/json/487.json','["聞說天壇花耐涼，笑風含露對秋光。", "欲求禦史更分別，何似衣花歲歲香。"]'),
('yuding-12','和王璠侍禦酬友人贈白角冠','鮑溶','唐','御定全唐诗','yuding','','[]','芙蓉寒豔鏤冰姿，天朗燈深拔豸時。',32,'御定全唐詩/json/487.json','["芙蓉寒豔鏤冰姿，天朗燈深拔豸時。", "好見吹笙伊洛上，紫煙丹鳳亦相隨。"]'),
('yuding-13','送僧擇棲遊天臺二首','鮑溶','唐','御定全唐诗','yuding','','[]','身非居士常多病，心愛空王稍覺閑。',64,'御定全唐詩/json/487.json','["身非居士常多病，心愛空王稍覺閑。", "師問寄禪何處所，浙東青翠沃洲山。", "金嶺雪晴僧獨歸，水文霞彩衲禪衣。", "可憐石室燒香夜，江月對心無是非。"]'),
('yuding-14','上巳日寄樊瓘、樊宗憲，兼呈上浙東孟中丞簡','鮑溶','唐','御定全唐诗','yuding','','[]','世間禊事風流處，鏡裏雲山若畫屏。',32,'御定全唐詩/json/487.json','["世間禊事風流處，鏡裏雲山若畫屏。", "今日會稽王內史，好將賓客醉蘭亭。"]'),
('yuding-15','暮春戲贈樊宗憲','鮑溶','唐','御定全唐诗','yuding','','[]','羌笛胡琴春調長，美人何處樂年芳。野船弄酒鴛鴦醉，',24,'御定全唐詩/json/487.json','["羌笛胡琴春調長，美人何處樂年芳。野船弄酒鴛鴦醉，"]'),
('yuding-16','酬王侍禦','鮑溶','唐','御定全唐诗','yuding','','[]','慚非青玉制，故以贈仙郎。希冀留書合，提攜在筆床。',48,'御定全唐詩/json/487.json','["慚非青玉制，故以贈仙郎。希冀留書合，提攜在筆床。", "詎能輝繡服，安得似芸香。所報何珍重，清明勝夜光。"]'),
('yuding-17','寄宋申錫評事時從李少師移軍回歸','鮑溶','唐','御定全唐诗','yuding','','[]','君逐元侯靜虜歸，虎旗龍節駐春暉。欲求岱岳燔柴禮，',40,'御定全唐詩/json/487.json','["君逐元侯靜虜歸，虎旗龍節駐春暉。欲求岱岳燔柴禮，", "心期共賀太平世，去去故鄉親食薇。"]'),
('yuding-18','夏日懷杜悰駙馬','鮑溶','唐','御定全唐诗','yuding','','[]','五月清涼蕭史家，瑤池分水種菱花。回文地簟龍鱗浪，',40,'御定全唐詩/json/487.json','["五月清涼蕭史家，瑤池分水種菱花。回文地簟龍鱗浪，", "仍聞聖主知書癖，鳳閣燒香對五車。"]'),
('yuding-19','鶯雛','鮑溶','唐','御定全唐诗','yuding','','[]','雙鶯銜野蝶，枝上教雛飛。避日花陰語，愁風竹裏啼。',36,'御定全唐詩/json/487.json','["雙鶯銜野蝶，枝上教雛飛。避日花陰語，愁風竹裏啼。", "須防美人賞，為爾好毛衣。"]'),
('yuding-20','上陽宮月','鮑溶','唐','御定全唐诗','yuding','','[]','水北宮城夜柝嚴，宮西新月影纖纖。受環花幌小開鏡，',40,'御定全唐詩/json/487.json','["水北宮城夜柝嚴，宮西新月影纖纖。受環花幌小開鏡，", "合裁班扇思行幸，願托涼風篋笥嫌。"]'),
('yuding-21','淮南臥病聞李相夷簡移軍山陽以靖東寇感激之下因抒長句','鮑溶','唐','御定全唐诗','yuding','','[]','太白星前龍虎符，元臣出將順天誅。教聞清淨蕭丞相，',40,'御定全唐詩/json/487.json','["太白星前龍虎符，元臣出將順天誅。教聞清淨蕭丞相，", "魯連未必蹈滄海，應見麒麟新畫圖。"]'),
('yuding-22','讀淮南李相行營至楚州詩','鮑溶','唐','御定全唐诗','yuding','','[]','閫外建牙威不賓，古來戡難憶忠臣。已分舟楫歸元老，',40,'御定全唐詩/json/487.json','["閫外建牙威不賓，古來戡難憶忠臣。已分舟楫歸元老，", "來年二月登封禮，去望台星扈日輪。"]'),
('yuding-23','讀李相心中樂','鮑溶','唐','御定全唐诗','yuding','','[]','負海狂鯨縱巨鱗，四朝天子阻時巡。誰將侯玉乖南面，',40,'御定全唐詩/json/487.json','["負海狂鯨縱巨鱗，四朝天子阻時巡。誰將侯玉乖南面，", "果聞丞相心中樂，上贊陶唐一萬春。"]'),
('yuding-24','聞國家將行封禪聊抒臣情','鮑溶','唐','御定全唐诗','yuding','','[]','雲雨由來隨六龍，玉泥瑤檢不幹封。山知槱柞新煙火，',40,'御定全唐詩/json/487.json','["雲雨由來隨六龍，玉泥瑤檢不幹封。山知槱柞新煙火，", "旅中病客諳堯曲，身賤何由奏九重。"]'),
('yuding-25','和淮南李相公夷簡喜平淄青回軍之作','鮑溶','唐','御定全唐诗','yuding','','[]','橫笛臨吹發曉軍，元戎幢節拂寒雲。搜山羽騎乘風引，',40,'御定全唐詩/json/487.json','["橫笛臨吹發曉軍，元戎幢節拂寒雲。搜山羽騎乘風引，", "馬毛不汗東方靖，行見蕭何第一勳。"]'),
('yuding-26','秋暮八月十五夜與王璠侍禦賞月因愴遠離聊以奉寄','鮑溶','唐','御定全唐诗','yuding','','[]','前月月明夜，美人同遠光。清塵一以間，今夕坐相忘。',36,'御定全唐詩/json/487.json','["前月月明夜，美人同遠光。清塵一以間，今夕坐相忘。", "風落芙蓉露，凝餘繡服香。"]'),
('yuding-27','送蕭世秀才','鮑溶','唐','御定全唐诗','yuding','','[]','心交別我西京去，愁滿春魂不易醒。',32,'御定全唐詩/json/487.json','["心交別我西京去，愁滿春魂不易醒。", "從此無人訪窮病，馬蹄車轍草青青。"]'),
('yuding-28','懷惠明禪師','鮑溶','唐','御定全唐诗','yuding','','[]','秋天欲霜夜無風，我意不在天地中。雪山世界此涼夜，',40,'御定全唐詩/json/487.json','["秋天欲霜夜無風，我意不在天地中。雪山世界此涼夜，", "雪嶺無人又問來，十年夏臘平安否。"]'),
('yuding-29','吳中夜別','鮑溶','唐','御定全唐诗','yuding','','[]','楚客秋思著黃葉，吳姬夜歌停碧雲。',32,'御定全唐詩/json/487.json','["楚客秋思著黃葉，吳姬夜歌停碧雲。", "聲盡燈前各流淚，水天涼冷雁離群。"]'),
('yuding-30','隋家井','鮑溶','唐','御定全唐诗','yuding','','[]','玉鉤欄下寒泉水，金轆轤邊影照人。',32,'御定全唐詩/json/487.json','["玉鉤欄下寒泉水，金轆轤邊影照人。", "此水今為九泉路，數枝花照數堆塵。"]'),
('yuding-31','寄王璠侍禦求蜀箋','鮑溶','唐','御定全唐诗','yuding','','[]','蜀川箋紙彩雲初，聞說王家最有餘。',32,'御定全唐詩/json/487.json','["蜀川箋紙彩雲初，聞說王家最有餘。", "野客思將池上學，石楠紅葉不堪書。"]'),
('yuding-32','湘妃列女操','鮑溶','唐','御定全唐诗','yuding','','[]','有虞夫人哭虞後，淑女何事又傷離。竹上淚跡生不盡，',96,'御定全唐詩/json/487.json','["有虞夫人哭虞後，淑女何事又傷離。竹上淚跡生不盡，", "三湘測測流急綠，秋夜露寒蜀帝飛。楓林月斜楚臣宿，", "終疑既遠雙悄悄，蒼梧舊雲豈難召，老猿心寒不可嘯。", "目眄眄兮意蹉跎，魂騰騰兮驚秋波。曲一盡兮憶再奏，"]'),
('yuding-33','羽林行','鮑溶','唐','御定全唐诗','yuding','','[]','朝出羽林宮，入參雲台議。獨請萬里行，不奏和親事。',108,'御定全唐詩/json/487.json','["朝出羽林宮，入參雲台議。獨請萬里行，不奏和親事。", "君王重年少，深納開邊利。寶馬雕玉鞍，一朝從萬騎。", "煌煌都門外，祖帳光七貴。歌鐘樂行軍，雲物慘別地。", "簫笳整部曲，幢蓋動郊次。臨風親戚懷，滿袖兒女淚。", "行行複何贈，長劍報恩字。"]'),
('yuding-34','鳴雁行','鮑溶','唐','御定全唐诗','yuding','','[]','七月朔方雁心苦，聯影翻空落南土。八月江南陰複晴，',64,'御定全唐詩/json/487.json','["七月朔方雁心苦，聯影翻空落南土。八月江南陰複晴，", "楚童夜宿煙波側，沙上布羅連草色。月暗風悲欲下天，", "江南羽族本不少，寧得網羅此客鳥。"]'),
('yuding-35','織婦詞','鮑溶','唐','御定全唐诗','yuding','','[]','百日織彩絲，一朝停杼機。機中有雙鳳，化作天邊衣。',72,'御定全唐詩/json/487.json','["百日織彩絲，一朝停杼機。機中有雙鳳，化作天邊衣。", "使人馬如風，誠不阻音徽。影響隨羽翼，雙雙繞君飛。", "行人豈願行，不怨不知歸。所怨天盡處，何人見光輝。"]'),
('yuding-36','塞上行','鮑溶','唐','御定全唐诗','yuding','','[]','西風應時筋角堅，承露牧馬水草冷。',32,'御定全唐詩/json/487.json','["西風應時筋角堅，承露牧馬水草冷。", "可憐黃河九曲盡，氈館牢落胡無影。"]'),
('yuding-37','采珠行','鮑溶','唐','御定全唐诗','yuding','','[]','東方暮空海面平，驪龍弄珠燒月明。海人驚窺水底火，',112,'御定全唐詩/json/487.json','["東方暮空海面平，驪龍弄珠燒月明。海人驚窺水底火，", "擘波下去忘此身，迢迢謂海無靈神。海宮正當龍睡重，", "一團冰容掌上清，四面人入光中行。騰華乍搖白日影，", "一富何須龍頷前，千金幾葬魚腹裏。鱗蟲變化為陰陽，", "飲風衣日亦飽暖，老翁擲卻荊雞卵。"]'),
('yuding-38','采葛行','鮑溶','唐','御定全唐诗','yuding','','[]','春溪幾回葛花黃，黃麝引子山山香。蠻女不惜手足損，',96,'御定全唐詩/json/487.json','["春溪幾回葛花黃，黃麝引子山山香。蠻女不惜手足損，", "殷勤十指蠶吐絲，當窗嫋嫋聲高機。織成一尺無一兩，", "衣親玉體又何如，杳然獨對秋風曙。鏡湖女兒嫁鮫人，", "自茲貢薦無人惜，那敢更爭龍手跡。蠻女將來海市頭，"]'),
('yuding-39','南塘二首','鮑溶','唐','御定全唐诗','yuding','','[]','南塘旅舍秋淺清，夜深綠蘋風不生。',64,'御定全唐詩/json/487.json','["南塘旅舍秋淺清，夜深綠蘋風不生。", "蓮花受露重如睡，斜月起動鴛鴦聲。", "塘東白日駐紅霧，早魚翻光落碧潯。", "畫舟蘭棹欲破浪，恐畏驚動蓮花心。"]'),
('yuding-40','東鄰女','鮑溶','唐','御定全唐诗','yuding','','[]','雙飛鷓鴣春影斜，美人盤金衣上花。',32,'御定全唐詩/json/487.json','["雙飛鷓鴣春影斜，美人盤金衣上花。", "身為父母幾時客，一生知向何人家。"]'),
('yuding-41','寄李都護','鮑溶','唐','御定全唐诗','yuding','','[]','去年河上送行人，萬里弓旌一武臣。',32,'御定全唐詩/json/487.json','["去年河上送行人，萬里弓旌一武臣。", "聞道玉關烽火滅，犬戎知有外家親。"]'),
('yuding-42','長安旅舍懷舊山','鮑溶','唐','御定全唐诗','yuding','','[]','昨夜清涼夢本山，眠雲喚鶴有慚顏。',32,'御定全唐詩/json/487.json','["昨夜清涼夢本山，眠雲喚鶴有慚顏。", "青蓮道士長堪羨，身外無名至老閑。"]'),
('yuding-43','漢宮詞二首','鮑溶','唐','御定全唐诗','yuding','','[]','柏梁宸居清窈窕，東方先生夜待詔。',64,'御定全唐詩/json/487.json','["柏梁宸居清窈窕，東方先生夜待詔。", "夜久月當承露盤，內人吹笙舞鳳鸞。", "月映東窗似玉輪，未央前殿絕聲塵。", "宮槐花落西風起，鸚鵡驚寒夜喚人。"]'),
('yuding-44','薦冰','鮑溶','唐','御定全唐诗','yuding','','[]','西陸宜先啟，春寒寢廟清。曆官分氣候，天子薦精誠。',72,'御定全唐詩/json/487.json','["西陸宜先啟，春寒寢廟清。曆官分氣候，天子薦精誠。", "已辨瑤池色，如和玉佩鳴。禮餘神轉肅，曙後月殘明。", "雅合霜容潔，非同雪體輕。空憐一掬水，珍重此時情。"]'),
('yuding-45','送薛補闕入朝','鮑溶','唐','御定全唐诗','yuding','','[]','平原門下十餘人，獨受恩多未殺身。每歎陸家兄弟少，',40,'御定全唐詩/json/487.json','["平原門下十餘人，獨受恩多未殺身。每歎陸家兄弟少，", "賴有軍中遺令在，猶將談笑對風塵。"]'),
('yuding-46','句','鮑溶','唐','御定全唐诗','yuding','','[]','萬里岐路多，一身天地窄。',12,'御定全唐詩/json/487.json','["萬里岐路多，一身天地窄。"]'),
('yuding-0','薦冰','盧鈞','唐','御定全唐诗','yuding','','[]','薦冰朝日後，辟廟曉光清。不改晶熒質，能彰雨露情。',72,'御定全唐詩/json/488.json','["薦冰朝日後，辟廟曉光清。不改晶熒質，能彰雨露情。", "且無霜共潔，豈與水均明。在捧搖寒色，當呈表素誠。", "凝姿陳俎豆，浮彩映窗楹。皎皎盤盂側，棱棱嚴氣生。"]'),
('yuding-1','薦冰','範傳質','唐','御定全唐诗','yuding','','[]','乘春方啟閉，羞獻有常程。潔朗寒光徹，輝華素彩明。',72,'御定全唐詩/json/488.json','["乘春方啟閉，羞獻有常程。潔朗寒光徹，輝華素彩明。", "色凝霜雪淨，影照冕旒清。肅肅將崇禮，兢兢示捧盈。", "方圓陳玉座，小大表精誠。朝覿當西陸，桃弧每共行。"]'),
('yuding-2','賦得芙蓉出水','賈謨','唐','御定全唐诗','yuding','','[]','的皪舒芳豔，紅姿映綠蘋。搖風開細浪，出沼媚清晨。',72,'御定全唐詩/json/488.json','["的皪舒芳豔，紅姿映綠蘋。搖風開細浪，出沼媚清晨。", "翻影初迎日，流香暗襲人。獨披千葉淺，不競百花春。", "魚戲參差動，龜遊次第新。涉江如可采，從此免迷津。"]'),
('yuding-3','恩賜魏文貞公諸孫舊第以導直臣','陳彥博','唐','御定全唐诗','yuding','','[]','阿衡隨逝水，池館主他人。天意能酬德，雲孫喜庇身。',72,'御定全唐詩/json/488.json','["阿衡隨逝水，池館主他人。天意能酬德，雲孫喜庇身。", "生前由直道，歿後振芳塵。雨露新恩日，芝蘭舊裏春。", "勳庸留十代，光彩映諸鄰。共賀升平日，從茲得諫臣。"]'),
('yuding-4','使南海道長沙，題道林嶽麓寺','唐扶','唐','御定全唐诗','yuding','','[]','道林岳麓仲與昆，卓犖請從先後論。松根踏雲二千步，',112,'御定全唐詩/json/488.json','["道林岳麓仲與昆，卓犖請從先後論。松根踏雲二千步，", "即今異鳥聲不斷，聞道看花春更繁。從容一衲分若有，", "稍揖皇英頮濃淚，試與屈賈招清魂。荒唐大樹悉楠桂，", "主人念我塵眼昏，半夜號令期至暾。遲回雖得上白舫，", "晚來光彩更騰射，筆鋒正健如可吞。"]'),
('yuding-5','和兵部鄭侍郎省中四松詩','唐扶','唐','御定全唐诗','yuding','','[]','幽抱應無語，貞松遂自栽。寄懷丞相業，因擢大夫材。',120,'御定全唐詩/json/488.json','["幽抱應無語，貞松遂自栽。寄懷丞相業，因擢大夫材。", "日射蒼鱗動，塵迎翠帚回。嫩茸含細粉，初葉泛新杯。", "偶聖為舟去，逢時與鶴來。寒聲連曉竹，靜氣結陰苔。", "赫奕鳴騶至，熒煌洞戶開。良辰一臨眺，憩樹幾裴回。", "恨發風期阻，詩從綺思裁。還聞舊凋契，凡在此中培。"]'),
('yuding-6','和兵部鄭侍郎省中四松詩','陶雍','唐','御定全唐诗','yuding','','[]','右相曆兵署，四松皆手栽。劚時驚鶴去，移處帶雲來。',120,'御定全唐詩/json/488.json','["右相曆兵署，四松皆手栽。劚時驚鶴去，移處帶雲來。", "根倍雙桐植，花分八桂開。生成造化力，長作棟樑材。", "豈羨蘭依省，猶嫌柏占台。出樓終百尺，入夢已三台。", "幽韻和宮漏，餘香度酒杯。拂冠枝上雪，染履影中苔。", "高位相承地，新詩寡和才。何由比蘿蔓，樊附在條枚。"]'),
('yuding-7','譚子池','郭周藩','唐','御定全唐诗','yuding','','[]','澄水一百步，世名譚子池。余詰陵陽叟，此池當因誰。',288,'御定全唐詩/json/488.json','["澄水一百步，世名譚子池。余詰陵陽叟，此池當因誰。", "父老謂餘說，本郡譚叔皮。開元末年中，生子字阿宜。", "墜地便能語，九歲多鬚眉。不飲亦不食，未嘗言渴饑。", "十五銳行走，快馬不能追。二十入山林，一去無還期。", "父母憶念深，鄉閭為立祠。大曆元年春，此兒忽來歸。", "頭冠簪鳳凰，身著霞裳衣。普遍拯疲俗，丁寧告親知。", "余為神仙官，下界不可祈。恐為妖魅假，不如早平夷。", "此有黃金藏，鎮在茲廟基。發掘散生聚，可以救貧羸。", "金出繼靈泉，湛若清琉璃。泓澄表符瑞，水旱無竭時。", "言訖辭沖虛，杳靄上玄微。凡情留不得，攀望眾號悲。", "尋稟神仙誡，徹廟劚開窺。果獲無窮寶，均融沾因危。", "巨源出嶺頂，噴湧世間稀。異境流千古，終年福四維。"]'),
('yuding-8','金穀園花發懷古','侯冽','唐','御定全唐诗','yuding','','[]','金穀千年後，春花發滿園。紅芳徒笑日，穠豔尚迎軒。',72,'御定全唐詩/json/488.json','["金穀千年後，春花發滿園。紅芳徒笑日，穠豔尚迎軒。", "雨濕輕光軟，風搖碎影翻。猶疑施錦帳，堪歎罷朱紈。", "愁態鶯吟澀，啼容露綴繁。殷勤問前事，桃李竟無言。"]'),
('yuding-9','花發上林','侯冽','唐','御定全唐诗','yuding','','[]','花發三陽盛，香飄五柞深。素暉雲積苑，紅彩繡張林。',72,'御定全唐詩/json/488.json','["花發三陽盛，香飄五柞深。素暉雲積苑，紅彩繡張林。", "落水隨魚戲，搖風映鳥吟。瓊樓出高豔，玉輦駐濃陰。", "亂蝶枝開影，繁蜂蕊上音。鮮芳盈禁籞，布澤荷天心。"]'),
('yuding-10','金穀園花發懷古','王質','唐','御定全唐诗','yuding','','[]','寂寥金穀澗，花發舊時園。人事空懷古，煙霞此獨存。',72,'御定全唐詩/json/488.json','["寂寥金穀澗，花發舊時園。人事空懷古，煙霞此獨存。", "管弦非上客，歌舞少王孫。繁蕊風驚散，輕紅鳥乍翻。", "山川終不改，桃李自無言。今日經塵路，淒涼詎可論。"]'),
('yuding-11','和太原張相公山亭懷古','高銖','唐','御定全唐诗','yuding','','[]','鬥石類岩巘，飛流瀉潺湲。遠壑簷宇際，孤巒雉堞間。',48,'御定全唐詩/json/488.json','["鬥石類岩巘，飛流瀉潺湲。遠壑簷宇際，孤巒雉堞間。", "何必到海嶽，境幽機自閑。茲焉得高趣，高步謝東山。"]'),
('yuding-0','八月五日中部官舍讀唐曆天寶已來追愴故事','舒元輿','唐','御定全唐诗','yuding','','[]','將尋國朝事，靜讀柳芳曆。八月日之五，開卷忽感激。',276,'御定全唐詩/json/489.json','["將尋國朝事，靜讀柳芳曆。八月日之五，開卷忽感激。", "正當天寶末，撫事坐追惜。仰思聖明帝，貽禍在肘腋。", "楊李盜吏權，貪殘日狼藉。燕戎伺其便，百萬奮長戟。", "兩河連煙塵，二京成瓦礫。生人死欲盡，揳業猶不息。", "肅宗傳寶圖，寇難連年擊。天地方開泰，鑄鼎成繼述。", "萬國哭龍袞，悲思動蠻貊。自此千秋節，不復動金石。", "悲風揚霜天，繐帷冷塵席。零落太平老，東西亂離客。", "往往為餘言，嗚咽淚雙滴。況當近塞地，哀吹起邊笛。", "撫幾觀陳文，使我心不懌。花萼笑繁華，溫泉樹容碧。", "霓裳煙雲盡，梨園風雨隔。露囊與金鏡，東逝驚波溺。", "昔聞歡娛事，今日成慘戚。神仙不可求，劍璽苔文積。", "萬古長恨端，蕭蕭泰陵陌。"]'),
('yuding-1','坊州按獄','舒元輿','唐','御定全唐诗','yuding','','[]','中部接戎塞，頑山四周遭。風冷木長瘦，石磽人亦勞。',300,'御定全唐詩/json/489.json','["中部接戎塞，頑山四周遭。風冷木長瘦，石磽人亦勞。", "牧守苟懷仁，癢之時為搔。其愛如赤子，始得無啼號。", "奈何貪狼心，潤屋沉脂膏。攫搏如猛虎，吞噬若狂獒。", "山禿逾高采，水窮益深撈。龜魚既絕跡，鹿兔無遺毛。", "氓苦稅外緡，吏憂笑中刀。大君明四目，燭之洞秋毫。", "眷茲一州命，慮齊墜波濤。臨軒詔小臣，汝往窮貪饕。", "分明舉公法，為我緩窮騷。小臣誠小心，奉命如煎熬。", "飲冰不待夕，驅馬淩晨皋。及此督簿書，遊詞出狴牢。", "門牆見狼狽，案牘聞腥臊。探情與之言，變態如奸猱。", "真非既巧飾，偽意乃深韜。去惡猶農夫，稂莠須耘耨。", "恢恢布疏網，罪者何由逃。自顧孱鈍姿，利器非能操。", "六旬始歸奏，霜落秋原蒿。寄謝守土臣，努力清郡曹。", "須知所甚卑，勿謂天之高。"]'),
('yuding-2','橋山懷古','舒元輿','唐','御定全唐诗','yuding','','[]','軒轅厭代千萬秋，淥波浩蕩東南流。今來古往無不死，',115,'御定全唐詩/json/489.json','["軒轅厭代千萬秋，淥波浩蕩東南流。今來古往無不死，", "橋山突兀在其左，荒榛交鎖寒風愁。神仙天下亦如此，", "哀喧叫笑牧童戲，陰天月落狐狸遊。卻思皇墳立人極，", "知勇神天不自大，風後力牧輸長籌。襄城迷路問童子，", "君不見黃龍飛去山下路，斷髯成草風颼颼。"]'),
('yuding-3','坊州按獄蘇氏莊記室二賢自鄜州走馬相訪留連數日發後獨坐寂寞因成詩寄之','舒元輿','唐','御定全唐诗','yuding','','[]','十年一相見，世俗信多岐。雲雨易分散，山川長間之。',336,'御定全唐詩/json/489.json','["十年一相見，世俗信多岐。雲雨易分散，山川長間之。", "我銜鳳闕恩，按獄橋山陲。君在龍驤府，掌奏羽檄詞。", "相去百餘裏，魂夢自相馳。形容在胸臆，書劄通相思。", "煩君愛我深，輕車忽載脂。塞門秋色老，霜氣方凝姿。", "此地少平川，岡阜相參差。誰知路非遠，行者多雲疲。", "君能犯勁風，信宿淩欹危。情親不自倦，下馬開雙眉。", "相對坐沉吟，屈指驚歲時。萬事且莫問，一杯欣共持。", "陽烏忽西傾，明蟾掛高枝。捲簾引瑤玉，滅燭臨霜墀。", "中庭有疏蘆，淅淅聞風吹。長河卷雲色，凝碧無瑕疵。", "一言開我懷，曠然澹希夷。悠悠夜方永，冷思偏相宜。", "眉睫無他人，與君閑解題。陶然叩寂寞，再請吟清詩。", "得意且忘言，何況竹與絲。頃刻過三夕，起坐輕四肢。", "明朝告行去，慘然還別離。出門送君去，君馬揚金羈。", "回來坐空堂，寂寞無人知。重重碧雲合，何處尋佳期。"]'),
('yuding-4','履春冰','舒元輿','唐','御定全唐诗','yuding','','[]','投跡清冰上，凝光動早春。兢兢愁陷履，步步怯移身。',72,'御定全唐詩/json/489.json','["投跡清冰上，凝光動早春。兢兢愁陷履，步步怯移身。", "鳥照微生水，狐聽或過人。細遷形外影，輕躡鏡中輪。", "咫尺憂偏遠，危疑懼已頻。願堅容足分，莫使獨驚神。"]'),
('yuding-5','贈李翱','舒元輿','唐','御定全唐诗','yuding','','[]','湘江舞罷忽成悲，便脫蠻靴出絳帷。',32,'御定全唐詩/json/489.json','["湘江舞罷忽成悲，便脫蠻靴出絳帷。", "誰是蔡邕琴酒客，魏公懷舊嫁文姬。"]'),
('yuding-0','登長安慈恩寺塔','盧宗回','唐','御定全唐诗','yuding','','[]','東方曉日上翔鸞，西轉蒼龍拂露盤。渭水寒光搖藻井，',40,'御定全唐詩/json/490.json','["東方曉日上翔鸞，西轉蒼龍拂露盤。渭水寒光搖藻井，", "暫輟去蓬悲不定，一憑金界望長安。"]'),
('yuding-1','古鏡歌','周匡物','唐','御定全唐诗','yuding','','[]','軒轅鑄鏡誰將去，曾被良工瀉金取。明月中心桂不生，',40,'御定全唐詩/json/490.json','["軒轅鑄鏡誰將去，曾被良工瀉金取。明月中心桂不生，", "欲向高臺對曉開，不知誰是孤光主。"]'),
('yuding-2','及第謠','周匡物','唐','御定全唐诗','yuding','','[]','水國寒消春日長，燕鶯催促花枝忙。風吹金榜落凡世，',48,'御定全唐詩/json/490.json','["水國寒消春日長，燕鶯催促花枝忙。風吹金榜落凡世，", "驊騮一百三十蹄，踏破蓬萊五雲地。物經千載出塵埃，"]'),
('yuding-3','及第後謝座主','周匡物','唐','御定全唐诗','yuding','','[]','一從東越入西秦，十度聞鶯不見春。試向昆山投瓦礫，',40,'御定全唐詩/json/490.json','["一從東越入西秦，十度聞鶯不見春。試向昆山投瓦礫，", "中夜自將形影語，古來吞炭是何人。"]'),
('yuding-4','自題讀書堂','周匡物','唐','御定全唐诗','yuding','','[]','窗外捲簾侵碧落，檻前敲竹響青冥。',32,'御定全唐詩/json/490.json','["窗外捲簾侵碧落，檻前敲竹響青冥。", "黃昏不欲留人宿，雲起風生龍虎醒。"]'),
('yuding-5','應舉題錢塘公館','周匡物','唐','御定全唐诗','yuding','','[]','萬里茫茫天塹遙，秦皇底事不安橋。',32,'御定全唐詩/json/490.json','["萬里茫茫天塹遙，秦皇底事不安橋。", "錢塘江口無錢過，又阻西陵兩信潮。"]'),
('yuding-6','題旅櫬','廖有方','唐','御定全唐诗','yuding','','[]','嗟君沒世委空囊，幾度勞心翰墨場。',32,'御定全唐詩/json/490.json','["嗟君沒世委空囊，幾度勞心翰墨場。", "半面為君申一慟，不知何處是家鄉。"]'),
('yuding-7','立春日呈宮傅侍郎','皇甫曙','唐','御定全唐诗','yuding','','[]','朝旦微風吹曉霞，散為和氣滿家家。不知容貌潛消落，',40,'御定全唐詩/json/490.json','["朝旦微風吹曉霞，散為和氣滿家家。不知容貌潛消落，", "摩娑酒甕重封閉，待入新年共賞花。"]'),
('yuding-8','賦得玉聲如樂','潘存實','唐','御定全唐诗','yuding','','[]','表質自堅貞，因人一扣鳴。靜將金並響，妙與樂同聲。',72,'御定全唐詩/json/490.json','["表質自堅貞，因人一扣鳴。靜將金並響，妙與樂同聲。", "杳杳疑風送，泠泠似曲成。韻含湘瑟切，音帶舜弦清。", "不獨藏虹氣，猶能暢物情。後夔如為聽，從此振琮琤。"]'),
('yuding-9','送林刺史簡言之漳州','陳去疾','唐','御定全唐诗','yuding','','[]','江樹欲含曛，清歌一送君。征驂辭荔浦，別袂暗松雲。',48,'御定全唐詩/json/490.json','["江樹欲含曛，清歌一送君。征驂辭荔浦，別袂暗松雲。", "路狹橫柯度，山深墜葉聞。明朝宿何處，未忍醉中分。"]'),
('yuding-10','憶山中','陳去疾','唐','御定全唐诗','yuding','','[]','長吟重悒然，為憶山中年。清瑟泛遙夜，亂花隨暮煙。',96,'御定全唐詩/json/490.json','["長吟重悒然，為憶山中年。清瑟泛遙夜，亂花隨暮煙。", "珠林餘露氣，乳竇滴香泉。跡遠塵埃外，花開綺藻前。", "岩羅雲貌逸，竹抱水容妍。蕙磴飛英繞，萍潭片影懸。", "林藏諸曲勝，台擅一峰偏。會可標真寄，焚香對石筵。"]'),
('yuding-11','元夕京城和歐陽袞','陳去疾','唐','御定全唐诗','yuding','','[]','蘭焰芳芬徹曉開，珠光新靄映人來。歌迎甲夜催銀管，',40,'御定全唐詩/json/490.json','["蘭焰芳芬徹曉開，珠光新靄映人來。歌迎甲夜催銀管，", "此時月色同沾醉，何處遊輪陌上回。"]'),
('yuding-12','送韓將軍之雁門','陳去疾','唐','御定全唐诗','yuding','','[]','荒塞峰煙百道馳，雁門風色暗旌旗。破圍鐵騎長驅疾，',40,'御定全唐詩/json/490.json','["荒塞峰煙百道馳，雁門風色暗旌旗。破圍鐵騎長驅疾，", "歸來長揖功成後，黃石當年故有期。"]'),
('yuding-13','賦得騏驥長鳴','陳去疾','唐','御定全唐诗','yuding','','[]','騏驥忻知己，嘶鳴忽異常。積悲攄怨抑，一舉徹穹蒼。',72,'御定全唐詩/json/490.json','["騏驥忻知己，嘶鳴忽異常。積悲攄怨抑，一舉徹穹蒼。", "跡類三年鳥，心馳五達莊。何言從蹇躓，今日逐騰驤。", "牛皂休維縶，天衢恣陸梁。向非逢伯樂，誰足見其長。"]'),
('yuding-14','偶題','陳去疾','唐','御定全唐诗','yuding','','[]','魂夢天南垂，宿昔萬里道。池台花氣深，到處生春草。',24,'御定全唐詩/json/490.json','["魂夢天南垂，宿昔萬里道。池台花氣深，到處生春草。"]'),
('yuding-15','春宮曲','陳去疾','唐','御定全唐诗','yuding','','[]','流鶯春曉喚櫻桃，花外傳呼殿影高。',32,'御定全唐詩/json/490.json','["流鶯春曉喚櫻桃，花外傳呼殿影高。", "抱裏琵琶最承寵，君王敕賜玉檀槽。"]'),
('yuding-16','採蓮曲','陳去疾','唐','御定全唐诗','yuding','','[]','粉光花色葉中開，荷氣衣香水上來。',32,'御定全唐詩/json/490.json','["粉光花色葉中開，荷氣衣香水上來。", "棹響清潭見斜領，雙鴛何事亦相猜。"]'),
('yuding-17','踏歌行','陳去疾','唐','御定全唐诗','yuding','','[]','鴛鴦樓下萬花新，翡翠宮前百戲陳。',64,'御定全唐詩/json/490.json','["鴛鴦樓下萬花新，翡翠宮前百戲陳。", "夭矯翔龍銜火樹，飛來瑞鳳散芳春。", "仙蹕初傳紫禁香，瑞雲開處夜花芳。", "繁弦促管升平調，綺綴丹蓮借月光。"]'),
('yuding-18','塞下曲','陳去疾','唐','御定全唐诗','yuding','','[]','春至金河雪似花，蕭條玉塞但胡沙。',32,'御定全唐詩/json/490.json','["春至金河雪似花，蕭條玉塞但胡沙。", "曉來重上關城望，惟見驚塵不見家。"]'),
('yuding-19','送人謫幽州','陳去疾','唐','御定全唐诗','yuding','','[]','臨路深懷放廢慚，夢中猶自憶江南。',32,'御定全唐詩/json/490.json','["臨路深懷放廢慚，夢中猶自憶江南。", "莫言塞北春風少，還勝炎荒入瘴嵐。"]'),
('yuding-20','西上辭母墳','陳去疾','唐','御定全唐诗','yuding','','[]','高蓋山頭日影微，黃昏獨立宿禽稀。',32,'御定全唐詩/json/490.json','["高蓋山頭日影微，黃昏獨立宿禽稀。", "林間滴酒空垂淚，不見丁寧囑早歸。"]'),
('yuding-0','履春冰','張蕭遠','唐','御定全唐诗','yuding','','[]','一步一愁新，輕輕恐陷人。薄光全透日，殘影半銷春。',72,'御定全唐詩/json/491.json','["一步一愁新，輕輕恐陷人。薄光全透日，殘影半銷春。", "蟬想行時翼，魚驚蹋處鱗。底虛難駐足，岸闊怯回身。", "豈暇踟躕久，寧辭顧盼頻。願將兢慎意，從此赴通津。"]'),
('yuding-1','觀燈','張蕭遠','唐','御定全唐诗','yuding','','[]','十萬人家火燭光，門門開處見紅妝。歌鐘喧夜更漏暗，',40,'御定全唐詩/json/491.json','["十萬人家火燭光，門門開處見紅妝。歌鐘喧夜更漏暗，", "寶釵驟馬多遺落，依舊明朝在路傍。"]'),
('yuding-2','送宮人入道','張蕭遠','唐','御定全唐诗','yuding','','[]','舍寵求仙畏色衰，辭天素面立階墀。金丹擬駐千年貌，',40,'御定全唐詩/json/491.json','["舍寵求仙畏色衰，辭天素面立階墀。金丹擬駐千年貌，", "從來宮女皆相妒，聞向瑤台盡淚垂。"]'),
('yuding-3','句','張蕭遠','唐','御定全唐诗','yuding','','[]','秦雲寂寂僧還定，盡日無人鹿繞床。',41,'御定全唐詩/json/491.json','["秦雲寂寂僧還定，盡日無人鹿繞床。", "日暮風吹官渡柳，白鴉飛出石頭牆。", "雙雙白燕入祠堂。。"]'),
('yuding-4','見志','李播','唐','御定全唐诗','yuding','','[]','去歲買琴不與價，今年沽酒未還錢。',32,'御定全唐詩/json/491.json','["去歲買琴不與價，今年沽酒未還錢。", "門前債主雁行立，屋裏醉人魚貫眠。"]'),
('yuding-5','魚上冰','王季則','唐','御定全唐诗','yuding','','[]','北陸收寒盡，東風解凍初。冰消通淺溜，氣變躍潛魚。',72,'御定全唐詩/json/491.json','["北陸收寒盡，東風解凍初。冰消通淺溜，氣變躍潛魚。", "應節似知化，揚鬐任所如。浮沉非樂藻，沿溯異傳書。", "結網時空久，臨川意有餘。為龍將可望，今日愧才虛。"]'),
('yuding-6','魚上冰','紀元皋','唐','御定全唐诗','yuding','','[]','春生寒氣滅，稍動伏泉魚。乍喜東風至，來觀曲浦初。',72,'御定全唐詩/json/491.json','["春生寒氣滅，稍動伏泉魚。乍喜東風至，來觀曲浦初。", "近冰朱鬣見，望日錦鱗舒。漸覺流澌退，還忻掉尾餘。", "噞喁情自樂，沿溯意寧疏。倘得隨鯤化，終能戾太虛。"]'),
('yuding-7','魚上冰','吳晃','唐','御定全唐诗','yuding','','[]','春水潛鱗發，寒潭舊藻疏。揚鬐順氣後，振鬣上冰初。',72,'御定全唐詩/json/491.json','["春水潛鱗發，寒潭舊藻疏。揚鬐順氣後，振鬣上冰初。", "戲廣憐空潔，浮清媚景虛。戒貪還避餌，思達每懷書。", "濕映流澌薄，狂遊觸浪餘。終希泮渙澤，為化北溟魚。"]'),
('yuding-8','贈柳氏妓','鄭還古','唐','御定全唐诗','yuding','','[]','冶豔出神仙，歌聲勝管弦。詞輕白紵曲，歌遏碧雲天。',48,'御定全唐詩/json/491.json','["冶豔出神仙，歌聲勝管弦。詞輕白紵曲，歌遏碧雲天。", "未擬生裴秀，如何乞鄭玄。不堪金谷水，橫過墜樓前。"]'),
('yuding-9','吉州道中','鄭還古','唐','御定全唐诗','yuding','','[]','吉州新置掾，馳驛到條山。薏苡殊非謗，羊腸未是艱。',48,'御定全唐詩/json/491.json','["吉州新置掾，馳驛到條山。薏苡殊非謗，羊腸未是艱。", "自慚多白髮，爭敢競朱顏。若有前生債，今朝不懊還。"]'),
('yuding-10','望思台','鄭還古','唐','御定全唐诗','yuding','','[]','讒語能令骨肉離，姦情難測事堪悲。',32,'御定全唐詩/json/491.json','["讒語能令骨肉離，姦情難測事堪悲。", "何因掘得江充骨，搗作微塵祭望思。"]'),
('yuding-11','日南長至','獨孤鉉','唐','御定全唐诗','yuding','','[]','玉曆頒新律，凝陰發一陽。輪輝猶惜短，圭影此偏長。',72,'御定全唐詩/json/491.json','["玉曆頒新律，凝陰發一陽。輪輝猶惜短，圭影此偏長。", "晷度經南斗，流晶盡北堂。乍疑周戶耀，可愛逗林光。", "積雪銷微照，初萌動早芒。更升臺上望，雲物已昭彰。"]'),
('yuding-12','延平天慶觀','王初','唐','御定全唐诗','yuding','','[]','劍化江邊綠構新，層台不染玉梯塵。千章隱篆標龍簡，',40,'御定全唐詩/json/491.json','["劍化江邊綠構新，層台不染玉梯塵。千章隱篆標龍簡，", "盟經早晚聞仙語，學種三芝伴羽人。"]'),
('yuding-13','送葉秀才','王初','唐','御定全唐诗','yuding','','[]','快騎璁瓏刻玉羈，河梁返照上征衣。層冰春近蟠龍起，',40,'御定全唐詩/json/491.json','["快騎璁瓏刻玉羈，河梁返照上征衣。層冰春近蟠龍起，", "漢庭狗監深知己，有日前驅負弩歸。"]'),
('yuding-14','送王秀才謁池州吳都督','王初','唐','御定全唐诗','yuding','','[]','池陽去去躍雕鞍，十裏長亭百草幹。衣袂障風金鏤細，',40,'御定全唐詩/json/491.json','["池陽去去躍雕鞍，十裏長亭百草幹。衣袂障風金鏤細，", "南館星郎東道主，搖鞭休問路行難。"]'),
('yuding-15','青帝','王初','唐','御定全唐诗','yuding','','[]','青帝邀春隔歲還，月娥孀獨夜漫漫。韓憑舞羽身猶在，',40,'御定全唐詩/json/491.json','["青帝邀春隔歲還，月娥孀獨夜漫漫。韓憑舞羽身猶在，", "幾時幽恨飄然斷，共待天池一水幹。"]'),
('yuding-16','銀河','王初','唐','御定全唐诗','yuding','','[]','閶闔疏雲漏絳津，橋頭秋夜鵲飛頻。猶殘仙媛湔裙水，',40,'御定全唐詩/json/491.json','["閶闔疏雲漏絳津，橋頭秋夜鵲飛頻。猶殘仙媛湔裙水，", "年來若有乘槎客，為吊波靈是楚臣。"]'),
('yuding-17','書秋','王初','唐','御定全唐诗','yuding','','[]','千里南雲度塞鴻，秋容無跡淡平空。人間玉嶺清宵月，',40,'御定全唐詩/json/491.json','["千里南雲度塞鴻，秋容無跡淡平空。人間玉嶺清宵月，", "往來未若奇張翰，欲鱠霜鯨碧海東。"]'),
('yuding-18','自和書秋','王初','唐','御定全唐诗','yuding','','[]','隴首斜飛避弋鴻，頹雲蕭索見層空。漢宮夜結雙莖露，',40,'御定全唐詩/json/491.json','["隴首斜飛避弋鴻，頹雲蕭索見層空。漢宮夜結雙莖露，", "江邊兩槳連歌渡，驚散游魚蓮葉東。"]'),
('yuding-19','立春後作','王初','唐','御定全唐诗','yuding','','[]','東君珂佩響珊珊，青馭多時下九關。',32,'御定全唐詩/json/491.json','["東君珂佩響珊珊，青馭多時下九關。", "方信玉霄千萬里，春風猶未到人間。"]'),
('yuding-20','梅花二首','王初','唐','御定全唐诗','yuding','','[]','應為陽春信未傳，固將青豔屬殘年。',64,'御定全唐詩/json/491.json','["應為陽春信未傳，固將青豔屬殘年。", "東君欲待尋佳約，剩寄衣香與粉綿。", "迎春雪豔飄零極，度夕蟾華掩映多。", "欲托清香傳遠信，一枝無計奈愁何。"]'),
('yuding-21','春日詠梅花二首','王初','唐','御定全唐诗','yuding','','[]','靚妝才罷粉痕新，遞曉風回散玉塵。',64,'御定全唐詩/json/491.json','["靚妝才罷粉痕新，遞曉風回散玉塵。", "若遣有情應悵望，已兼殘雪又兼春。", "青帝來時值遠芳，殘花殘雪尚交光。", "來年擬待春消息，得見春風已斷腸。"]'),
('yuding-22','即夕','王初','唐','御定全唐诗','yuding','','[]','榆葉飄零碧漢流，玉蟾珠露兩清秋。',32,'御定全唐詩/json/491.json','["榆葉飄零碧漢流，玉蟾珠露兩清秋。", "仙家若有單棲恨，莫向銀台半夜遊。"]'),
('yuding-23','送陳校勘入宿','王初','唐','御定全唐诗','yuding','','[]','日落風回卷碧霓，芳蓬一夜拆龍泥。',32,'御定全唐詩/json/491.json','["日落風回卷碧霓，芳蓬一夜拆龍泥。", "銀台級級連清漢，桂子香濃月杵低。"]'),
('yuding-24','即夕','王初','唐','御定全唐诗','yuding','','[]','風幌涼生白袷衣，星榆才亂絳河低。',32,'御定全唐詩/json/491.json','["風幌涼生白袷衣，星榆才亂絳河低。", "月明休近相思樹，恐有韓憑一處棲。"]'),
('yuding-25','早春詠雪','王初','唐','御定全唐诗','yuding','','[]','句芒宮樹已先開，珠蕊瓊花鬥剪裁。',32,'御定全唐詩/json/491.json','["句芒宮樹已先開，珠蕊瓊花鬥剪裁。", "散作上林今夜雪，送教春色一時來。"]'),
('yuding-26','望雪','王初','唐','御定全唐诗','yuding','','[]','銀花珠樹曉來看，宿醉初醒一倍寒。',32,'御定全唐詩/json/491.json','["銀花珠樹曉來看，宿醉初醒一倍寒。", "已似王恭披鶴氅，憑欄仍是玉欄幹。"]'),
('yuding-27','雪霽','王初','唐','御定全唐诗','yuding','','[]','星榆葉葉晝離披，雲粉千重凝不飛。',32,'御定全唐詩/json/491.json','["星榆葉葉晝離披，雲粉千重凝不飛。", "昆玉樓臺珠樹密，夜來誰向月中歸。"]'),
('yuding-28','舟次汴堤','王初','唐','御定全唐诗','yuding','','[]','曲岸蘭叢雁飛起，野客維舟碧煙裏。',32,'御定全唐詩/json/491.json','["曲岸蘭叢雁飛起，野客維舟碧煙裏。", "竿頭五兩轉天風，白日楊花滿流水。"]'),
('yuding-29','玉聲如樂','劉軻','唐','御定全唐诗','yuding','','[]','玉叩能旋止，人言與樂並。繁音忽已闋，雅韻詘然清。',72,'御定全唐詩/json/491.json','["玉叩能旋止，人言與樂並。繁音忽已闋，雅韻詘然清。", "佩想停仙步，泉疑咽夜聲。曲終無異聽，響極有餘情。", "特達知難擬，玲瓏豈易名。昆山如可得，一片佇為榮。"]'),
('yuding-30','喜陳懿老示新制','朱晝','唐','御定全唐诗','yuding','','[]','一別一千日，一日十二憶。苦心無閒時，今夕見玉色。',84,'御定全唐詩/json/491.json','["一別一千日，一日十二憶。苦心無閒時，今夕見玉色。", "玉色複何異，弘明含群德。有文如星宿，飛入我胸臆。", "憂愁方破壞，歡喜重補塞。使我心貌全，且非黃金力。", "將攀下風手，願假仙鸞翼。"]'),
('yuding-31','贈友人古鏡','朱晝','唐','御定全唐诗','yuding','','[]','我有古時鏡，初自壞陵得。蛟龍猶泥蟠，魑魅幸月蝕。',48,'御定全唐詩/json/491.json','["我有古時鏡，初自壞陵得。蛟龍猶泥蟠，魑魅幸月蝕。", "摩久見菱蕊，青于藍水色。贈君將照色，無使心受惑。"]'),
('yuding-32','賦得花藤藥合寄潁陰故人','朱晝','唐','御定全唐诗','yuding','','[]','藤生南海濱，引蔓青且長。剪削為花枝，何人無文章。',72,'御定全唐詩/json/491.json','["藤生南海濱，引蔓青且長。剪削為花枝，何人無文章。", "非才亦有心，割骨聞餘芳。繁葉落何處，孤貞在中央。", "願盛黃金膏，寄與青眼郎。路遠莫知意，水深天蒼蒼。"]'),
('yuding-33','春色滿皇州','滕邁','唐','御定全唐诗','yuding','','[]','藹藹複悠悠，春歸十二樓。最明雲裏闕，先滿日邊州。',72,'御定全唐詩/json/491.json','["藹藹複悠悠，春歸十二樓。最明雲裏闕，先滿日邊州。", "色媚青門外，光搖紫陌頭。上林榮舊樹，太液鏡新流。", "暖帶祥煙起，清添瑞景浮。陽和如啟蟄，從此事芳遊。"]'),
('yuding-34','楊柳枝詞','滕邁','唐','御定全唐诗','yuding','','[]','三條陌上拂金羈，萬里橋邊映酒旗。',32,'御定全唐詩/json/491.json','["三條陌上拂金羈，萬里橋邊映酒旗。", "此日令人腸欲斷，不堪將入笛中吹。"]'),
('yuding-35','句','滕邁','唐','御定全唐诗','yuding','','[]','陶令門前罥接z5，亞夫營裏拂朱旗。（《柳》，',22,'御定全唐詩/json/491.json','["陶令門前罥接z5，亞夫營裏拂朱旗。（《柳》，"]'),
('yuding-36','留別吉州太守宗人邁','滕倪','唐','御定全唐诗','yuding','','[]','秋初江上別旌旗，故國無家淚欲垂。千里未知投足處，',40,'御定全唐詩/json/491.json','["秋初江上別旌旗，故國無家淚欲垂。千里未知投足處，", "羽翼凋零飛不得，丹霄無路接差池。"]'),
('yuding-37','句','滕倪','唐','御定全唐诗','yuding','','[]','映水有深意，見人無懼心。（《題鷺鷥障子》。',48,'御定全唐詩/json/491.json','["映水有深意，見人無懼心。（《題鷺鷥障子》。", "以下並見《雲溪友議》）", "白髮不能容相國，也同閑客滿頭生。"]'),
('yuding-0','吳宮','殷堯藩','唐','御定全唐诗','yuding','','[]','吳王愛歌舞，夜夜醉嬋娟。見日吹紅燭，和塵掃翠鈿。',48,'御定全唐詩/json/492.json','["吳王愛歌舞，夜夜醉嬋娟。見日吹紅燭，和塵掃翠鈿。", "徒令勾踐霸，不信子胥賢。莫問長洲草，荒涼無限年。"]'),
('yuding-1','久雨','殷堯藩','唐','御定全唐诗','yuding','','[]','雲影蔽遙空，無端淡複濃。兩旬綿密雨，二月似深冬。',48,'御定全唐詩/json/492.json','["雲影蔽遙空，無端淡複濃。兩旬綿密雨，二月似深冬。", "詩酒從教數，簾幃一任重。孰知春有地，微露小桃紅。"]'),
('yuding-2','郊行逢社日','殷堯藩','唐','御定全唐诗','yuding','','[]','酒熟送迎便，村村慶有年。妻孥親稼穡，老稚效漁畋。',48,'御定全唐詩/json/492.json','["酒熟送迎便，村村慶有年。妻孥親稼穡，老稚效漁畋。", "紅樹青林外，黃蘆白鳥邊。稔看風景美，寧不羨歸田。"]'),
('yuding-3','過友人幽居','殷堯藩','唐','御定全唐诗','yuding','','[]','身坐眾香國，蒲團詩思新。一貧曾累我，此興未輸人。',48,'御定全唐詩/json/492.json','["身坐眾香國，蒲團詩思新。一貧曾累我，此興未輸人。", "陋巷誰為俗，寒窗不染塵。石齋盟四友，年下頓生春。"]'),
('yuding-4','過雍陶博士邸中飲','殷堯藩','唐','御定全唐诗','yuding','','[]','落葉下蕭蕭，幽居遠市朝。偶成投轄飲，不待致書招。',48,'御定全唐詩/json/492.json','["落葉下蕭蕭，幽居遠市朝。偶成投轄飲，不待致書招。", "塞雁沖寒過，山雲傍檻飄。此身何所似，天地一漁樵。"]'),
('yuding-5','游王羽士山房','殷堯藩','唐','御定全唐诗','yuding','','[]','落日半樓明，琳宮事事清。山橫萬古色，鶴帶九皋聲。',48,'御定全唐詩/json/492.json','["落日半樓明，琳宮事事清。山橫萬古色，鶴帶九皋聲。", "易作神仙侶，難忘父子情。道人應識我，未肯說長生。"]'),
('yuding-6','署中答武功姚合','殷堯藩','唐','御定全唐诗','yuding','','[]','原中多陰雨，惟留一室明。自宜居靜者，誰得問先生。',48,'御定全唐詩/json/492.json','["原中多陰雨，惟留一室明。自宜居靜者，誰得問先生。", "深井泉香出，危沙藥更榮。全家笑無辱，曾不見戈兵。"]'),
('yuding-7','贈龍陽尉馬戴','殷堯藩','唐','御定全唐诗','yuding','','[]','早學全身術，惟令耕近田。自輸官稅後，常臥晚雲邊。',48,'御定全唐詩/json/492.json','["早學全身術，惟令耕近田。自輸官稅後，常臥晚雲邊。", "細草沿階長，高蘿出石懸。向來名姓茂，空被外情牽。"]'),
('yuding-8','上巳日贈都上人','殷堯藩','唐','御定全唐诗','yuding','','[]','三月初三日，千家與萬家。蝶飛秦地草，鶯入漢宮花。',96,'御定全唐詩/json/492.json','["三月初三日，千家與萬家。蝶飛秦地草，鶯入漢宮花。", "鞍馬皆爭麗，笙歌盡鬥奢。吾師無所願，惟願老煙霞。", "曲水公卿宴，香塵盡滿街。無心修禊事，獨步到禪齋。", "細草縈愁目，繁花逆旅懷。綺羅人走馬，遺落鳳凰釵。"]'),
('yuding-9','送沈亞之尉南康','殷堯藩','唐','御定全唐诗','yuding','','[]','行邁南康路，客心離怨多。暮煙葵葉屋，秋月竹枝歌。',48,'御定全唐詩/json/492.json','["行邁南康路，客心離怨多。暮煙葵葉屋，秋月竹枝歌。", "孤鶴唳殘夢，驚猿嘯薜蘿。對江翹首望，愁淚疊如波。"]'),
('yuding-10','奉送劉使君王屋山隱居','殷堯藩','唐','御定全唐诗','yuding','','[]','散發風簷下，沉沉日漸曛。鷹拳擒野雀，蛛網獵飛蚊。',48,'御定全唐詩/json/492.json','["散發風簷下，沉沉日漸曛。鷹拳擒野雀，蛛網獵飛蚊。", "群動能歸計，吾生亦謾勤。塵緣難著眼，晚興寄青雲。"]'),
('yuding-11','寄許渾秀才','殷堯藩','唐','御定全唐诗','yuding','','[]','文字饑難煮，為農策最良。興來鉏曉月，倦後臥斜陽。',48,'御定全唐詩/json/492.json','["文字饑難煮，為農策最良。興來鉏曉月，倦後臥斜陽。", "秋稼連千頃，春花醉幾場。任他名利客，車馬鬧康莊。"]'),
('yuding-12','送客游吳','殷堯藩','唐','御定全唐诗','yuding','','[]','吳國水中央，波濤白渺茫。衣逢梅雨漬，船入稻花香。',48,'御定全唐詩/json/492.json','["吳國水中央，波濤白渺茫。衣逢梅雨漬，船入稻花香。", "海戍通鹽灶，山村帶蜜房。欲知蘇小小，君試到錢塘。"]'),
('yuding-13','陸丞相故宅','殷堯藩','唐','御定全唐诗','yuding','','[]','衣冠零落久，今日事堪傷。廚起青煙薄，門開白日長。',48,'御定全唐詩/json/492.json','["衣冠零落久，今日事堪傷。廚起青煙薄，門開白日長。", "殘梅欹古道，名石臥頹牆。山色依然好，興衰未可量。"]'),
('yuding-14','中元日觀諸道士步虛','殷堯藩','唐','御定全唐诗','yuding','','[]','玄都開秘籙，白石禮先生。上界秋光淨，中元夜氣清。',72,'御定全唐詩/json/492.json','["玄都開秘籙，白石禮先生。上界秋光淨，中元夜氣清。", "星辰朝帝處，鸞鶴步虛聲。玉洞花長髮，珠宮月最明。", "掃壇天地肅，投簡鬼神驚。倘賜刀圭藥，還留不死名。"]'),
('yuding-15','醉贈劉十二','殷堯藩','唐','御定全唐诗','yuding','','[]','春草正淒淒，知君過惡溪。鶯將吉了語，猿共猓然啼。',72,'御定全唐詩/json/492.json','["春草正淒淒，知君過惡溪。鶯將吉了語，猿共猓然啼。", "別路魂先斷，還家夢幾迷。定尋雷令劍，應識越王笄。", "樹色多於北，潮聲少向西。椰花好為酒，誰伴醉如泥。"]'),
('yuding-16','早朝','殷堯藩','唐','御定全唐诗','yuding','','[]','曙鐘催入紫宸朝，列炬流虹映絳綃。天近鼇頭花簇仗，',40,'御定全唐詩/json/492.json','["曙鐘催入紫宸朝，列炬流虹映絳綃。天近鼇頭花簇仗，", "昨日鐘山甘露降，玻璃滿賜出宮瓢。"]'),
('yuding-17','帝京二首','殷堯藩','唐','御定全唐诗','yuding','','[]','列郡征才起俊髦，萬機獨使聖躬勞。開藩上相頒龍節，',80,'御定全唐詩/json/492.json','["列郡征才起俊髦，萬機獨使聖躬勞。開藩上相頒龍節，", "迎春別賜瑤池宴，捧進金盤五色桃。", "龍虎山河禦氣通，遙瞻帝闕五雲紅。英雄盡入江東籍，", "都將儉德熙文治，淳俗應還太古風。"]'),
('yuding-18','宮詞','殷堯藩','唐','御定全唐诗','yuding','','[]','悄悄深宮不見人，倚闌惟見石麒麟。芙蓉帳冷愁長夜，',40,'御定全唐詩/json/492.json','["悄悄深宮不見人，倚闌惟見石麒麟。芙蓉帳冷愁長夜，", "夜深怕有羊車過，自起籠燈看雪紋。"]'),
('yuding-19','郊居作','殷堯藩','唐','御定全唐诗','yuding','','[]','碧樹濃陰護短垣，蒼江春暖渚鳧喧。買魚試喚鳴榔艇，',40,'御定全唐詩/json/492.json','["碧樹濃陰護短垣，蒼江春暖渚鳧喧。買魚試喚鳴榔艇，", "相逢謂我迂疏甚，欲辨還憎恐失言。"]'),
('yuding-20','閒居','殷堯藩','唐','御定全唐诗','yuding','','[]','茂苑閒居木石同，旋開小徑翦蒿蓬。虛游心在鴻蒙外，',40,'御定全唐詩/json/492.json','["茂苑閒居木石同，旋開小徑翦蒿蓬。虛游心在鴻蒙外，", "百年寄傲聊容膝，何必高車駟馬通。"]'),
('yuding-21','暮春述懷','殷堯藩','唐','御定全唐诗','yuding','','[]','為客山南二十年，愁來怳近落花天。陰雲帶雨連山脊，',40,'御定全唐詩/json/492.json','["為客山南二十年，愁來怳近落花天。陰雲帶雨連山脊，", "此時若遇孫陽顧，肯服鹽車不受鞭。"]'),
('yuding-22','端午日','殷堯藩','唐','御定全唐诗','yuding','','[]','少年佳節倍多情，老去誰知感慨生。不效艾符趨習俗，',40,'御定全唐詩/json/492.json','["少年佳節倍多情，老去誰知感慨生。不效艾符趨習俗，", "千載賢愚同瞬息，幾人湮沒幾垂名。"]'),
('yuding-23','九日','殷堯藩','唐','御定全唐诗','yuding','','[]','萬里飄零十二秋，不堪今倚夕陽樓。壯懷空擲班超筆，',40,'御定全唐詩/json/492.json','["萬里飄零十二秋，不堪今倚夕陽樓。壯懷空擲班超筆，", "酣歌欲盡登高興，強把黃花插滿頭。"]'),
('yuding-24','九日病起','殷堯藩','唐','御定全唐诗','yuding','','[]','重陽開滿菊花金，病起支床惜賞心。紫蟹霜肥秋縱好，',40,'御定全唐詩/json/492.json','["重陽開滿菊花金，病起支床惜賞心。紫蟹霜肥秋縱好，", "沈醉又成來歲約，遣懷聊作記時吟。"]'),
('yuding-25','寒夜','殷堯藩','唐','御定全唐诗','yuding','','[]','雲冷江空歲暮時，竹陰梅影月參差。雞催夢枕司晨早，',40,'御定全唐詩/json/492.json','["雲冷江空歲暮時，竹陰梅影月參差。雞催夢枕司晨早，", "憑誰蕩滌窮殘候，入眼東風喜在期。"]'),
('yuding-26','喜雨','殷堯藩','唐','御定全唐诗','yuding','','[]','臨岐終日自裴回，幹我茅齋半畝苔。山上亂雲隨手變，',40,'御定全唐詩/json/492.json','["臨岐終日自裴回，幹我茅齋半畝苔。山上亂雲隨手變，", "千里稻花應秀色，酒樽風月醉亭台。"]'),
('yuding-27','春遊','殷堯藩','唐','御定全唐诗','yuding','','[]','明日城東看杏花，叮嚀童子蚤將車。路從丹鳳樓前過，',40,'御定全唐詩/json/492.json','["明日城東看杏花，叮嚀童子蚤將車。路從丹鳳樓前過，", "絕勝羊傅襄陽道，車騎西風擁鼓笳。"]'),
('yuding-28','夜酌溪樓','殷堯藩','唐','御定全唐诗','yuding','','[]','樓居溪上涼生早，坐對城頭起暮笳。打鼓泊船何處客，',40,'御定全唐詩/json/492.json','["樓居溪上涼生早，坐對城頭起暮笳。打鼓泊船何處客，", "得意引杯須痛飲，好懷那許負年華。"]'),
('yuding-29','旅行','殷堯藩','唐','御定全唐诗','yuding','','[]','煙樹寒林半有無，野人行李更蕭疏。堠長堠短逢官馬，',40,'御定全唐詩/json/492.json','["煙樹寒林半有無，野人行李更蕭疏。堠長堠短逢官馬，", "寂寥一點寒燈在，酒熟鄰家許夜沽。"]'),
('yuding-30','下第東歸作','殷堯藩','唐','御定全唐诗','yuding','','[]','十載驅馳倦荷鋤，三年生計鬢蕭疏。辛勤幾逐英雄後，',40,'御定全唐詩/json/492.json','["十載驅馳倦荷鋤，三年生計鬢蕭疏。辛勤幾逐英雄後，", "身賤自慚貧骨相，朗嘯東歸學釣魚。"]'),
('yuding-31','還京口','殷堯藩','唐','御定全唐诗','yuding','','[]','黃鶴山頭雪未消，行人歸計在今朝。城高鐵甕江山壯，',40,'御定全唐詩/json/492.json','["黃鶴山頭雪未消，行人歸計在今朝。城高鐵甕江山壯，", "吏民莫見參軍面，水宿風餐鬢髮焦。"]'),
('yuding-32','襄口阻風','殷堯藩','唐','御定全唐诗','yuding','','[]','雪浪排空接海門，孤舟三日阻龍津。曹瞞曾墮周郎計，',40,'御定全唐詩/json/492.json','["雪浪排空接海門，孤舟三日阻龍津。曹瞞曾墮周郎計，", "篙師整纜候明發，仍謁荒祠問鬼神。"]'),
('yuding-33','潭州獨步','殷堯藩','唐','御定全唐诗','yuding','','[]','鶴發垂肩懶著巾，晚涼獨步楚江濱。一帆暝色鷗邊雨，',40,'御定全唐詩/json/492.json','["鶴發垂肩懶著巾，晚涼獨步楚江濱。一帆暝色鷗邊雨，", "笑看斥鷃飛翔去，樂處蓬萊便有春。"]'),
('yuding-34','金陵懷古','殷堯藩','唐','御定全唐诗','yuding','','[]','黃道天清擁佩珂，東南王氣秣陵多。江吞彭蠡來三蜀，',40,'御定全唐詩/json/492.json','["黃道天清擁佩珂，東南王氣秣陵多。江吞彭蠡來三蜀，", "華夷混一歸真主，端拱無為樂太和。"]'),
('yuding-35','登鳳凰台二首','殷堯藩','唐','御定全唐诗','yuding','','[]','鳳凰臺上望長安，五色宮袍照水寒。彩筆十年留翰墨，',80,'御定全唐詩/json/492.json','["鳳凰臺上望長安，五色宮袍照水寒。彩筆十年留翰墨，", "始信人生如一夢，壯懷莫使酒杯幹。", "梧桐葉落秋風老，人去台空鳳不來。梁武台城芳草合，", "莫問人間興廢事，百年相遇且銜杯。"]'),
('yuding-36','韓信廟','殷堯藩','唐','御定全唐诗','yuding','','[]','長空鳥盡將軍死，無複中原入馬蹄。身向九泉還屬漢，',40,'御定全唐詩/json/492.json','["長空鳥盡將軍死，無複中原入馬蹄。身向九泉還屬漢，", "此日深憐蕭相國，竟無一語到金閨。"]'),
('yuding-37','訪許渾','殷堯藩','唐','御定全唐诗','yuding','','[]','去郭來尋隱者居，柳陰假步小籃輿。每期會面初償約，',40,'御定全唐詩/json/492.json','["去郭來尋隱者居，柳陰假步小籃輿。每期會面初償約，", "為言肯共留連飲，澗有青芹罟有魚。"]'),
('yuding-38','李舍人席上感遇','殷堯藩','唐','御定全唐诗','yuding','','[]','微雲斂雨天氣清，松聲出樹秋泠泠。窗戶長含碧蘿色，',40,'御定全唐詩/json/492.json','["微雲斂雨天氣清，松聲出樹秋泠泠。窗戶長含碧蘿色，", "飄然曳杖出門去，無數好山江上橫。"]'),
('yuding-39','和趙相公登鸛雀樓','殷堯藩','唐','御定全唐诗','yuding','','[]','危樓高架泬寥天，上相閑登立彩旃。樹色到京三百里，',40,'御定全唐詩/json/492.json','["危樓高架泬寥天，上相閑登立彩旃。樹色到京三百里，", "雲路何人見高志，最看西面赤闌前。"]'),
('yuding-40','冬至酬劉使君','殷堯藩','唐','御定全唐诗','yuding','','[]','異鄉冬至又今朝，回首家山入夢遙。漸喜一陽從地複，',40,'御定全唐詩/json/492.json','["異鄉冬至又今朝，回首家山入夢遙。漸喜一陽從地複，", "多少故人承宴賞，五雲堆裏聽簫韶。"]'),
('yuding-41','李節度平虜詩','殷堯藩','唐','御定全唐诗','yuding','','[]','百萬王師下日邊，將軍雄略可圖全。元勳未論封茅異，',40,'御定全唐詩/json/492.json','["百萬王師下日邊，將軍雄略可圖全。元勳未論封茅異，", "太平從此銷兵甲，記取紅羊換劫年。"]'),
('yuding-42','金陵上李公垂侍郎','殷堯藩','唐','御定全唐诗','yuding','','[]','海國微茫散曉暾，鬱蔥佳氣滿乾坤。六朝空據長江險，',40,'御定全唐詩/json/492.json','["海國微茫散曉暾，鬱蔥佳氣滿乾坤。六朝空據長江險，", "願從吾道禧文運，再使河清俗化淳。"]'),
('yuding-43','贈惟儼師','殷堯藩','唐','御定全唐诗','yuding','','[]','煥然文采照青春，一策江湖自在身。雲鎖木龕聊息影，',40,'御定全唐詩/json/492.json','["煥然文采照青春，一策江湖自在身。雲鎖木龕聊息影，", "擬掃綠陰浮佛寺，桫欏高樹結為鄰。"]'),
('yuding-44','寄許渾秀才','殷堯藩','唐','御定全唐诗','yuding','','[]','萬木驚秋葉漸稀，靜探造化見玄機。眼前誰悟先天理，',40,'御定全唐詩/json/492.json','["萬木驚秋葉漸稀，靜探造化見玄機。眼前誰悟先天理，", "漢廷累下征賢詔，未許嚴陵老釣磯。"]'),
('yuding-45','送白舍人渡江','殷堯藩','唐','御定全唐诗','yuding','','[]','曉發龍江第一程，諸公同濟似登瀛。海門日上千峰出，',40,'御定全唐詩/json/492.json','["曉發龍江第一程，諸公同濟似登瀛。海門日上千峰出，", "片時喜得東風便，回首鐘聲隔鳳城。"]'),
('yuding-46','送劉禹錫侍禦出刺連州','殷堯藩','唐','御定全唐诗','yuding','','[]','遐荒迢遞五羊城，歸興濃消客裏情。家近似忘山路險，',40,'御定全唐詩/json/492.json','["遐荒迢遞五羊城，歸興濃消客裏情。家近似忘山路險，", "此去定知償隱趣，石田春雨讀書耕。"]'),
('yuding-47','送韋侍禦報使西蕃','殷堯藩','唐','御定全唐诗','yuding','','[]','歸奏聖朝行萬里，卻銜天詔報蕃臣。本是諸生守文墨，',40,'御定全唐詩/json/492.json','["歸奏聖朝行萬里，卻銜天詔報蕃臣。本是諸生守文墨，", "此去多應收故地，甯辭沙塞往來頻。"]'),
('yuding-48','寒食城南即事因訪藍田韋明府','殷堯藩','唐','御定全唐诗','yuding','','[]','閑出城南禁火天，路傍騎馬獨搖鞭。青松古墓傷碑碣，',40,'御定全唐詩/json/492.json','["閑出城南禁火天，路傍騎馬獨搖鞭。青松古墓傷碑碣，", "世間儘是悠悠事，且飲韋家冷酒眠。"]'),
('yuding-49','送源中丞使新羅','殷堯藩','唐','御定全唐诗','yuding','','[]','赤墀奉命使殊方，官重霜台紫綬光。玉節在船清海怪，',40,'御定全唐詩/json/492.json','["赤墀奉命使殊方，官重霜台紫綬光。玉節在船清海怪，", "誰得似君將雨露，海東萬里灑扶桑。"]'),
('yuding-50','送景玄上人還山','殷堯藩','唐','御定全唐诗','yuding','','[]','嵩陽聽罷講經鐘，遠訪庭闈錫度空。蒲履謾從歸後織，',40,'御定全唐詩/json/492.json','["嵩陽聽罷講經鐘，遠訪庭闈錫度空。蒲履謾從歸後織，", "梵宇傳來金貝葉，花前拜捧慰親容。"]'),
('yuding-51','宮人入道','殷堯藩','唐','御定全唐诗','yuding','','[]','卸卻宮妝錦繡衣，黃冠素服制相宜。錫名近奉君王旨，',40,'御定全唐詩/json/492.json','["卸卻宮妝錦繡衣，黃冠素服制相宜。錫名近奉君王旨，", "綠鬟女伴含愁別，釋盡當年妒寵私。"]'),
('yuding-52','友人山中梅花','殷堯藩','唐','御定全唐诗','yuding','','[]','南國看花動遠情，沈郎詩苦瘦容生。鐵心自儗山中賦，',40,'御定全唐詩/json/492.json','["南國看花動遠情，沈郎詩苦瘦容生。鐵心自儗山中賦，", "好風吹醒羅浮夢，莫聽空林翠羽聲。"]'),
('yuding-53','客中有感','殷堯藩','唐','御定全唐诗','yuding','','[]','天地一身在，頭顱五十過。流年消壯志，空使淚成河。',24,'御定全唐詩/json/492.json','["天地一身在，頭顱五十過。流年消壯志，空使淚成河。"]'),
('yuding-54','憶家二首','殷堯藩','唐','御定全唐诗','yuding','','[]','新霽颺林初，蘋花貼岸舒。故鄉今夜月，猶得照孤廬。',48,'御定全唐詩/json/492.json','["新霽颺林初，蘋花貼岸舒。故鄉今夜月，猶得照孤廬。", "樹擁溪邊閣，山浮雨後嵐。白頭歸未得，夢裏望江南。"]'),
('yuding-55','江行二首','殷堯藩','唐','御定全唐诗','yuding','','[]','暝色滄州迥，秋聲玉峽長。只因江上月，不覺過潯陽。',48,'御定全唐詩/json/492.json','["暝色滄州迥，秋聲玉峽長。只因江上月，不覺過潯陽。", "晚泊長江口，寒沙白似霜。年光流不盡，東去水聲長。"]'),
('yuding-56','偶題','殷堯藩','唐','御定全唐诗','yuding','','[]','越女收龍眼，蠻兒拾象牙。長安千萬里，走馬送誰家。',24,'御定全唐詩/json/492.json','["越女收龍眼，蠻兒拾象牙。長安千萬里，走馬送誰家。"]'),
('yuding-57','關中傷亂後','殷堯藩','唐','御定全唐诗','yuding','','[]','去歲干戈險，今年蝗旱憂。關西歸戰馬，海內賣耕牛。',24,'御定全唐詩/json/492.json','["去歲干戈險，今年蝗旱憂。關西歸戰馬，海內賣耕牛。"]'),
('yuding-58','楚江懷古','殷堯藩','唐','御定全唐诗','yuding','','[]','騷靈不可見，楚些竟誰聞。欲采蘋花去，滄州隔暮雲。',24,'御定全唐詩/json/492.json','["騷靈不可見，楚些竟誰聞。欲采蘋花去，滄州隔暮雲。"]'),
('yuding-59','張飛廟','殷堯藩','唐','御定全唐诗','yuding','','[]','威名垂萬古，勇力冠當時。回首三分國，何人賦黍離。',24,'御定全唐詩/json/492.json','["威名垂萬古，勇力冠當時。回首三分國，何人賦黍離。"]'),
('yuding-60','生公講臺','殷堯藩','唐','御定全唐诗','yuding','','[]','暝色護樓臺，陰雲晝未開。一塵無處著，花雨遍蒼苔。',24,'御定全唐詩/json/492.json','["暝色護樓臺，陰雲晝未開。一塵無處著，花雨遍蒼苔。"]'),
('yuding-61','席上聽琴','殷堯藩','唐','御定全唐诗','yuding','','[]','高堂流月明，萬籟不到耳。一聽清心魂，飛絮春紛起。',24,'御定全唐詩/json/492.json','["高堂流月明，萬籟不到耳。一聽清心魂，飛絮春紛起。"]'),
('yuding-62','酬雍秀才二首','殷堯藩','唐','御定全唐诗','yuding','','[]','晚市人煙合，歸帆帶夕陽。棲遲未歸客，猶著錦衣裳。',48,'御定全唐詩/json/492.json','["晚市人煙合，歸帆帶夕陽。棲遲未歸客，猶著錦衣裳。", "臥病茅窗下，驚聞兩月過。興來聊賦詠，清婉逼陰何。"]'),
('yuding-63','竹','殷堯藩','唐','御定全唐诗','yuding','','[]','窗戶盡蕭森，空階凝碧陰。不緣冰雪裏，為識歲寒心。',24,'御定全唐詩/json/492.json','["窗戶盡蕭森，空階凝碧陰。不緣冰雪裏，為識歲寒心。"]'),
('yuding-64','春怨','殷堯藩','唐','御定全唐诗','yuding','','[]','柳花撲簾春欲盡，綠陰障林鶯亂啼。',32,'御定全唐詩/json/492.json','["柳花撲簾春欲盡，綠陰障林鶯亂啼。", "只愁明日送春去，落日滿園啼竹雞。"]'),
('yuding-65','館娃宮','殷堯藩','唐','御定全唐诗','yuding','','[]','宮女三千去不回，真珠翠羽是塵埃。',32,'御定全唐詩/json/492.json','["宮女三千去不回，真珠翠羽是塵埃。", "夫差舊國久破碎，紅燕自歸花自開。"]'),
('yuding-66','漢宮詞三首','殷堯藩','唐','御定全唐诗','yuding','','[]','成帝夫人淚滿懷，璧宮相趁落空階。',96,'御定全唐詩/json/492.json','["成帝夫人淚滿懷，璧宮相趁落空階。", "可憐玉貌花前死，惟有君恩白燕釵。", "霍家有女字成君，年少教人著繡裙。", "枉殺宮中許皇后，椒房恩澤是浮雲。", "駿馬金鞍白玉鞭，宮中來取李延年。", "承恩直日鴛鴦殿，一曲清歌在九天。"]'),
('yuding-67','同州端午','殷堯藩','唐','御定全唐诗','yuding','','[]','鶴發垂肩尺許長，離家三十五端陽。',32,'御定全唐詩/json/492.json','["鶴發垂肩尺許長，離家三十五端陽。", "兒童見說深驚訝，卻問何方是故鄉。"]'),
('yuding-68','夜過洞庭','殷堯藩','唐','御定全唐诗','yuding','','[]','笙歌只解鬧花天，誰是敲冰掉小船。',32,'御定全唐詩/json/492.json','["笙歌只解鬧花天，誰是敲冰掉小船。", "為覓瀟湘幽隱處，夜深載月聽鳴泉。"]'),
('yuding-69','游山南寺二首','殷堯藩','唐','御定全唐诗','yuding','','[]','山中盡日無人到，竹外交加百鳥鳴。',64,'御定全唐詩/json/492.json','["山中盡日無人到，竹外交加百鳥鳴。", "昨日小樓微雨過，櫻桃花落晚風晴。", "踏碎羊山黃葉堆，天飛細雨隱輕雷。", "朗陵莫訝來何晚，不忍聽君話別杯。"]'),
('yuding-70','寄太僕田卿二首','殷堯藩','唐','御定全唐诗','yuding','','[]','客窗強飲太匆匆，急雨寒風意萬重。',64,'御定全唐詩/json/492.json','["客窗強飲太匆匆，急雨寒風意萬重。", "驀上心來消未得，夢回又聽五更鐘。", "一陽才動伏群陰，萬物於今寓太音。", "若喜長生添線日，微微消息識天心。"]'),
('yuding-71','新昌井','殷堯藩','唐','御定全唐诗','yuding','','[]','轆轤千轉勞筋力，待得甘泉渴殺人。',32,'御定全唐詩/json/492.json','["轆轤千轉勞筋力，待得甘泉渴殺人。", "且共山麋同飲澗，玉沙鋪底淺磷磷。"]'),
('yuding-72','經靖安裏','殷堯藩','唐','御定全唐诗','yuding','','[]','巷底蕭蕭絕市塵，供愁疏雨打黃昏。',32,'御定全唐詩/json/492.json','["巷底蕭蕭絕市塵，供愁疏雨打黃昏。", "悠然一曲泉明調，淺立閒愁輕閉門。"]'),
('yuding-73','聞箏歌','殷堯藩','唐','御定全唐诗','yuding','','[]','淒淒切切斷腸聲，指滑音柔萬種情。',32,'御定全唐詩/json/492.json','["淒淒切切斷腸聲，指滑音柔萬種情。", "花影深沈遮不住，度幃穿幕又殘更。"]'),
('yuding-74','吹笙歌','殷堯藩','唐','御定全唐诗','yuding','','[]','伶兒竹聲愁繞空，秦女淚濕燕支紅。',32,'御定全唐詩/json/492.json','["伶兒竹聲愁繞空，秦女淚濕燕支紅。", "玉桃花片落不住，三十六簧能喚風。"]'),
('yuding-75','贈歌人郭婉二首','殷堯藩','唐','御定全唐诗','yuding','','[]','石家金穀舊歌人，起唱花筵淚滿巾。',64,'御定全唐詩/json/492.json','["石家金穀舊歌人，起唱花筵淚滿巾。", "紅粉少年諸弟子，一時惆悵望梁塵。", "雲滿衣裳月滿身，輕盈歸步過流塵。", "五更無限留連意，常恐風花又一春。"]'),
('yuding-76','潭州席上贈舞柘枝妓','殷堯藩','唐','御定全唐诗','yuding','','[]','姑蘇太守青娥女，流落長沙舞柘枝。',32,'御定全唐詩/json/492.json','["姑蘇太守青娥女，流落長沙舞柘枝。", "坐滿繡衣皆不識，可憐紅臉淚雙垂。"]'),
('yuding-77','句','殷堯藩','唐','御定全唐诗','yuding','','[]','瘴雨出虹蝀，蠻煙渡江急。嘗聞島夷俗，犀象滿城邑。',25,'御定全唐詩/json/492.json','["瘴雨出虹蝀，蠻煙渡江急。嘗聞島夷俗，犀象滿城邑。", "。"]'),
('yuding-0','虎丘山真娘墓','沈亞之','唐','御定全唐诗','yuding','','[]','金釵淪劍壑，茲地似花台。油壁何人值，錢塘度曲哀。',48,'御定全唐詩/json/493.json','["金釵淪劍壑，茲地似花台。油壁何人值，錢塘度曲哀。", "翠餘長染柳，香重欲熏梅。但道行雲去，應隨魂夢來。"]'),
('yuding-1','答殷堯藩贈罷涇源記室','沈亞之','唐','御定全唐诗','yuding','','[]','勞君輟雅話，聽說事疆場。提筆從征虜，飛書始伏羌。',48,'御定全唐詩/json/493.json','["勞君輟雅話，聽說事疆場。提筆從征虜，飛書始伏羌。", "河流辭馬嶺，節臥聽龍驤。孤負平生劍，空憐射鬥光。"]'),
('yuding-2','五月六日，發石頭城，步望前船，示舍弟兼寄侯郎','沈亞之','唐','御定全唐诗','yuding','','[]','客子去淮陽，逶迤別夢長。水關開夜鎖，霧棹起晨涼。',72,'御定全唐詩/json/493.json','["客子去淮陽，逶迤別夢長。水關開夜鎖，霧棹起晨涼。", "煙月期同賞，風波勿異行。隱山曾撼櫓，轉瀨指遙檣。", "蒲葉吳刀綠，筠筒楚粽香。因書報惠遠，為我憶檀郎。"]'),
('yuding-3','別龐子肅','沈亞之','唐','御定全唐诗','yuding','','[]','自為應仙才，丹砂煉幾回。山秋夢桂樹，月曉憶瑤台。',48,'御定全唐詩/json/493.json','["自為應仙才，丹砂煉幾回。山秋夢桂樹，月曉憶瑤台。", "雨雪依岩避，煙雲逐步開。今朝龍仗去，早晚鶴書來。"]'),
('yuding-4','春色滿皇州','沈亞之','唐','御定全唐诗','yuding','','[]','何處春輝好，偏宜在雍州。花明夾城道，柳暗曲江頭。',72,'御定全唐詩/json/493.json','["何處春輝好，偏宜在雍州。花明夾城道，柳暗曲江頭。", "風軟遊絲重，光融瑞氣浮。鬥雞憐短草，乳燕傍高樓。", "繡轂盈香陌，新泉溢禦溝。回看日欲暮，還騎似川流。"]'),
('yuding-5','宿白馬津寄寇立','沈亞之','唐','御定全唐诗','yuding','','[]','客思聽蛩嗟，秋懷似亂砂。劍頭懸日影，蠅鼻落燈花。',48,'御定全唐詩/json/493.json','["客思聽蛩嗟，秋懷似亂砂。劍頭懸日影，蠅鼻落燈花。", "天外歸鴻斷，漳南別路賒。聞君同旅舍，幾得夢還家。"]'),
('yuding-6','汴州船行賦岸傍所見','沈亞之','唐','御定全唐诗','yuding','','[]','古木曉蒼蒼，秋林拂岸香。露珠蟲網細，金縷兔絲長。',72,'御定全唐詩/json/493.json','["古木曉蒼蒼，秋林拂岸香。露珠蟲網細，金縷兔絲長。", "秋浪時回沫，驚鱗乍觸航。蓬煙拈綠線，棘實綴紅囊。", "亂穗搖鼯尾，出根掛鳳腸。聊持一濯足，誰道比滄浪。"]'),
('yuding-7','送文穎上人游天臺','沈亞之','唐','御定全唐诗','yuding','','[]','露花浮翠瓦，鮮思起芳叢。此際斷客夢，況複別志公。',48,'御定全唐詩/json/493.json','["露花浮翠瓦，鮮思起芳叢。此際斷客夢，況複別志公。", "既曆天臺去，言過赤城東。莫說人間事，崎嶇塵土中。"]'),
('yuding-8','宿後自華陽行次昭應寄王直方','沈亞之','唐','御定全唐诗','yuding','','[]','重歸能幾日，物意早如春。暖色先驪岫，寒聲別雁群。',48,'御定全唐詩/json/493.json','["重歸能幾日，物意早如春。暖色先驪岫，寒聲別雁群。", "川光如戲劍，帆態似翔雲。為報東園蝶，南枝日已曛。"]'),
('yuding-9','題海榴樹呈八叔大人','沈亞之','唐','御定全唐诗','yuding','','[]','曾在蓬壺伴眾仙，文章枝葉五雲邊。幾時奉宴瑤台下，',40,'御定全唐詩/json/493.json','["曾在蓬壺伴眾仙，文章枝葉五雲邊。幾時奉宴瑤台下，", "應笑強如河畔柳，逢波逐浪送張騫。"]'),
('yuding-10','西蕃請謁廟','沈亞之','唐','御定全唐诗','yuding','','[]','肅肅層城裏，巍巍祖廟清。聖恩覃布濩，異域獻精誠。',96,'御定全唐詩/json/493.json','["肅肅層城裏，巍巍祖廟清。聖恩覃布濩，異域獻精誠。", "冠蓋分行列，戎夷辨姓名。禮終齊百拜，心潔表忠貞。", "瑞氣千重色，簫韶九奏聲。仗移迎日轉，旌動逐風輕。", "休運威儀正，年推俎豆盈。不才慚聖澤，空此望華纓。"]'),
('yuding-11','勸政樓下觀百官獻壽','沈亞之','唐','御定全唐诗','yuding','','[]','禦氣黃花節，臨軒紫陌頭。早陽生彩仗，霽色入仙樓。',72,'御定全唐詩/json/493.json','["禦氣黃花節，臨軒紫陌頭。早陽生彩仗，霽色入仙樓。", "獻壽皆鴛鷺，瞻天在冕旒。菊尊開九日，鳳曆啟千秋。", "樂闋祥煙起，杯酣瑞影收。年年歌舞夕，此地慶皇休。"]'),
('yuding-12','山出雲','沈亞之','唐','御定全唐诗','yuding','','[]','片雲朝出岫，孤色迥難親。蓋小辭山早，根輕觸石新。',72,'御定全唐詩/json/493.json','["片雲朝出岫，孤色迥難親。蓋小辭山早，根輕觸石新。", "飄揚經綠野，明麗照青春。拂樹疑舒葉，臨江似結鱗。", "從龍方有感，捧日豈無因。看助為霖去，恩沾雨露均。"]'),
('yuding-13','曲江亭望慈恩杏花發','沈亞之','唐','御定全唐诗','yuding','','[]','曲台晴好望，近接梵王家。十畝開金地，千株發杏花。',72,'御定全唐詩/json/493.json','["曲台晴好望，近接梵王家。十畝開金地，千株發杏花。", "帶雲猶誤雪，映日欲欺霞。紫陌傳香遠，紅泉落影斜。", "園中春尚早，亭上路非賒。芳景偏堪賞，其如積歲華。"]'),
('yuding-14','村居','沈亞之','唐','御定全唐诗','yuding','','[]','有樹巢宿鳥，無酒共客醉。月上蟬韻殘，梧桐陰繞地。',60,'御定全唐詩/json/493.json','["有樹巢宿鳥，無酒共客醉。月上蟬韻殘，梧桐陰繞地。", "獨出村舍門，吟劇微風起。蕭蕭蘆荻叢，叫嘯如山鬼。", "應緣我憔悴，為我哭秋思。"]'),
('yuding-15','春詞酬元微之','沈亞之','唐','御定全唐诗','yuding','','[]','黃鶯啼時春日高，紅芳發盡井邊桃。',32,'御定全唐詩/json/493.json','["黃鶯啼時春日高，紅芳發盡井邊桃。", "美人手暖裁衣易，片片輕花落翦刀。"]'),
('yuding-16','題侯仙亭','沈亞之','唐','御定全唐诗','yuding','','[]','新創仙亭覆石壇，雕梁峻宇入雲端。',32,'御定全唐詩/json/493.json','["新創仙亭覆石壇，雕梁峻宇入雲端。", "嶺北嘯猿高枕聽，湖南山色捲簾看。"]'),
('yuding-17','送龐子肅','沈亞之','唐','御定全唐诗','yuding','','[]','三年遊宦也迷津，馬困長安九陌塵。',32,'御定全唐詩/json/493.json','["三年遊宦也迷津，馬困長安九陌塵。", "都作無成不歸去，古來妻嫂笑蘇秦。"]'),
('yuding-18','夢挽秦弄玉','沈亞之','唐','御定全唐诗','yuding','','[]','泣葬一枝紅，生同死不同。金鈿墜芳草，香繡滿春風。',48,'御定全唐詩/json/493.json','["泣葬一枝紅，生同死不同。金鈿墜芳草，香繡滿春風。", "舊日聞簫處，高樓當月中。梨花寒食夜，深閉翠微宮。"]'),
('yuding-19','夢別秦穆公','沈亞之','唐','御定全唐诗','yuding','','[]','擊髆舞，恨滿煙光無處所。淚如雨，欲擬著辭不成語。',48,'御定全唐詩/json/493.json','["擊髆舞，恨滿煙光無處所。淚如雨，欲擬著辭不成語。", "金鳳銜紅舊繡衣，幾度宮中同看舞。人間春日正歡樂，"]'),
('yuding-20','夢游秦宮','沈亞之','唐','御定全唐诗','yuding','','[]','君王多感放東歸，從此秦宮不復期。',32,'御定全唐詩/json/493.json','["君王多感放東歸，從此秦宮不復期。", "春景似傷秦喪主，落花如雨淚胭脂。"]'),
('yuding-21','湘中怨','沈亞之','唐','御定全唐诗','yuding','','[]','隆佳秀兮昭盛時，播熏綠兮淑華歸。顧室荑與處萼兮，',96,'御定全唐詩/json/493.json','["隆佳秀兮昭盛時，播熏綠兮淑華歸。顧室荑與處萼兮，", "醉融光兮渺渺彌彌，迷千里兮涵煙眉，晨陶陶兮暮熙熙。", "舞婑那之穠條兮，騁盈盈以披遲。酡游顏兮倡蔓卉縠，", "溯青山兮江之隅，拖湘波兮嫋綠裾。荷拳拳兮未舒，"]'),
('yuding-22','文祝延二闋','沈亞之','唐','御定全唐诗','yuding','','[]','閩山之杭杭兮水堋堋，吞荒抱大兮香疊層。',190,'御定全唐詩/json/493.json','["閩山之杭杭兮水堋堋，吞荒抱大兮香疊層。", "騰氣清渾兮朝昏，神生其中兮宅幽凝。居如山兮惠如水，", "侯臨我兮恩如光，照導兮天覆。惠流吾兮樂且康，", "神有澤兮宜蔭沃，脫侯之恙兮歸侯之多福。", "群卑勤之恭潔兮，鑒貞盟乎山竹。。", "兕載吹兮音咿咿，銅鐃呶兮睋呼眓睢。樟之蓋兮麓下，", "肴盤列兮答神，神擺漁篁兮降拂窣窣。", "右持妓兮左夫人，態修邃兮佻眇。調丹含瓊兮瑳佳笑，", "朝馬駕兮搦寶轡，千弭函弦兮森道騎。吾何樂兮神軒，"]'),
('yuding-0','及第後過揚子江','施肩吾','唐','御定全唐诗','yuding','','[]','憶昔將貢年，抱愁此江邊。魚龍互閃爍，黑浪高於天。',48,'御定全唐詩/json/494.json','["憶昔將貢年，抱愁此江邊。魚龍互閃爍，黑浪高於天。", "今日步春草，複來經此道。江神也世情，為我風色好。"]'),
('yuding-1','夜宴曲','施肩吾','唐','御定全唐诗','yuding','','[]','蘭缸如晝曉不眠，玉堂夜起沈香煙。青娥一行十二仙，',40,'御定全唐詩/json/494.json','["蘭缸如晝曉不眠，玉堂夜起沈香煙。青娥一行十二仙，", "被郎嗔罰琉璃盞，酒入四肢紅玉軟。"]'),
('yuding-2','效古興','施肩吾','唐','御定全唐诗','yuding','','[]','金雀無舊釵，緗綺無舊裾。唯有一寸心，長貯萬里夫。',48,'御定全唐詩/json/494.json','["金雀無舊釵，緗綺無舊裾。唯有一寸心，長貯萬里夫。", "南軒夜蟲織已促，北牖飛蛾繞殘燭。只言眾口鑠千金，"]'),
('yuding-3','古別離二首','施肩吾','唐','御定全唐诗','yuding','','[]','古人謾歌西飛燕，十年不見狂夫面。三更風作切夢刀，',68,'御定全唐詩/json/494.json','["古人謾歌西飛燕，十年不見狂夫面。三更風作切夢刀，", "老母別愛子，少妻送征郎。血流既四面，乃一斷二腸。", "不愁寒無衣，不怕饑無糧。惟恐征戰不還鄉，"]'),
('yuding-4','壯士行','施肩吾','唐','御定全唐诗','yuding','','[]','一鬥之膽撐臟腑，如磥之筋礙臂骨。有時誤入千人叢，',40,'御定全唐詩/json/494.json','["一鬥之膽撐臟腑，如磥之筋礙臂骨。有時誤入千人叢，", "凍梟殘蠆我不取，汙我匣裏青蛇鱗。"]'),
('yuding-5','代征婦怨','施肩吾','唐','御定全唐诗','yuding','','[]','寒窗羞見影相隨，嫁得五陵輕薄兒。長短豔歌君自解，',40,'御定全唐詩/json/494.json','["寒窗羞見影相隨，嫁得五陵輕薄兒。長短豔歌君自解，", "何事不看霜雪裏，堅貞惟有古松枝。"]'),
('yuding-6','送人南游','施肩吾','唐','御定全唐诗','yuding','','[]','見說南行偏不易，中途莫忘寄書頻。淩空瘴氣墮飛鳥，',40,'御定全唐詩/json/494.json','["見說南行偏不易，中途莫忘寄書頻。淩空瘴氣墮飛鳥，", "異花奇竹分明看，待汝歸來畫取真。"]'),
('yuding-7','贈邊將','施肩吾','唐','御定全唐诗','yuding','','[]','輕生奉國不為難，戰苦身多舊箭瘢。玉匣鎖龍鱗甲冷，',40,'御定全唐詩/json/494.json','["輕生奉國不為難，戰苦身多舊箭瘢。玉匣鎖龍鱗甲冷，", "猶恐犬戎臨虜塞，柳營時把陣圖看。"]'),
('yuding-8','上禮部侍郎陳情','施肩吾','唐','御定全唐诗','yuding','','[]','九重城裏無親識，八百人中獨姓施。弱羽飛時攢箭險，',40,'御定全唐詩/json/494.json','["九重城裏無親識，八百人中獨姓施。弱羽飛時攢箭險，", "卻向從來受恩地，再求青律變寒枝。"]'),
('yuding-9','早春殘雪','施肩吾','唐','御定全唐诗','yuding','','[]','春景照林巒，玲瓏雪影殘。井泉添碧甃，藥圃洗朱欄。',72,'御定全唐詩/json/494.json','["春景照林巒，玲瓏雪影殘。井泉添碧甃，藥圃洗朱欄。", "雲路迷初醒，書堂映漸難。花分梅嶺色，塵減玉階寒。", "遠稱棲松鶴，高宜點露盤。佇逢春律後，陰穀始堪看。"]'),
('yuding-10','送端上人游天臺','施肩吾','唐','御定全唐诗','yuding','','[]','師今欲向天臺去，來說天臺意最真。溪過石橋為險處，',40,'御定全唐詩/json/494.json','["師今欲向天臺去，來說天臺意最真。溪過石橋為險處，", "只可且論經夏別，莫教琪樹兩回春。"]'),
('yuding-11','惜花','施肩吾','唐','御定全唐诗','yuding','','[]','落盡萬株紅，無人解系風。今朝芳徑裏，惆悵錦機空。',24,'御定全唐詩/json/494.json','["落盡萬株紅，無人解系風。今朝芳徑裏，惆悵錦機空。"]'),
('yuding-12','沖夜行','施肩吾','唐','御定全唐诗','yuding','','[]','夜行無月時，古路多荒榛。山鬼遙把火，自照不照人。',24,'御定全唐詩/json/494.json','["夜行無月時，古路多荒榛。山鬼遙把火，自照不照人。"]'),
('yuding-13','夜愁曲','施肩吾','唐','御定全唐诗','yuding','','[]','歌者歌未絕，愁人愁轉增。空把琅玕枝，強挑無心燈。',24,'御定全唐詩/json/494.json','["歌者歌未絕，愁人愁轉增。空把琅玕枝，強挑無心燈。"]'),
('yuding-14','雜古詞五首','施肩吾','唐','御定全唐诗','yuding','','[]','可憐江北女，慣唱江南曲。搖盪木蘭舟，雙鳧不成浴。',120,'御定全唐詩/json/494.json','["可憐江北女，慣唱江南曲。搖盪木蘭舟，雙鳧不成浴。", "郎為七上香，妾作籠下灰。歸時即暖熱，去罷生塵埃。", "夜裁鴛鴦綺，朝織蒲桃綾。欲試一寸心，待縫三尺冰。", "憐時魚得水，怨罷商與參。不如山梔子，卻能結同心。", "紅顏感暮花，白日同流水。思君若孤燈，一夜一心死。"]'),
('yuding-15','幼女詞','施肩吾','唐','御定全唐诗','yuding','','[]','幼女才六歲，未知巧與拙。向夜在堂前，學人拜新月。',24,'御定全唐詩/json/494.json','["幼女才六歲，未知巧與拙。向夜在堂前，學人拜新月。"]'),
('yuding-16','買地詞','施肩吾','唐','御定全唐诗','yuding','','[]','買地不惜錢，為多芳桂叢。所期在清涼，坐起聞香風。',24,'御定全唐詩/json/494.json','["買地不惜錢，為多芳桂叢。所期在清涼，坐起聞香風。"]'),
('yuding-17','弋陽訪古','施肩吾','唐','御定全唐诗','yuding','','[]','行逢葛溪水，不見葛仙人。空拋青竹杖，咒作葛陂神。',24,'御定全唐詩/json/494.json','["行逢葛溪水，不見葛仙人。空拋青竹杖，咒作葛陂神。"]'),
('yuding-18','幽居樂','施肩吾','唐','御定全唐诗','yuding','','[]','萬籟不在耳，寂寥心境清。無妨數莖竹，時有蕭蕭聲。',24,'御定全唐詩/json/494.json','["萬籟不在耳，寂寥心境清。無妨數莖竹，時有蕭蕭聲。"]'),
('yuding-19','湘川懷古','施肩吾','唐','御定全唐诗','yuding','','[]','湘水終日流，湘妃昔時哭。美色已成塵，淚痕猶在竹。',24,'御定全唐詩/json/494.json','["湘水終日流，湘妃昔時哭。美色已成塵，淚痕猶在竹。"]'),
('yuding-20','秋山吟','施肩吾','唐','御定全唐诗','yuding','','[]','夜吟秋山上，嫋嫋秋風歸。月色清且冷，桂香落人衣。',24,'御定全唐詩/json/494.json','["夜吟秋山上，嫋嫋秋風歸。月色清且冷，桂香落人衣。"]'),
('yuding-21','寒夜','施肩吾','唐','御定全唐诗','yuding','','[]','三複招隱吟，不知寒夜深。看看西來月，移到青天心。',24,'御定全唐詩/json/494.json','["三複招隱吟，不知寒夜深。看看西來月，移到青天心。"]'),
('yuding-22','湘竹詞','施肩吾','唐','御定全唐诗','yuding','','[]','萬古湘江竹，無窮奈怨何。年年長春筍，只是淚痕多。',24,'御定全唐詩/json/494.json','["萬古湘江竹，無窮奈怨何。年年長春筍，只是淚痕多。"]'),
('yuding-23','觀花後遊慈恩寺','施肩吾','唐','御定全唐诗','yuding','','[]','世事知難了，應須問苦空。羞將看花眼，來入梵王宮。',24,'御定全唐詩/json/494.json','["世事知難了，應須問苦空。羞將看花眼，來入梵王宮。"]'),
('yuding-24','乞巧詞','施肩吾','唐','御定全唐诗','yuding','','[]','乞巧望星河，雙雙並綺羅。不嫌針眼小，只道月明多。',24,'御定全唐詩/json/494.json','["乞巧望星河，雙雙並綺羅。不嫌針眼小，只道月明多。"]'),
('yuding-25','不見來詞','施肩吾','唐','御定全唐诗','yuding','','[]','烏鵲語千回，黃昏不見來。漫教脂粉匣，閉了又重開。',24,'御定全唐詩/json/494.json','["烏鵲語千回，黃昏不見來。漫教脂粉匣，閉了又重開。"]'),
('yuding-26','夜起來','施肩吾','唐','御定全唐诗','yuding','','[]','香銷連理帶，塵覆合歡杯。懶臥相思枕，愁吟夜起來。',24,'御定全唐詩/json/494.json','["香銷連理帶，塵覆合歡杯。懶臥相思枕，愁吟夜起來。"]'),
('yuding-27','笑卿卿詞','施肩吾','唐','御定全唐诗','yuding','','[]','笑向卿卿道，耽書夜夜多。出來看玉兔，又欲過銀河。',24,'御定全唐詩/json/494.json','["笑向卿卿道，耽書夜夜多。出來看玉兔，又欲過銀河。"]'),
('yuding-28','感遇詞','施肩吾','唐','御定全唐诗','yuding','','[]','一種貌如仙，人情要自偏。羅敷有底好，最得使君憐。',24,'御定全唐詩/json/494.json','["一種貌如仙，人情要自偏。羅敷有底好，最得使君憐。"]'),
('yuding-29','及第後夜訪月仙子','施肩吾','唐','御定全唐诗','yuding','','[]','自喜尋幽夜，新當及第年。還將天上桂，來訪月中仙。',24,'御定全唐詩/json/494.json','["自喜尋幽夜，新當及第年。還將天上桂，來訪月中仙。"]'),
('yuding-30','定情樂','施肩吾','唐','御定全唐诗','yuding','','[]','敢嗟君不憐，自是命不諧。著破三條裙，卻還雙股釵。',48,'御定全唐詩/json/494.json','["敢嗟君不憐，自是命不諧。著破三條裙，卻還雙股釵。", "感郎雙條脫，新破八幅綃。不惜榆莢錢，買人金步搖。"]'),
('yuding-31','宿南一上人山房','施肩吾','唐','御定全唐诗','yuding','','[]','窗牖月色多，坐臥禪心靜。青鬼來試人，夜深弄燈影。',24,'御定全唐詩/json/494.json','["窗牖月色多，坐臥禪心靜。青鬼來試人，夜深弄燈影。"]'),
('yuding-32','蘭渚泊','施肩吾','唐','御定全唐诗','yuding','','[]','家在洞水西，身作蘭渚客。天晝無纖雲，獨坐空江碧。',24,'御定全唐詩/json/494.json','["家在洞水西，身作蘭渚客。天晝無纖雲，獨坐空江碧。"]'),
('yuding-33','經吳真君舊宅','施肩吾','唐','御定全唐诗','yuding','','[]','古仙煉丹處，不測何歲年。至今空宅基，時有五色煙。',24,'御定全唐詩/json/494.json','["古仙煉丹處，不測何歲年。至今空宅基，時有五色煙。"]'),
('yuding-34','古相思','施肩吾','唐','御定全唐诗','yuding','','[]','十訪九不見，甚於菖蒲花。可憐雲中月，今夜墮我家。',24,'御定全唐詩/json/494.json','["十訪九不見，甚於菖蒲花。可憐雲中月，今夜墮我家。"]'),
('yuding-35','瀑布','施肩吾','唐','御定全唐诗','yuding','','[]','豁開青冥顛，寫出萬丈泉。如裁一條素，白日懸秋天。',24,'御定全唐詩/json/494.json','["豁開青冥顛，寫出萬丈泉。如裁一條素，白日懸秋天。"]'),
('yuding-36','金尺石','施肩吾','唐','御定全唐诗','yuding','','[]','丹砂畫頑石，黃金橫一尺。人世較短長，仙家愛平直。',24,'御定全唐詩/json/494.json','["丹砂畫頑石，黃金橫一尺。人世較短長，仙家愛平直。"]'),
('yuding-37','秋洞宿','施肩吾','唐','御定全唐诗','yuding','','[]','夜深秋洞裏，風雨報龍歸。何事觸人睡，不教蝴蝶飛。',24,'御定全唐詩/json/494.json','["夜深秋洞裏，風雨報龍歸。何事觸人睡，不教蝴蝶飛。"]'),
('yuding-38','效古詞','施肩吾','唐','御定全唐诗','yuding','','[]','姊妹無多兄弟少，舉家鍾愛年最小。',32,'御定全唐詩/json/494.json','["姊妹無多兄弟少，舉家鍾愛年最小。", "有時繞樹山鵲飛，貪看不待畫眉了。"]'),
('yuding-39','山中得劉秀才京書','施肩吾','唐','御定全唐诗','yuding','','[]','自笑家貧客到疏，滿庭煙草不能鋤。',32,'御定全唐詩/json/494.json','["自笑家貧客到疏，滿庭煙草不能鋤。", "今朝誰料三千里，忽得劉京一紙書。"]'),
('yuding-40','望夫詞','施肩吾','唐','御定全唐诗','yuding','','[]','手爇寒燈向影頻，回文機上暗生塵。',32,'御定全唐詩/json/494.json','["手爇寒燈向影頻，回文機上暗生塵。", "自家夫婿無消息，卻恨橋頭賣蔔人。"]'),
('yuding-41','憶四明山泉','施肩吾','唐','御定全唐诗','yuding','','[]','愛彼山中石泉水，幽深夜夜落空裏。',32,'御定全唐詩/json/494.json','["愛彼山中石泉水，幽深夜夜落空裏。", "至今憶得臥雲時，猶自涓涓在人耳。"]'),
('yuding-42','西山靜中吟','施肩吾','唐','御定全唐诗','yuding','','[]','重重道氣結成神，玉闕金堂逐日新。',32,'御定全唐詩/json/494.json','["重重道氣結成神，玉闕金堂逐日新。", "若數西山得道者，連予便是十三人。"]'),
('yuding-43','天柱山贈峨嵋田道士','施肩吾','唐','御定全唐诗','yuding','','[]','古稱天柱連九天，峨嵋道士棲其巔。',32,'御定全唐詩/json/494.json','["古稱天柱連九天，峨嵋道士棲其巔。", "近聞教得玄鶴舞，試憑驅出青芝田。"]'),
('yuding-44','夜岩謠','施肩吾','唐','御定全唐诗','yuding','','[]','夜上幽岩踏靈草，松枝已疏桂枝老。',32,'御定全唐詩/json/494.json','["夜上幽岩踏靈草，松枝已疏桂枝老。", "新詩幾度惜不吟，此處一聲風月好。"]'),
('yuding-45','島夷行','施肩吾','唐','御定全唐诗','yuding','','[]','腥臊海邊多鬼市，島夷居處無鄉里。',32,'御定全唐詩/json/494.json','["腥臊海邊多鬼市，島夷居處無鄉里。", "黑皮年少學采珠，手把生犀照鹹水。"]'),
('yuding-46','帝宮詞','施肩吾','唐','御定全唐诗','yuding','','[]','自得君王寵愛時，敢言春色上寒枝。',32,'御定全唐詩/json/494.json','["自得君王寵愛時，敢言春色上寒枝。", "十年宮裏無人問，一日承恩天下知。"]'),
('yuding-47','歎花詞','施肩吾','唐','御定全唐诗','yuding','','[]','前日滿林紅錦遍，今日繞林看不見。',32,'御定全唐詩/json/494.json','["前日滿林紅錦遍，今日繞林看不見。", "空餘古岸泥土中，零落胭脂兩三片。"]'),
('yuding-48','杜鵑花詞','施肩吾','唐','御定全唐诗','yuding','','[]','杜鵑花時夭豔然，所恨帝城人不識。',32,'御定全唐詩/json/494.json','["杜鵑花時夭豔然，所恨帝城人不識。", "丁甯莫遣春風吹，留與佳人比顏色。"]'),
('yuding-49','曉光詞','施肩吾','唐','御定全唐诗','yuding','','[]','日輪浮動羲和推，東方一軋天門開。',32,'御定全唐詩/json/494.json','["日輪浮動羲和推，東方一軋天門開。", "風神為我掃煙霧，四海蕩蕩無塵埃。"]'),
('yuding-50','望曉詞','施肩吾','唐','御定全唐诗','yuding','','[]','攬衣起兮望秋河，濛濛遠霧飛輕羅。',32,'御定全唐詩/json/494.json','["攬衣起兮望秋河，濛濛遠霧飛輕羅。", "蟠桃樹上日欲出，白榆枝畔星無多。"]'),
('yuding-51','海邊遠望','施肩吾','唐','御定全唐诗','yuding','','[]','扶桑枝邊紅皎皎，天雞一聲四溟曉。',32,'御定全唐詩/json/494.json','["扶桑枝邊紅皎皎，天雞一聲四溟曉。", "偶看仙女上青天，鸞鶴無多采雲少。"]'),
('yuding-52','聽南僧說偈詞','施肩吾','唐','御定全唐诗','yuding','','[]','師子座中香已發，西方佛偈南僧說。',32,'御定全唐詩/json/494.json','["師子座中香已發，西方佛偈南僧說。", "惠風吹盡六條塵，清淨水中初見月。"]'),
('yuding-53','春日美新綠詞','施肩吾','唐','御定全唐诗','yuding','','[]','前日萌芽小於粟，今朝草樹色已足。',32,'御定全唐詩/json/494.json','["前日萌芽小於粟，今朝草樹色已足。", "天公不語能運為，驅遣羲和染新綠。"]'),
('yuding-54','對月憶嵩陽故人','施肩吾','唐','御定全唐诗','yuding','','[]','團團月光照西壁，嵩陽故人千里隔。',32,'御定全唐詩/json/494.json','["團團月光照西壁，嵩陽故人千里隔。", "不知三十六峰前，定為何處峰前客。"]'),
('yuding-55','贈莎地道士','施肩吾','唐','御定全唐诗','yuding','','[]','莎地陰森古蓮葉，遊龜暗老青苔甲。',32,'御定全唐詩/json/494.json','["莎地陰森古蓮葉，遊龜暗老青苔甲。", "池邊道士誇眼明，夜取蟭螟摘蚊睫。"]'),
('yuding-56','效古詞','施肩吾','唐','御定全唐诗','yuding','','[]','莫愁新得年十六，如蛾雙眉長帶綠。',32,'御定全唐詩/json/494.json','["莫愁新得年十六，如蛾雙眉長帶綠。", "初學箜篌四五人，莫愁獨自聲前足。"]'),
('yuding-57','冬日觀早朝','施肩吾','唐','御定全唐诗','yuding','','[]','紫煙捧日爐香動，萬馬千車踏新凍。',32,'御定全唐詩/json/494.json','["紫煙捧日爐香動，萬馬千車踏新凍。", "繡衣年少朝欲歸，美人猶在青樓夢。"]'),
('yuding-58','觀吳偃畫松','施肩吾','唐','御定全唐诗','yuding','','[]','君有絕藝終身寶，方寸巧心通萬造。',32,'御定全唐詩/json/494.json','["君有絕藝終身寶，方寸巧心通萬造。", "忽然寫出澗底松，筆下看看一枝老。"]'),
('yuding-59','題山僧水閣','施肩吾','唐','御定全唐诗','yuding','','[]','山房水閣連空翠，沉沉下有蛟龍睡。',32,'御定全唐詩/json/494.json','["山房水閣連空翠，沉沉下有蛟龍睡。", "老僧趺坐入定時，不知花落黃金地。"]'),
('yuding-60','登峴亭懷孟生','施肩吾','唐','御定全唐诗','yuding','','[]','峴山自高水自綠，後輩詞人心眼俗。',32,'御定全唐詩/json/494.json','["峴山自高水自綠，後輩詞人心眼俗。", "鹿門才子不再生，怪景幽奇無管屬。"]'),
('yuding-61','吳中代蜀客吟','施肩吾','唐','御定全唐诗','yuding','','[]','身狎吳兒家在蜀，春深屢唱思鄉曲。',32,'御定全唐詩/json/494.json','["身狎吳兒家在蜀，春深屢唱思鄉曲。", "峨眉風景無主人，錦江悠悠為誰綠。"]'),
('yuding-62','戲詠榆莢','施肩吾','唐','御定全唐诗','yuding','','[]','風吹榆錢落如雨，繞林繞屋來不住。',32,'御定全唐詩/json/494.json','["風吹榆錢落如雨，繞林繞屋來不住。", "知爾不堪還酒家，漫教夷甫無行處。"]'),
('yuding-63','寄李補闕','施肩吾','唐','御定全唐诗','yuding','','[]','蒼生應怪君起遲，蒲輪重輾嵩陽道。',32,'御定全唐詩/json/494.json','["蒼生應怪君起遲，蒲輪重輾嵩陽道。", "功成名遂來不及，三十六峰仙鶴老。"]'),
('yuding-64','貧客吟','施肩吾','唐','御定全唐诗','yuding','','[]','l6毯敝衣無處結，寸心耿耿如刀切。',33,'御定全唐詩/json/494.json','["l6毯敝衣無處結，寸心耿耿如刀切。", "今朝欲泣泉客珠，及到盤中卻成血。"]'),
('yuding-65','誚山中叟','施肩吾','唐','御定全唐诗','yuding','','[]','老人今年八十幾，口中零落殘牙齒。',32,'御定全唐詩/json/494.json','["老人今年八十幾，口中零落殘牙齒。", "天陰傴僂帶嗽行，猶向岩前種松子。"]'),
('yuding-66','聞山中步虛聲','施肩吾','唐','御定全唐诗','yuding','','[]','何人步虛南峰頂，鶴唳九天霜月冷。',32,'御定全唐詩/json/494.json','["何人步虛南峰頂，鶴唳九天霜月冷。", "仙詞偶逐東風來，誤飄數聲落塵境。"]'),
('yuding-67','題龍池山人','施肩吾','唐','御定全唐诗','yuding','','[]','主人家在龍池側，水中有魚不敢食。',32,'御定全唐詩/json/494.json','["主人家在龍池側，水中有魚不敢食。", "終朝采藥供仙廚，卻笑桃花少顏色。"]'),
('yuding-68','玩新桃花','施肩吾','唐','御定全唐诗','yuding','','[]','幾歎紅桃開未得，忽驚造化新裝飾。',32,'御定全唐詩/json/494.json','["幾歎紅桃開未得，忽驚造化新裝飾。", "一種同沾榮盛時，偏荷清光借顏色。"]'),
('yuding-69','山石榴花','施肩吾','唐','御定全唐诗','yuding','','[]','深色胭脂碎剪紅，巧能攢合是天公。',32,'御定全唐詩/json/494.json','["深色胭脂碎剪紅，巧能攢合是天公。", "莫言無物堪相比，妖豔西施春驛中。"]'),
('yuding-70','玩友人庭竹','施肩吾','唐','御定全唐诗','yuding','','[]','曾去玄洲看種玉，那似君家滿庭竹。',32,'御定全唐詩/json/494.json','["曾去玄洲看種玉，那似君家滿庭竹。", "客來不用呼清風，此處掛冠涼自足。"]'),
('yuding-71','秋夜山居二首','施肩吾','唐','御定全唐诗','yuding','','[]','幽居正想餐霞客，夜久月寒珠露滴。',64,'御定全唐詩/json/494.json','["幽居正想餐霞客，夜久月寒珠露滴。", "千年獨鶴兩三聲，飛下岩前一枝柏。", "去雁聲遙人語絕，誰家素機織新雪。", "秋山野客醉醒時，百尺老松銜半月。"]'),
('yuding-72','秋夜山中別友人','施肩吾','唐','御定全唐诗','yuding','','[]','獨鶴孤雲兩難說，明朝又作東西別。',32,'御定全唐詩/json/494.json','["獨鶴孤雲兩難說，明朝又作東西別。", "知君少壯無幾年，莫愛閑吟老松月。"]'),
('yuding-73','贈別王煉師往羅浮','施肩吾','唐','御定全唐诗','yuding','','[]','道俗駢闐留不住，羅浮山上有心期。',32,'御定全唐詩/json/494.json','["道俗駢闐留不住，羅浮山上有心期。", "卻愁仙處人難到，別後音書寄與誰。"]'),
('yuding-74','春日餐霞閣','施肩吾','唐','御定全唐诗','yuding','','[]','灑水初晴物候新，餐霞閣上最宜春。',32,'御定全唐詩/json/494.json','["灑水初晴物候新，餐霞閣上最宜春。", "山花四面風吹入，為我鋪床作錦茵。"]'),
('yuding-75','喜友再相逢','施肩吾','唐','御定全唐诗','yuding','','[]','三十年前與君別，可憐容色奪花紅。',32,'御定全唐詩/json/494.json','["三十年前與君別，可憐容色奪花紅。", "誰知日月相催促，此度見君成老翁。"]'),
('yuding-76','候仙詞','施肩吾','唐','御定全唐诗','yuding','','[]','西歸公子何時降，南嶽先生早晚來。',32,'御定全唐詩/json/494.json','["西歸公子何時降，南嶽先生早晚來。", "巡曆世間猶未遍，乞求鸞鶴且裴回。"]'),
('yuding-77','修仙詞','施肩吾','唐','御定全唐诗','yuding','','[]','丹田自種留年藥，玄谷長生續命芝。',32,'御定全唐詩/json/494.json','["丹田自種留年藥，玄谷長生續命芝。", "世上漫忙兼漫走，不知求己更求誰。"]'),
('yuding-78','夏日題方師院','施肩吾','唐','御定全唐诗','yuding','','[]','火天無處買清風，悶發時來入梵宮。',32,'御定全唐詩/json/494.json','["火天無處買清風，悶發時來入梵宮。", "只向方師小廊下，回看門外是樊籠。"]'),
('yuding-79','春遊樂','施肩吾','唐','御定全唐诗','yuding','','[]','一年三百六十日，賞心那似春中物。',32,'御定全唐詩/json/494.json','["一年三百六十日，賞心那似春中物。", "草迷曲塢花滿園，東家少年西家出。"]'),
('yuding-80','仙客歸鄉詞二首','施肩吾','唐','御定全唐诗','yuding','','[]','六合八荒遊未半，子孫零落暫歸來。',64,'御定全唐詩/json/494.json','["六合八荒遊未半，子孫零落暫歸來。", "井邊不認捎雲樹，多是門人在後栽。", "洞中日月洞中仙，不算離家是幾年。", "出郭始知人代變，又須拋卻古時錢。"]'),
