('yuding-171','戲鄭申府','施肩吾','唐','御定全唐诗','yuding','','[]','年少鄭郎那解愁，春來閑臥酒家樓。',32,'御定全唐詩/json/494.json','["年少鄭郎那解愁，春來閑臥酒家樓。", "胡姬若擬邀他宿，掛卻金鞭系紫騮。"]'),
('yuding-172','宿幹越亭','施肩吾','唐','御定全唐诗','yuding','','[]','琵琶洲上人行絕，幹越亭中客思多。',32,'御定全唐詩/json/494.json','["琵琶洲上人行絕，幹越亭中客思多。", "月滿秋江山冷落，不知誰問夜如何。"]'),
('yuding-173','少女詞二首','施肩吾','唐','御定全唐诗','yuding','','[]','嬌羞不肯點新黃，踏過金鈿出繡床。',64,'御定全唐詩/json/494.json','["嬌羞不肯點新黃，踏過金鈿出繡床。", "信物無端寄誰去，等閒裁破錦鴛鴦。", "同心帶裏脫金錢，買取頭花翠羽連。", "手執木蘭猶未慣，今朝初上采菱船。"]'),
('yuding-174','冬詞','施肩吾','唐','御定全唐诗','yuding','','[]','錦繡堆中臥初起，芙蓉面上粉猶殘。',32,'御定全唐詩/json/494.json','["錦繡堆中臥初起，芙蓉面上粉猶殘。", "台前也欲梳雲髻，只怕盤龍手撚難。"]'),
('yuding-175','昭君怨','施肩吾','唐','御定全唐诗','yuding','','[]','馬上徒勞別恨深，總緣如玉不輸金。',32,'御定全唐詩/json/494.json','["馬上徒勞別恨深，總緣如玉不輸金。", "已知賤妾無歸日，空荷君王有悔心。"]'),
('yuding-176','贈仙子','施肩吾','唐','御定全唐诗','yuding','','[]','欲令雪貌帶紅芳，更取金瓶瀉玉漿。',32,'御定全唐詩/json/494.json','["欲令雪貌帶紅芳，更取金瓶瀉玉漿。", "鳳管鶴聲來未足，懶眠秋月憶蕭郎。"]'),
('yuding-177','越溪懷古','施肩吾','唐','御定全唐诗','yuding','','[]','憶昔西施人未求，浣紗曾向此溪頭。',32,'御定全唐詩/json/494.json','["憶昔西施人未求，浣紗曾向此溪頭。", "一朝得侍君王側，不見玉顏空水流。"]'),
('yuding-178','秋夜山中贈別友人','施肩吾','唐','御定全唐诗','yuding','','[]','何處邀君話別情，寒山木落月華清。',32,'御定全唐詩/json/494.json','["何處邀君話別情，寒山木落月華清。", "莫愁今夜無詩思，已聽秋猿第一聲。"]'),
('yuding-179','大堤新詠','施肩吾','唐','御定全唐诗','yuding','','[]','行路少年知不知，襄陽全欠舊來時。',32,'御定全唐詩/json/494.json','["行路少年知不知，襄陽全欠舊來時。", "宜城賈客載錢出，始覺大堤無女兒。"]'),
('yuding-180','宿四明山','施肩吾','唐','御定全唐诗','yuding','','[]','黎洲老人命餘宿，杳然高頂浮雲平。',32,'御定全唐詩/json/494.json','["黎洲老人命餘宿，杳然高頂浮雲平。", "下視不知幾千仞，欲曉不曉天雞聲。"]'),
('yuding-181','禁中新柳','施肩吾','唐','御定全唐诗','yuding','','[]','萬條金錢帶春煙，深染青絲不直錢。',32,'御定全唐詩/json/494.json','["萬條金錢帶春煙，深染青絲不直錢。", "又免生當離別地，宮鴉啼處禁門前。"]'),
('yuding-182','酬張明府','施肩吾','唐','御定全唐诗','yuding','','[]','潘令新詩忽寄來，分明繡段對花開。',32,'御定全唐詩/json/494.json','["潘令新詩忽寄來，分明繡段對花開。", "此時欲醉紅樓裏，正被歌人勸一杯。"]'),
('yuding-183','安吉天甯寺聞磬','施肩吾','唐','御定全唐诗','yuding','','[]','玉磬敲時清夜分，老龍吟斷碧天雲。',32,'御定全唐詩/json/494.json','["玉磬敲時清夜分，老龍吟斷碧天雲。", "鄰房逢見廣州客，曾向羅浮山裏聞。"]'),
('yuding-184','句','施肩吾','唐','御定全唐诗','yuding','','[]','年來如拋梭，不老應不得。。',247,'御定全唐詩/json/494.json','["年來如拋梭，不老應不得。。", "花眼綻紅斟酒看，藥心抽綠帶煙鋤。", "顛狂楚客歌成雪，媚賴吳娘笑是鹽。", "荷翻紫蓋搖波面，蒲瑩青刀插水湄。", "煙黏薜荔龍須軟，雨壓芭蕉鳳翅垂。（二聯並百韻，", "茶為滌煩子，酒為忘憂君。。", "鋤藥顧老叟，焚香呼小青。", "遺卻白雞呼喌喌。。", "五通本是佛家奴，身著青衣一足無。（寺宿為五通所撓作。", "以下見《海錄碎事》）", "天邊有仙藥，為我補三關。", "世人誰不愛年長，所欲皆非保命方。", "但看日及花，惟是朝可憐。。", "池塘已長雞頭葉，籬落初開狗脊花。", "出路船為腳，供官本是奴。", "一言感著熱鐵心，為人劍下偷青娥。", "青鬢丈人不識愁。"]'),
('yuding-0','不赴拾遺召','費冠卿','唐','御定全唐诗','yuding','','[]','君親同是先王道，何如骨肉一處老。',32,'御定全唐詩/json/495.json','["君親同是先王道，何如骨肉一處老。", "也知臣子合佐時，自古榮華誰可保。"]'),
('yuding-1','閒居即事','費冠卿','唐','御定全唐诗','yuding','','[]','生計唯將三尺僮，學他賢者隱牆東。照眠夜後多因月，',40,'御定全唐詩/json/495.json','["生計唯將三尺僮，學他賢者隱牆東。照眠夜後多因月，", "子房仙去孔明死，更有何人解指蹤。"]'),
('yuding-2','酬範中丞見','費冠卿','唐','御定全唐诗','yuding','','[]','花宮柳陌正從行，紫袂金鞍問姓名。戰國方須禮幹木，',40,'御定全唐詩/json/495.json','["花宮柳陌正從行，紫袂金鞍問姓名。戰國方須禮幹木，", "直為雲泥相去遠，一言知己殺身輕。"]'),
('yuding-3','秋日與冷然上人寺莊觀稼','費冠卿','唐','御定全唐诗','yuding','','[]','世人從擾擾，獨自愛身閑。美景當新霽，隨僧過遠山。',48,'御定全唐詩/json/495.json','["世人從擾擾，獨自愛身閑。美景當新霽，隨僧過遠山。", "村橋出秋稼，空翠落澄灣。唯有中林犬，猶應望我還。"]'),
('yuding-4','題中峰','費冠卿','唐','御定全唐诗','yuding','','[]','中峰高拄泬寥天，上有茅庵與石泉。',32,'御定全唐詩/json/495.json','["中峰高拄泬寥天，上有茅庵與石泉。", "晴景獵人曾望見，青藍色裏一僧禪。"]'),
('yuding-5','蒙召拜拾遺書情二首','費冠卿','唐','御定全唐诗','yuding','','[]','拾遺帝側知難得，官緊才微恐不勝。',64,'御定全唐詩/json/495.json','["拾遺帝側知難得，官緊才微恐不勝。", "好是中朝絕親友，九華山下詔來征。", "三千裏外一微臣，二十年來任運身。", "今日忽蒙天子召，自慚驚動國中人。"]'),
('yuding-6','掛樹藤','費冠卿','唐','御定全唐诗','yuding','','[]','本為獨立難，寄彼高樹枝。蔓衍數條遠，溟蒙千朵垂。',48,'御定全唐詩/json/495.json','["本為獨立難，寄彼高樹枝。蔓衍數條遠，溟蒙千朵垂。", "向日助成陰，當風藉持危。誰言柔可屈，坐見蟠蛟螭。"]'),
('yuding-7','枕流石','費冠卿','唐','御定全唐诗','yuding','','[]','不為幽岸隱，古色涵空出。願以清泚流，鑒此堅貞質。',48,'御定全唐詩/json/495.json','["不為幽岸隱，古色涵空出。願以清泚流，鑒此堅貞質。", "傍臨玉光潤，時瀉苔花密。往往驚游鱗，尚疑垂釣日。"]'),
('yuding-8','久居京師感懷詩','費冠卿','唐','御定全唐诗','yuding','','[]','煢獨不為苦，求名始辛酸。上國無交親，請謁多少難。',84,'御定全唐詩/json/495.json','["煢獨不為苦，求名始辛酸。上國無交親，請謁多少難。", "九月風到面，羞汗成冰片。求名俟公道，名與公道遠。", "力盡得一名，他喜我且輕。家書十年絕，歸去知誰榮。", "馬嘶渭橋柳，特地起秋聲。"]'),
('yuding-9','答蕭建','費冠卿','唐','御定全唐诗','yuding','','[]','自地上青峰，懸崖一萬重。踐危頻側足，登塹半齊胸。',217,'御定全唐詩/json/495.json','["自地上青峰，懸崖一萬重。踐危頻側足，登塹半齊胸。", "飛狖啼攀桂，遊人喘倚松。入林寒z9々，近瀑雨濛濛。", "徑滑石棱上，寺開山掌中。幡花撲淨地，台殿印晴空。", "勝境層層別，高僧院院逢。泉魚候洗缽，老玃戲撞鐘。", "外戶憑雲掩，中廚課水舂。搜泥時和麵，拾橡半添穜。", "渡壑緣槎險，持燈入洞窮。夾天開壁峭，透石蹙波雄。", "潤藹清無土，潭深碧有龍。畬田一片淨，谷樹萬株濃。", "野客登臨慣，山房幽寂同。寒爐樹根火，夏牖竹稍風。", "邊鄙籌賢相，黔黎托聖躬。君能棄名利，歲晏一相從。"]'),
('yuding-10','代書問費征君九華亭','蕭建','唐','御定全唐诗','yuding','','[]','見說九華峰上寺，日宮猶在下方開。',32,'御定全唐詩/json/495.json','["見說九華峰上寺，日宮猶在下方開。", "其中幽境客難到，請為詩中圖畫來。"]'),
('yuding-11','獻主文','劉虛白','唐','御定全唐诗','yuding','','[]','二十年前此夜中，一般燈燭一般風。',32,'御定全唐詩/json/495.json','["二十年前此夜中，一般燈燭一般風。", "不知歲月能多少，猶著麻衣待至公。"]'),
('yuding-12','句','劉虛白','唐','御定全唐诗','yuding','','[]','知道醉鄉無戶稅，任他荒卻下丹田。',16,'御定全唐詩/json/495.json','["知道醉鄉無戶稅，任他荒卻下丹田。"]'),
('yuding-13','山出雲','張複','唐','御定全唐诗','yuding','','[]','山靜雲初吐，霏微觸石新。無心離碧岫，有葉占青春。',72,'御定全唐詩/json/495.json','["山靜雲初吐，霏微觸石新。無心離碧岫，有葉占青春。", "散類如虹氣，輕同不讓塵。淩空還似翼，映潤欲成鱗。", "異起臨汾鼎，疑隨出峽神。為霖終濟旱，非獨降賢人。"]'),
('yuding-14','山出雲','張勝之','唐','御定全唐诗','yuding','','[]','片雲初出岫，孤迥色難親。蓋小辭山近，根輕觸石新。',72,'御定全唐詩/json/495.json','["片雲初出岫，孤迥色難親。蓋小辭山近，根輕觸石新。", "飄颻經綠野，明麗照晴春。拂樹疑舒葉，臨流似結鱗。", "從龍方有感，捧日豈無因。看取為霖去，恩沾雨露均。"]'),
('yuding-0','送狄尚書鎮太原','姚合','唐','御定全唐诗','yuding','','[]','授鉞儒生貴，傾朝赴餞筵。麾幢官在省，禮樂將臨邊。',96,'御定全唐詩/json/496.json','["授鉞儒生貴，傾朝赴餞筵。麾幢官在省，禮樂將臨邊。", "代馬龍相雜，汾河海暗連。遠戎移帳幕，高鳥避旌旃。", "天下屯兵處，皇威破虜年。防秋嫌壘近，入塞必身先。", "中外恩重疊，科名歲接連。散材無所用，老向瑣闈眠。"]'),
('yuding-1','送楊尚書祭西嶽','姚合','唐','御定全唐诗','yuding','','[]','報功嚴祀典，寵詔下明庭。酒氣飄林嶺，香煙入杳冥。',60,'御定全唐詩/json/496.json','["報功嚴祀典，寵詔下明庭。酒氣飄林嶺，香煙入杳冥。", "樂清三奏備，詞直百神聽。衣拂雲霞濕，詩通水石靈。", "何因逐騶騎，暫得到岩扃。"]'),
('yuding-2','送李侍禦過夏州','姚合','唐','御定全唐诗','yuding','','[]','酬恩不顧名，走馬覺身輕。迢遞河邊路，蒼茫塞上城。',48,'御定全唐詩/json/496.json','["酬恩不顧名，走馬覺身輕。迢遞河邊路，蒼茫塞上城。", "沙寒無宿雁，虜近少閑兵。飲罷揮鞭去，旁人意氣生。"]'),
('yuding-3','送李起居赴池州','姚合','唐','御定全唐诗','yuding','','[]','天子念疲民，分憂輟侍臣。紅旗高起焰，綠野靜無塵。',48,'御定全唐詩/json/496.json','["天子念疲民，分憂輟侍臣。紅旗高起焰，綠野靜無塵。", "闕下親知別，江南惠化新。朝昏即千里，且願話逡巡。"]'),
('yuding-4','送劉詹事赴壽州','姚合','唐','御定全唐诗','yuding','','[]','殷勤莫遽起，四坐悉同袍。世上詩難得，林中酒更高。',48,'御定全唐詩/json/496.json','["殷勤莫遽起，四坐悉同袍。世上詩難得，林中酒更高。", "隋堤傍楊柳，楚驛在波濤。別後書頻寄，無辭費筆毫。"]'),
('yuding-5','送裴大夫赴亳州','姚合','唐','御定全唐诗','yuding','','[]','杭人遮道路，垂泣浙江前。譙國迎舟艦，行歌汴水邊。',72,'御定全唐詩/json/496.json','["杭人遮道路，垂泣浙江前。譙國迎舟艦，行歌汴水邊。", "周旋君量遠，交代我才偏。寒日嚴旌戟，晴風出管弦。", "一杯誠淡薄，四坐願留連。異政承殊澤，應為天下先。"]'),
('yuding-6','送徐州韋僅行軍','姚合','唐','御定全唐诗','yuding','','[]','餞幕儼征軒，行軍歸大藩。山程度函谷，水驛到夷門。',48,'御定全唐詩/json/496.json','["餞幕儼征軒，行軍歸大藩。山程度函谷，水驛到夷門。", "曉日詩情遠，春風酒色渾。逡巡何足貴，所貴盡殘樽。"]'),
('yuding-7','送劉禹錫郎中赴蘇州','姚合','唐','御定全唐诗','yuding','','[]','三十年來天下名，銜恩東守闔閭城。初經咸穀眠山驛，',80,'御定全唐詩/json/496.json','["三十年來天下名，銜恩東守闔閭城。初經咸穀眠山驛，", "虎丘野寺吳中少，誰伴吟詩月裏行。", "州城全是故吳宮，香徑難尋古蘚中。雲水計程千里遠，", "太守吟詩人自理，小齋閑臥白蘋風。"]'),
('yuding-8','送賈謨赴共城營田','姚合','唐','御定全唐诗','yuding','','[]','上國羞長選，戎裝貴所從。山田依法種，兵食及時供。',48,'御定全唐詩/json/496.json','["上國羞長選，戎裝貴所從。山田依法種，兵食及時供。", "水氣詩書軟，嵐煙筆硯濃。幾時無事擾，相見得從容。"]'),
('yuding-9','送裴宰君','姚合','唐','御定全唐诗','yuding','','[]','見說為官處，煙霞思不窮。夜猿啼戶外，瀑水落廚中。',48,'御定全唐詩/json/496.json','["見說為官處，煙霞思不窮。夜猿啼戶外，瀑水落廚中。", "名藥人難識，仙山路易通。還應施靜化，誰複與君同。"]'),
('yuding-10','送顧非熊下第歸越','姚合','唐','御定全唐诗','yuding','','[]','失意尋歸路，親知不復過。家山去城遠，日月在船多。',48,'御定全唐詩/json/496.json','["失意尋歸路，親知不復過。家山去城遠，日月在船多。", "楚塞數逢雁，浙江長有波。秋風別鄉老，還聽鹿鳴歌。"]'),
('yuding-11','送雍陶游蜀','姚合','唐','御定全唐诗','yuding','','[]','春色三千里，愁人意未開。木梢穿棧出，雨勢隔江來。',48,'御定全唐詩/json/496.json','["春色三千里，愁人意未開。木梢穿棧出，雨勢隔江來。", "荒館因花宿，深山羨客回。相如何物在，應只有琴台。"]'),
('yuding-12','送崔約下第歸揚州','姚合','唐','御定全唐诗','yuding','','[]','滿座詩人吟送酒，離城此會亦應稀。春風下第時稱屈，',40,'御定全唐詩/json/496.json','["滿座詩人吟送酒，離城此會亦應稀。春風下第時稱屈，", "江邊道路多苔蘚，塵土無由得上衣。"]'),
('yuding-13','送李廓侍禦赴西川行營','姚合','唐','御定全唐诗','yuding','','[]','不道弓箭字，罷官唯醉眠。何人薦籌策，走馬逐旌旃。',48,'御定全唐詩/json/496.json','["不道弓箭字，罷官唯醉眠。何人薦籌策，走馬逐旌旃。", "陣變孤虛外，功成語笑前。從今巂州路，無複有烽煙。"]'),
('yuding-14','送楊尚書赴東川','姚合','唐','御定全唐诗','yuding','','[]','卻縠詩書將，銜恩赴梓州。繞身垂印綬，護馬執戈矛。',48,'御定全唐詩/json/496.json','["卻縠詩書將，銜恩赴梓州。繞身垂印綬，護馬執戈矛。", "劍閣和銘峭，巴江帶字流。從來皆惜別，此別複何愁。"]'),
('yuding-15','送邢郎中赴太原','姚合','唐','御定全唐诗','yuding','','[]','上將得良策，恩威作長城。如今並州北，不見有胡兵。',48,'御定全唐詩/json/496.json','["上將得良策，恩威作長城。如今並州北，不見有胡兵。", "晉野雨初足，汾河波亦清。所從古無比，意氣送君行。"]'),
('yuding-16','送裴中丞赴華州','姚合','唐','御定全唐诗','yuding','','[]','我夢何曾應，看君渡滻川。自無仙掌分，非是聖心偏。',48,'御定全唐詩/json/496.json','["我夢何曾應，看君渡滻川。自無仙掌分，非是聖心偏。", "徑草多生藥，庭花半落泉。人間有此郡，況在鳳城邊。"]'),
('yuding-17','送徐員外赴河中從事','姚合','唐','御定全唐诗','yuding','','[]','赤府從軍美，儒衣結束輕。涼飆下山寺，曉浪滿關城。',48,'御定全唐詩/json/496.json','["赤府從軍美，儒衣結束輕。涼飆下山寺，曉浪滿關城。", "閑坐饒詩景，高眠長道情。將軍不戰術，計日立功名。"]'),
('yuding-18','送殷堯藩侍禦赴同州','姚合','唐','御定全唐诗','yuding','','[]','吟詩擲酒船，仙掌白樓前。從事關中貴，主人天下賢。',48,'御定全唐詩/json/496.json','["吟詩擲酒船，仙掌白樓前。從事關中貴，主人天下賢。", "此生無了日，終歲踏離筵。何計因歸去，深山恣意眠。"]'),
('yuding-19','送崔中丞赴鄭州','姚合','唐','御定全唐诗','yuding','','[]','僕射陂前郡，清高越四鄰。丹霄鳳詔下，太守虎符新。',48,'御定全唐詩/json/496.json','["僕射陂前郡，清高越四鄰。丹霄鳳詔下，太守虎符新。", "霧濕關城月，花香驛路塵。連枝相庭樹，歲歲一家春。"]'),
('yuding-20','送丁端公赴河陰','姚合','唐','御定全唐诗','yuding','','[]','炎天木葉焦，曉夕絕涼飆。念子獨歸縣，何人不在朝。',48,'御定全唐詩/json/496.json','["炎天木葉焦，曉夕絕涼飆。念子獨歸縣，何人不在朝。", "市連風浪動，帆徹海門遙。飲盡樽中酒，同年同寂寥。"]'),
('yuding-21','送鄭尚書赴興元','姚合','唐','御定全唐诗','yuding','','[]','儒有登壇貴，何人得此功。紅旗燒密雪，白馬踏長風。',48,'御定全唐詩/json/496.json','["儒有登壇貴，何人得此功。紅旗燒密雪，白馬踏長風。", "斧鉞來天上，詩書理漢中。方知百勝略，應不在彎弓。"]'),
('yuding-22','送田使君赴蔡州','姚合','唐','御定全唐诗','yuding','','[]','長年離別情，百盞酒須傾。詩外應無思，人間半是行。',48,'御定全唐詩/json/496.json','["長年離別情，百盞酒須傾。詩外應無思，人間半是行。", "路遙嘶白馬，林斷出紅旌。功業今應立，淮西有勁兵。"]'),
('yuding-23','送無可上人游邊','姚合','唐','御定全唐诗','yuding','','[]','一缽與三衣，經行遠近隨。出家還養母，持律複能詩。',48,'御定全唐詩/json/496.json','["一缽與三衣，經行遠近隨。出家還養母，持律複能詩。", "春雪離京厚，晨鐘近塞遲。亦知蓮府客，夜坐喜同師。"]'),
('yuding-24','送僧','姚合','唐','御定全唐诗','yuding','','[]','人間擾擾唯閒事，自見高人只有詩。',64,'御定全唐詩/json/496.json','["人間擾擾唯閒事，自見高人只有詩。", "寂寞嵩峰雲外寺，常多夢裏過齋時。", "城中聽得新經論，卻過關東說向人。", "舊國門徒終日望，見時應是見真身。"]'),
('yuding-25','送宋慎言','姚合','唐','御定全唐诗','yuding','','[]','童稚便知聞，如今只有君。百篇詩盡和，一盞酒須分。',48,'御定全唐詩/json/496.json','["童稚便知聞，如今只有君。百篇詩盡和，一盞酒須分。", "驛路多連水，州城半在雲。離情同落葉，向晚更紛紛。"]'),
('yuding-26','送家兄赴任昭義','姚合','唐','御定全唐诗','yuding','','[]','早得白眉名，之官濠上城。別離浮世事，迢遞長年情。',72,'御定全唐詩/json/496.json','["早得白眉名，之官濠上城。別離浮世事，迢遞長年情。", "廣陌垂花影，遙林起雨聲。出關春草長，過汴夏雲生。", "黠吏先潛去，疲人相次迎。宴餘和酒拜，魂夢共東行。"]'),
('yuding-27','送崔玄亮赴果州冬夜宴韓卿宅','姚合','唐','御定全唐诗','yuding','','[]','蘭燭照重茵，飛杯複幾分。主人寒不寐，上客曉離群。',72,'御定全唐詩/json/496.json','["蘭燭照重茵，飛杯複幾分。主人寒不寐，上客曉離群。", "騎吏緣青壁，旌旗度白雲。劍銘生蘚色，巴字疊冰文。", "華省思仙侶，疲民愛使君。泠泠唯自適，郡邸有誰聞。"]'),
('yuding-28','送喻鳧校書歸毗陵','姚合','唐','御定全唐诗','yuding','','[]','主人庭葉黑，詩稿更誰書。闕下科名出，鄉中賦籍除。',48,'御定全唐詩/json/496.json','["主人庭葉黑，詩稿更誰書。闕下科名出，鄉中賦籍除。", "山春煙樹眾，江遠晚帆疏。吾亦家吳者，無因到弊廬。"]'),
('yuding-29','送董正字武歸常州覲親','姚合','唐','御定全唐诗','yuding','','[]','路岐知不盡，離別自無窮。行客心方切，主人樽未空。',48,'御定全唐詩/json/496.json','["路岐知不盡，離別自無窮。行客心方切，主人樽未空。", "楚檣收月下，江樹在潮中。人各還家去，還家慶不同。"]'),
('yuding-30','送蕭正字往蔡州賀裴相淮西平','姚合','唐','御定全唐诗','yuding','','[]','相府旌旄重，還邀上客行。今朝郭門路，初徹蔡州城。',48,'御定全唐詩/json/496.json','["相府旌旄重，還邀上客行。今朝郭門路，初徹蔡州城。", "從馬唯提酒，防身不要兵。從來皆作使，君去是時平。"]'),
('yuding-31','送進士田卓入華山','姚合','唐','御定全唐诗','yuding','','[]','何物隨身去，六經與一琴。辭家計已久，入谷住應深。',48,'御定全唐詩/json/496.json','["何物隨身去，六經與一琴。辭家計已久，入谷住應深。", "偶坐僧同石，閒書葉滿林。業成須謁帝，無貯白雲心。"]'),
('yuding-32','送右司薛員外赴處州','姚合','唐','御定全唐诗','yuding','','[]','懷中天子書，腰下使君魚。瀑布和雲落，仙都與世疏。',48,'御定全唐詩/json/496.json','["懷中天子書，腰下使君魚。瀑布和雲落，仙都與世疏。", "遠程兼水陸，半歲在舟車。相送難相別，南風入夏初。"]'),
('yuding-33','送王建秘書往渭南莊','姚合','唐','御定全唐诗','yuding','','[]','白須芸閣吏，羸馬月中行。莊僻難尋路，官閑易出城。',48,'御定全唐詩/json/496.json','["白須芸閣吏，羸馬月中行。莊僻難尋路，官閑易出城。", "看山多失飯，過寺故題名。秋日田家作，唯添集卷成。"]'),
('yuding-34','送殷堯藩侍禦游山南','姚合','唐','御定全唐诗','yuding','','[]','詩境西南好，秋深晝夜蛩。人家連水影，驛路在山峰。',48,'御定全唐詩/json/496.json','["詩境西南好，秋深晝夜蛩。人家連水影，驛路在山峰。", "谷靜雲生石，天寒雪覆松。我為公府系，不得此相從。"]'),
('yuding-35','送李植侍禦','姚合','唐','御定全唐诗','yuding','','[]','聖代無邪觸，空林獬豸歸。誰知隴山鳥，長繞玉樓飛。',48,'御定全唐詩/json/496.json','["聖代無邪觸，空林獬豸歸。誰知隴山鳥，長繞玉樓飛。", "風雨依山急，雲泉入郭微。無同昔年別，別後寄書稀。"]'),
('yuding-36','送王澹','姚合','唐','御定全唐诗','yuding','','[]','常省為官處，門前數樹松。尋山屐費齒，書石筆無鋒。',48,'御定全唐詩/json/496.json','["常省為官處，門前數樹松。尋山屐費齒，書石筆無鋒。", "果熟猿偷亂，花繁鳥語重。今來為客去，惜取最高峰。"]'),
('yuding-37','送崔之仁','姚合','唐','御定全唐诗','yuding','','[]','欲出還成住，前程甚謫遷。佯眠隨客醉，愁坐似僧禪。',48,'御定全唐詩/json/496.json','["欲出還成住，前程甚謫遷。佯眠隨客醉，愁坐似僧禪。", "舊國歸何處，春山買欠錢。幾時無一事，長在故人邊。"]'),
('yuding-38','送孫山人','姚合','唐','御定全唐诗','yuding','','[]','山翁來帝裏，不肯住多時。塵土衣裳重，腥膻僕隸饑。',48,'御定全唐詩/json/496.json','["山翁來帝裏，不肯住多時。塵土衣裳重，腥膻僕隸饑。", "林中愁不到，城外老應遲。喧寂一為別，相逢未有期。"]'),
('yuding-39','送費驤','姚合','唐','御定全唐诗','yuding','','[]','兄寒弟亦饑，力學少閒時。何路免為客，無門賣得詩。',48,'御定全唐詩/json/496.json','["兄寒弟亦饑，力學少閒時。何路免為客，無門賣得詩。", "幾人攜酒送，獨我入山遲。少小同居止，今朝始別離。"]'),
('yuding-40','送河中楊少府宴崔駙馬宅','姚合','唐','御定全唐诗','yuding','','[]','鳳凰樓下醉醺醺，晚出東門蟬漸聞。不使鄉人治驛路，',40,'御定全唐詩/json/496.json','["鳳凰樓下醉醺醺，晚出東門蟬漸聞。不使鄉人治驛路，", "縣吏若非三載滿，自知無計更尋君。"]'),
('yuding-41','送文著上人游越','姚合','唐','御定全唐诗','yuding','','[]','水石隨緣豈計程，東吳相遇別西京。夜禪月下袈裟濕，',40,'御定全唐詩/json/496.json','["水石隨緣豈計程，東吳相遇別西京。夜禪月下袈裟濕，", "越中多有前朝寺，處處鐵鐘石磬聲。"]'),
('yuding-42','送無可上人遊越','姚合','唐','御定全唐诗','yuding','','[]','清晨相訪立門前，麻履方袍一少年。懶讀經文求作佛，',40,'御定全唐詩/json/496.json','["清晨相訪立門前，麻履方袍一少年。懶讀經文求作佛，", "今日送行偏惜別，共師文字有因緣。"]'),
('yuding-43','送洛陽張員外','姚合','唐','御定全唐诗','yuding','','[]','餞客未歸城，東來騶騎迎。千山嵩嶽峭，百縣洛陽清。',48,'御定全唐詩/json/496.json','["餞客未歸城，東來騶騎迎。千山嵩嶽峭，百縣洛陽清。", "朔雁和雲度，川風吹雨晴。蘚庭公事暇，應只獨吟行。"]'),
('yuding-44','送少府田中丞入西蕃','姚合','唐','御定全唐诗','yuding','','[]','蕭關路絕久，石堠亦為塵。護塞空兵帳，和戎在使臣。',48,'御定全唐詩/json/496.json','["蕭關路絕久，石堠亦為塵。護塞空兵帳，和戎在使臣。", "風沙去國遠，雨雪換衣頻。若問涼州事，涼州多漢人。"]'),
('yuding-45','送王龜處士','姚合','唐','御定全唐诗','yuding','','[]','送客客為誰，朱門處士稀。唯修曾子行，不著老萊衣。',48,'御定全唐詩/json/496.json','["送客客為誰，朱門處士稀。唯修曾子行，不著老萊衣。", "古寺隨僧飯，空林共鳥歸。壺中駐年藥，燒得獻庭闈。"]'),
('yuding-46','送崔郎中赴常州','姚合','唐','御定全唐诗','yuding','','[]','貴是鴒原在紫微，榮逢知己領黃扉。人間盛事今全得，',40,'御定全唐詩/json/496.json','["貴是鴒原在紫微，榮逢知己領黃扉。人間盛事今全得，", "昔年嘗作毗陵客，石峭泉清天下稀。"]'),
('yuding-47','送林使君赴邵州','姚合','唐','御定全唐诗','yuding','','[]','詔書飛下五雲間，才子分符不等閒。驛路算程多是水，',40,'御定全唐詩/json/496.json','["詔書飛下五雲間，才子分符不等閒。驛路算程多是水，", "清淨化人人自理，終朝無事更相關。"]'),
('yuding-48','送別友人','姚合','唐','御定全唐诗','yuding','','[]','獨向山中覓紫芝，山人勾引住多時。摘花浸酒春愁盡，',40,'御定全唐詩/json/496.json','["獨向山中覓紫芝，山人勾引住多時。摘花浸酒春愁盡，", "明朝卻欲歸城市，問我來期總不知。"]'),
('yuding-49','送李琮歸靈州覲省','姚合','唐','御定全唐诗','yuding','','[]','餞席離人起，貪程醉不眠。風沙移道路，僕馬識山川。',48,'御定全唐詩/json/496.json','["餞席離人起，貪程醉不眠。風沙移道路，僕馬識山川。", "塞樹花開小，關城雪下偏。胡塵今已盡，應便促朝天。"]'),
('yuding-50','送任畹評事赴沂海','姚合','唐','御定全唐诗','yuding','','[]','擲筆不作尉，戎衣從嫖姚。嚴冬入都門，僕馬氣益豪。',120,'御定全唐詩/json/496.json','["擲筆不作尉，戎衣從嫖姚。嚴冬入都門，僕馬氣益豪。", "沂州右鎮雄，士勇旌旗高。洛東無憂虞，半夜開虎牢。", "丈夫貴功勳，不貴爵祿饒。仰眠作書生，衣食何由銷。", "任生非常才，臨事膽不搖。必當展長畫，逆波斬鯨鼇。", "九陌塵土黑，話別立遠郊。孟堅勒燕然，豈獨在漢朝。"]'),
('yuding-51','送李餘及第歸蜀','姚合','唐','御定全唐诗','yuding','','[]','蜀山高岧嶢，蜀客無平才。日飲錦江水，文章盈其懷。',192,'御定全唐詩/json/496.json','["蜀山高岧嶢，蜀客無平才。日飲錦江水，文章盈其懷。", "十年作貢賓，九年多邅回。春來登高科，升天得梯階。", "手持冬集書，還家獻庭闈。人生此為榮，得如君者稀。", "李白蜀道難，羞為無成歸。子今稱意行，所曆安覺危。", "與子久相從，今朝忽乖離。風飄海中船，會合難自期。", "長安米價高，伊我常渴饑。臨岐歌送子，無聲但陳詞。", "義交外不親，利交內相違。勉子慎其道，急若食與衣。", "苦爇道路赤，行人念前馳。一杯不可輕，遠別方自茲。"]'),
('yuding-52','送饒州張使君','姚合','唐','御定全唐诗','yuding','','[]','鄱陽勝事聞難比，千里連連是稻畦。山寺去時通水路，',40,'御定全唐詩/json/496.json','["鄱陽勝事聞難比，千里連連是稻畦。山寺去時通水路，", "飲罷春明門外別，蕭條驛路夕陽低。"]'),
('yuding-53','送張宗原','姚合','唐','御定全唐诗','yuding','','[]','東門送客道，春色如死灰。一客失意行，十客顏色低。',144,'御定全唐詩/json/496.json','["東門送客道，春色如死灰。一客失意行，十客顏色低。", "住者既無家，去者又非歸。窮愁一成疾，百藥不可治。", "子賢我且愚，命分不合齊。誰開蹇躓門，日日同遊棲。", "子行何所之，切切食與衣。誰能買仁義，令子無寒饑。", "野田不生草，四向生路岐。士人甚商賈，終日須東西。", "鴻雁春北去，秋風複南飛。勉君向前路，無失相見期。"]'),
('yuding-54','送王求','姚合','唐','御定全唐诗','yuding','','[]','士有經世籌，自無活身策。求食道路間，勞困甚徒役。',120,'御定全唐詩/json/496.json','["士有經世籌，自無活身策。求食道路間，勞困甚徒役。", "我身與子同，日被饑寒迫。側望卿相門，難入堅如石。", "為農昧耕耘，作商迷貿易。空把書卷行，投人買罪責。", "六月南風多，苦旱土色赤。坐家心尚焦，況乃遠作客。", "羸馬出郭門，餞飲曉連夕。願君似醉腸，莫謾生憂戚。"]'),
('yuding-55','送朱慶餘及第後歸越','姚合','唐','御定全唐诗','yuding','','[]','勸君緩上車，鄉里有吾廬。未得同歸去，空令相見疏。',48,'御定全唐詩/json/496.json','["勸君緩上車，鄉里有吾廬。未得同歸去，空令相見疏。", "山晴棲鶴起，天曉落潮初。此慶將誰比，獻親冬集書。"]'),
('yuding-56','送朱慶餘越州歸覲','姚合','唐','御定全唐诗','yuding','','[]','鄉書落姓名，太守拜親榮。訪我波濤郡，還家霧雨城。',48,'御定全唐詩/json/496.json','["鄉書落姓名，太守拜親榮。訪我波濤郡，還家霧雨城。", "海山窗外近，鏡水世間清。何計隨君去，鄰牆過此生。"]'),
('yuding-57','送任尊師歸蜀覲親','姚合','唐','御定全唐诗','yuding','','[]','白雲修道者，歸去春風前。玉簡通仙籍，金丹駐母年。',48,'御定全唐詩/json/496.json','["白雲修道者，歸去春風前。玉簡通仙籍，金丹駐母年。", "錦文江一色，酒氣雨相連。眾說君平死，真師易義全。"]'),
('yuding-58','送友人游蜀','姚合','唐','御定全唐诗','yuding','','[]','送君一壺酒，相別野庭邊。馬上過秋色，舟中到錦川。',48,'御定全唐詩/json/496.json','["送君一壺酒，相別野庭邊。馬上過秋色，舟中到錦川。", "峽猿啼夜雨，蜀鳥噪晨煙。莫便不回首，風光促幾年。"]'),
('yuding-59','送杜立歸蜀','姚合','唐','御定全唐诗','yuding','','[]','迢遞三千里，西南是去程。杜陵家已盡，蜀國客重行。',72,'御定全唐詩/json/496.json','["迢遞三千里，西南是去程。杜陵家已盡，蜀國客重行。", "雪照巴江色，風吹棧閣聲。馬嘶山稍暖，人語店初明。", "旅夢心多感，孤吟氣不平。誰為李白後，為訪錦官城。"]'),
('yuding-60','送韓湘赴江西從事','姚合','唐','御定全唐诗','yuding','','[]','年少登科客，從軍詔命新。行裝有兵器，祖席盡詩人。',72,'御定全唐詩/json/496.json','["年少登科客，從軍詔命新。行裝有兵器，祖席盡詩人。", "細雨湘城暮，微風楚水春。潯陽應足雁，夢澤豈無塵。", "猿叫來山頂，潮痕在樹身。從容多暇日，佳句寄須頻。"]'),
('yuding-61','送潘傳秀才歸宣州','姚合','唐','御定全唐诗','yuding','','[]','李白墳三尺，嵯峨萬古名。因君還故里，為我吊先生。',48,'御定全唐詩/json/496.json','["李白墳三尺，嵯峨萬古名。因君還故里，為我吊先生。", "晴日移虹影，空山出鶴聲。老郎閑未得，無計此中行。"]'),
('yuding-62','送僧默然','姚合','唐','御定全唐诗','yuding','','[]','出家侍母前，至孝自通禪。伏日江頭別，秋風檣下眠。',48,'御定全唐詩/json/496.json','["出家侍母前，至孝自通禪。伏日江頭別，秋風檣下眠。", "鳥聲猿更促，石色樹相連。此路多如此，師行亦有緣。"]'),
('yuding-63','送陟遐上人游天臺','姚合','唐','御定全唐诗','yuding','','[]','萬疊赤城路，終年遊客稀。朝來送師去，自覺有家非。',48,'御定全唐詩/json/496.json','["萬疊赤城路，終年遊客稀。朝來送師去，自覺有家非。", "石淨山光遠，雲深海色微。此詩成亦鄙，為我寫岩扉。"]'),
('yuding-64','送盛秀才赴舉','姚合','唐','御定全唐诗','yuding','','[]','重重吳越浙江潮，刺史何門始得消。五字州人唯有此，',40,'御定全唐詩/json/496.json','["重重吳越浙江潮，刺史何門始得消。五字州人唯有此，", "君去九衢須說我，病成疏懶懶趨朝。"]'),
('yuding-65','送僧貞實歸杭州天竺','姚合','唐','御定全唐诗','yuding','','[]','石橋寺裏最清涼，聞說茆庵寄上方。林外猿聲連院磬，',40,'御定全唐詩/json/496.json','["石橋寺裏最清涼，聞說茆庵寄上方。林外猿聲連院磬，", "九陌相逢千里別，青山重疊樹蒼蒼。"]'),
('yuding-66','送盧二弟茂才罷舉遊洛謁新相','姚合','唐','御定全唐诗','yuding','','[]','踏碎作賦筆，驅車出上京。離筵俯岐路，四坐半公卿。',48,'御定全唐詩/json/496.json','["踏碎作賦筆，驅車出上京。離筵俯岐路，四坐半公卿。", "守命貧難擲，憂身夢數驚。今朝赴知己，休詠苦辛行。"]'),
('yuding-67','送任畹及第歸蜀中覲親','姚合','唐','御定全唐诗','yuding','','[]','子規啼欲死，君聽固無愁。闕下聲名出，鄉中意氣遊。',48,'御定全唐詩/json/496.json','["子規啼欲死，君聽固無愁。闕下聲名出，鄉中意氣遊。", "東川橫劍閣，南斗近刀州。神聖題前字，千人看不休。"]'),
('yuding-68','送杜觀罷舉東游','姚合','唐','御定全唐诗','yuding','','[]','秋風離九陌，心事豈雲安。曾是求名苦，當知此去難。',48,'御定全唐詩/json/496.json','["秋風離九陌，心事豈雲安。曾是求名苦，當知此去難。", "辛勤程自遠，寂寞夜多寒。詩句無人識，應須把劍看。"]'),
('yuding-69','送狄兼謨下第歸故山','姚合','唐','御定全唐诗','yuding','','[]','慈恩塔上名，昨日敗垂成。賃舍應無直，居山豈釣聲。',72,'御定全唐詩/json/496.json','["慈恩塔上名，昨日敗垂成。賃舍應無直，居山豈釣聲。", "半年猶小隱，數日得閒行。映竹窺猿劇，尋雲探鶴情。", "愛花高酒戶，煮藥汙茶鐺。莫便多時住，煙霄路在城。"]'),
('yuding-70','送源中丞赴新羅','姚合','唐','御定全唐诗','yuding','','[]','赤墀賜對使殊方，官重霜台紫綬光。玉節在船清海怪，',40,'御定全唐詩/json/496.json','["赤墀賜對使殊方，官重霜台紫綬光。玉節在船清海怪，", "誰得似君將雨露，海東萬里灑扶桑。"]'),
('yuding-71','送陳倜赴江陵從事','姚合','唐','御定全唐诗','yuding','','[]','荊州勝事眾皆聞，幕下今朝又得君。才子何須藉科第，',40,'御定全唐詩/json/496.json','["荊州勝事眾皆聞，幕下今朝又得君。才子何須藉科第，", "新什定知饒景思，不應一向賦從軍。"]'),
('yuding-72','送張郎中副使赴澤潞','姚合','唐','御定全唐诗','yuding','','[]','曉陌事戎裝，風流粉署郎。機籌通變化，除拜出尋常。',48,'御定全唐詩/json/496.json','["曉陌事戎裝，風流粉署郎。機籌通變化，除拜出尋常。", "地冷饒霜氣，山高礙雁行。應無離別恨，車馬自生光。"]'),
('yuding-73','送陸暢侍禦歸揚州','姚合','唐','御定全唐诗','yuding','','[]','故園偏接近，霅水洞庭邊。歸去知何日，相逢各長年。',60,'御定全唐詩/json/496.json','["故園偏接近，霅水洞庭邊。歸去知何日，相逢各長年。", "山川南北路，風雪別離天。楚色窮冬燒，淮聲獨夜船。", "從軍丞相府，談笑酒杯前。"]'),
('yuding-74','送韋瑤校書赴越','姚合','唐','御定全唐诗','yuding','','[]','寄家臨禹穴，乘傳出秦關。霜落橘滿地，潮來帆近山。',48,'御定全唐詩/json/496.json','["寄家臨禹穴，乘傳出秦關。霜落橘滿地，潮來帆近山。", "相門賓益貴，水國事多閑。晨省高堂後，餘歡杯酒間。"]'),
('yuding-75','送雍陶及第歸覲','姚合','唐','御定全唐诗','yuding','','[]','獻親冬集書，比橘複何如。此去關山遠，相思笑語疏。',48,'御定全唐詩/json/496.json','["獻親冬集書，比橘複何如。此去關山遠，相思笑語疏。", "路尋丹壑斷，人近白雲居。幽石題名處，憑君亦記餘。"]'),
('yuding-76','送李秀才赴舉','姚合','唐','御定全唐诗','yuding','','[]','羅刹樓頭醉，送君西入京。秦吳無限地，山水半分程。',48,'御定全唐詩/json/496.json','["羅刹樓頭醉，送君西入京。秦吳無限地，山水半分程。", "海上煙霞濕，關中日月明。登科舊鄉里，當為改嘉名。"]'),
('yuding-77','送李傳秀才歸宣州','姚合','唐','御定全唐诗','yuding','','[]','謝守青山宅，山孤宅亦平。池塘無複見，春草野中生。',48,'御定全唐詩/json/496.json','["謝守青山宅，山孤宅亦平。池塘無複見，春草野中生。", "常日登樓望，今朝送客行。殷勤拂石壁，為我一書名。"]'),
('yuding-78','送元緒上人游商山','姚合','唐','御定全唐诗','yuding','','[]','萬法空門裏，師修曆幾生。過來心已悟，未到行彌精。',48,'御定全唐詩/json/496.json','["萬法空門裏，師修曆幾生。過來心已悟，未到行彌精。", "溪寂鐘還度，林昏錫獨鳴。朝簪抽未得，此別豈忘情。"]'),
('yuding-79','送僧棲真歸杭州天竺寺','姚合','唐','御定全唐诗','yuding','','[]','吏事日紛然，無因到佛前。勞師相借問，知我亦通禪。',48,'御定全唐詩/json/496.json','["吏事日紛然，無因到佛前。勞師相借問，知我亦通禪。", "古寺杉松出，殘陽鐘磬連。草庵磐石上，歸此是因緣。"]'),
('yuding-80','送敬法師歸福州','姚合','唐','御定全唐诗','yuding','','[]','結得隨緣伴，蟬鳴方出關。新經譯舊寺，故國與誰還。',48,'御定全唐詩/json/496.json','["結得隨緣伴，蟬鳴方出關。新經譯舊寺，故國與誰還。", "齋為無鐘早，心因罷講閑。東南數千里，何處不逢山。"]'),
('yuding-81','送清敬闍黎歸浙西','姚合','唐','御定全唐诗','yuding','','[]','大地無生理，吳中豈是歸。自翻貝葉偈，人施福田衣。',48,'御定全唐詩/json/496.json','["大地無生理，吳中豈是歸。自翻貝葉偈，人施福田衣。", "夏盡灘聲出，潮來日色微。郡齋師去後，寂寞夜吟稀。"]'),
('yuding-82','送賈島及鐘渾','姚合','唐','御定全唐诗','yuding','','[]','日日攻詩亦自強，年年供應在名場。',32,'御定全唐詩/json/496.json','["日日攻詩亦自強，年年供應在名場。", "春風驛路歸何處，紫閣山邊是草堂。"]'),
('yuding-83','送僧游邊','姚合','唐','御定全唐诗','yuding','','[]','師向邊頭去，邊人業障輕。腥膻齋自潔，部落講還成。',48,'御定全唐詩/json/496.json','["師向邊頭去，邊人業障輕。腥膻齋自潔，部落講還成。", "傳教多離寺，隨緣不計程。三千世界內，何處是無生。"]'),
('yuding-84','送澄江上人赴興元鄭尚書招','姚合','唐','御定全唐诗','yuding','','[]','師經非紙上，師佛在心中。覺路何曾異，行人自不同。',48,'御定全唐詩/json/496.json','["師經非紙上，師佛在心中。覺路何曾異，行人自不同。", "水雲晴亦雨，山木夜多風。聞結西方社，尚書待遠公。"]'),
('yuding-85','送馬戴下第客游','姚合','唐','御定全唐诗','yuding','','[]','昨來送君處，亦是九衢中。此日殷勤別，前時寂寞同。',48,'御定全唐詩/json/496.json','["昨來送君處，亦是九衢中。此日殷勤別，前時寂寞同。", "鳥啼寒食雨，花落暮春風。向晚離人起，筵收樽未空。"]'),
('yuding-86','送薛二十三郎中赴婺州','姚合','唐','御定全唐诗','yuding','','[]','我住浙江西，君去浙江東。日日心來往，不畏浙江風。',24,'御定全唐詩/json/496.json','["我住浙江西，君去浙江東。日日心來往，不畏浙江風。"]'),
('yuding-87','送獨孤煥評事赴豐州','姚合','唐','御定全唐诗','yuding','','[]','東門攜酒送廷評，結束從軍塞上行。深磧路移唯馬覺，',40,'御定全唐詩/json/496.json','["東門攜酒送廷評，結束從軍塞上行。深磧路移唯馬覺，", "須鑿燕然山上石，登科記裏是閑名。"]'),
('yuding-88','送張齊物主簿赴內鄉','姚合','唐','御定全唐诗','yuding','','[]','幾年山下事仙翁，名在長生籙籍中。',32,'御定全唐詩/json/496.json','["幾年山下事仙翁，名在長生籙籍中。", "燒得藥成須寄我，曾為主簿與君同。"]'),
('yuding-89','送王嗣之典儀城','姚合','唐','御定全唐诗','yuding','','[]','日日思朝位，偷閒城外行。唯求采藥者，不道在官名。',48,'御定全唐詩/json/496.json','["日日思朝位，偷閒城外行。唯求采藥者，不道在官名。", "好異嫌山淺，尋幽喜徑生。病來文字拙，不要把歸城。"]'),
('yuding-90','別賈島','姚合','唐','御定全唐诗','yuding','','[]','懶作住山人，貧家日賃身。書多筆漸重，睡少枕長新。',48,'御定全唐詩/json/496.json','["懶作住山人，貧家日賃身。書多筆漸重，睡少枕長新。", "野客狂無過，詩仙瘦始真。秋風千里去，誰與我相親。"]'),
('yuding-91','別李餘','姚合','唐','御定全唐诗','yuding','','[]','病童隨瘦馬，難算往來程。野寺僧相送，河橋酒滯行。',48,'御定全唐詩/json/496.json','["病童隨瘦馬，難算往來程。野寺僧相送，河橋酒滯行。", "足愁無道性，久客會人情。何計羈窮盡，同居不出城。"]'),
('yuding-92','別胡逸','姚合','唐','御定全唐诗','yuding','','[]','記得春闈同席試，逡巡何啻十年餘。',32,'御定全唐詩/json/496.json','["記得春闈同席試，逡巡何啻十年餘。", "今日相逢又相送，予乘五馬子單車。"]'),
('yuding-93','惜別','姚合','唐','御定全唐诗','yuding','','[]','酒闌歌罷更遲留，攜手思量憑翠樓。桃李容華猶歎月，',40,'御定全唐詩/json/496.json','["酒闌歌罷更遲留，攜手思量憑翠樓。桃李容華猶歎月，", "似把剪刀裁別恨，兩人分得一般愁。"]'),
('yuding-94','欲別','姚合','唐','御定全唐诗','yuding','','[]','山川重疊遠茫茫，欲別先憂別恨長。紅芍藥花雖共醉，',40,'御定全唐詩/json/496.json','["山川重疊遠茫茫，欲別先憂別恨長。紅芍藥花雖共醉，", "惆悵與君煙景迥，不知何日到瀟湘。"]'),
('yuding-95','別杭州','姚合','唐','御定全唐诗','yuding','','[]','醉與江濤別，江濤惜我遊。他年婚嫁了，終老此江頭。',24,'御定全唐詩/json/496.json','["醉與江濤別，江濤惜我遊。他年婚嫁了，終老此江頭。"]'),
('yuding-0','寄賈島','姚合','唐','御定全唐诗','yuding','','[]','漫向城中住，兒童不識錢。甕頭寒絕酒，灶額曉無煙。',48,'御定全唐詩/json/497.json','["漫向城中住，兒童不識錢。甕頭寒絕酒，灶額曉無煙。", "狂發吟如哭，愁來坐似禪。新詩有幾首，旋被世人傳。"]'),
('yuding-1','寄王度居士','姚合','唐','御定全唐诗','yuding','','[]','憔悴王居士，顛狂不稱時。天公與貧病，時輩複輕欺。',96,'御定全唐詩/json/497.json','["憔悴王居士，顛狂不稱時。天公與貧病，時輩複輕欺。", "茅屋隨年借，盤餐逐日移。棄嫌官似夢，珍重酒如師。", "無竹栽蘆看，思山疊石為。靜窗留客話，古寺覓僧棋。", "瘦馬寒來死，羸童餓得癡。唯應尋阮籍，心事遠相知。"]'),
('yuding-2','寄楊茂卿校書','姚合','唐','御定全唐诗','yuding','','[]','去年別君時，同宿黎陽城。黃河凍欲合，船入冰罅行。',168,'御定全唐詩/json/497.json','["去年別君時，同宿黎陽城。黃河凍欲合，船入冰罅行。", "君為使滑州，我來西入京。丈夫不泣別，旁人歎無情。", "到京就省試，落籍先有名。慚辱鄉薦書，忽欲自受刑。", "還家豈無路，羞為路人輕。決心住城中，百敗望一成。", "腐草眾所棄，猶能化為螢。豈我愚暗身，終久不發明。", "所悲道路長，親愛難合併。還如舟與車，奔走各異程。", "耳目甚短狹，背面若聾盲。安得學白日，遠見君儀形。"]'),
('yuding-3','寄杜師義','姚合','唐','御定全唐诗','yuding','','[]','出處難相見，同城似異鄉。點兵尋戶籍，燒藥試仙方。',48,'御定全唐詩/json/497.json','["出處難相見，同城似異鄉。點兵尋戶籍，燒藥試仙方。", "事校千般別，心還一種忙。黃金如化得，相寄亦何妨。"]'),
('yuding-4','寄陸渾縣尉李景先','姚合','唐','御定全唐诗','yuding','','[]','微俸還同請，唯君獨自閑。地偏無驛路，藥賤管仙山。',48,'御定全唐詩/json/497.json','["微俸還同請，唯君獨自閑。地偏無驛路，藥賤管仙山。", "月色生松裏，泉聲在石間。吟詩複飲酒，何事更相關。"]'),
('yuding-5','寄酬盧侍禦','姚合','唐','御定全唐诗','yuding','','[]','詩新得意恣狂疏，揮手終朝力有餘。',32,'御定全唐詩/json/497.json','["詩新得意恣狂疏，揮手終朝力有餘。", "今到詩家渾手戰，欲題名字倩人書。"]'),
('yuding-6','寄主客張郎中','姚合','唐','御定全唐诗','yuding','','[]','年長方慕道，金丹事參差。故園歸未得，秋風思難持。',96,'御定全唐詩/json/497.json','["年長方慕道，金丹事參差。故園歸未得，秋風思難持。", "蹇拙公府棄，朴靜高人知。以我齊杖屨，昏旭詎相離。", "吟詩紅葉寺，對酒黃菊籬。所賞未及畢，後遊良有期。", "粲粲華省步，屑屑旅客姿。未同山中去，固當殊路岐。"]'),
('yuding-7','寄鄠縣尉李廓少府','姚合','唐','御定全唐诗','yuding','','[]','歲滿休為吏，吟詩著白衣。愛山閑臥久，在世此心稀。',48,'御定全唐詩/json/497.json','["歲滿休為吏，吟詩著白衣。愛山閑臥久，在世此心稀。", "聽鶴向風立，捕魚乘月歸。此君才不及，謬得侍彤闈。"]'),
('yuding-8','寄紫閣隱者','姚合','唐','御定全唐诗','yuding','','[]','自聞憔客說，無計得相尋。幾世傳高臥，全家在一林。',48,'御定全唐詩/json/497.json','["自聞憔客說，無計得相尋。幾世傳高臥，全家在一林。", "養情書覽苦，采藥路多深。願得為鄰里，誰能說此心。"]'),
('yuding-9','寄國子楊巨源祭酒','姚合','唐','御定全唐诗','yuding','','[]','日日新詩出，城中寫不禁。清高疑對竹，閒雅勝聞琴。',48,'御定全唐詩/json/497.json','["日日新詩出，城中寫不禁。清高疑對竹，閒雅勝聞琴。", "門戶饒秋景，兒童解冷吟。雲山今作主，還借外人尋。"]'),
('yuding-10','寄永樂長官殷堯藩','姚合','唐','御定全唐诗','yuding','','[]','故人為吏隱，高臥簿書間。繞院唯栽藥，逢僧只說山。',48,'御定全唐詩/json/497.json','["故人為吏隱，高臥簿書間。繞院唯栽藥，逢僧只說山。", "此宵歡不接，窮歲信空還。何計相尋去，嚴風雪滿關。"]'),
('yuding-11','冬夜書事寄兩省閣老','姚合','唐','御定全唐诗','yuding','','[]','天寒漸覺雁聲疏，新月微微玉漏初。海嶠只宜今日去，',40,'御定全唐詩/json/497.json','["天寒漸覺雁聲疏，新月微微玉漏初。海嶠只宜今日去，", "閣下群公盡高思，誰能攜酒訪貧居。"]'),
('yuding-12','寄靈一律師','姚合','唐','御定全唐诗','yuding','','[]','梵書鈔律千餘紙，淨院焚香獨受持。',32,'御定全唐詩/json/497.json','["梵書鈔律千餘紙，淨院焚香獨受持。", "童子病來煙火絕，清泉漱口過齋時。"]'),
('yuding-13','郡中書事寄默然上人','姚合','唐','御定全唐诗','yuding','','[]','郡中饒野興，過客亦淹留。看月江樓曉，尋山石徑秋。',48,'御定全唐詩/json/497.json','["郡中饒野興，過客亦淹留。看月江樓曉，尋山石徑秋。", "意歸何處老，誰免此生愁。長愛東林子，安禪百事休。"]'),
('yuding-14','寄張徯','姚合','唐','御定全唐诗','yuding','','[]','幽處尋書坐，朝朝閉竹扉。山僧封茗寄，野客乞詩歸。',48,'御定全唐詩/json/497.json','["幽處尋書坐，朝朝閉竹扉。山僧封茗寄，野客乞詩歸。", "秋卷多唯好，時名屈更肥。明年取前字，杯酒賽春輝。"]'),
('yuding-15','寄李頻','姚合','唐','御定全唐诗','yuding','','[]','閉門常不出，惟覺長庭莎。朋友來看少，詩書臥讀多。',48,'御定全唐詩/json/497.json','["閉門常不出，惟覺長庭莎。朋友來看少，詩書臥讀多。", "命隨才共薄，愁與醉相和。珍重君名字，新登甲乙科。"]'),
('yuding-16','寄李群玉','姚合','唐','御定全唐诗','yuding','','[]','九衢名與利，無計擾閒人。道遠期輕世，才高貴重身。',72,'御定全唐詩/json/497.json','["九衢名與利，無計擾閒人。道遠期輕世，才高貴重身。", "石脂稀勝乳，玉粉細於塵。骨換肌膚膩，心靈氣色真。", "嵩山高到日，洛水暖如春。居住應安穩，黃金幾灶新。"]'),
('yuding-17','病中書事寄友人','姚合','唐','御定全唐诗','yuding','','[]','終日自纏繞，此身無適緣。萬愁生雨夜，百病湊衰年。',72,'御定全唐詩/json/497.json','["終日自纏繞，此身無適緣。萬愁生雨夜，百病湊衰年。", "多睡憎明屋，慵行待暖天。瘡頭梳有虱，風耳亂無蟬。", "換白方多錯，回金法不全。家貧何所怨，將在老僧邊。"]'),
('yuding-18','九日寄錢可複','姚合','唐','御定全唐诗','yuding','','[]','數杯黃菊酒，千里白雲天。上國名方振，戎州病未痊。',48,'御定全唐詩/json/497.json','["數杯黃菊酒，千里白雲天。上國名方振，戎州病未痊。", "靜愁惟憶醉，閑走不勝眠。惆悵東門別，相逢知幾年。"]'),
('yuding-19','春日早朝寄劉起居','姚合','唐','御定全唐诗','yuding','','[]','九衢寒霧斂，雙闕曙光分。彩仗迎春日，香煙接瑞雪。',48,'御定全唐詩/json/497.json','["九衢寒霧斂，雙闕曙光分。彩仗迎春日，香煙接瑞雪。", "佩聲清漏間，天語侍臣聞。莫笑馮唐老，還來謁聖君。"]'),
('yuding-20','秋日寄李支使','姚合','唐','御定全唐诗','yuding','','[]','秋思朝來起，侵人暑稍微。曉眠離北戶，午飯尚生衣。',48,'御定全唐詩/json/497.json','["秋思朝來起，侵人暑稍微。曉眠離北戶，午飯尚生衣。", "山靜雲初白，枝高果漸稀。聞君家海上，莫與燕同歸。"]'),
('yuding-21','寄汴州令狐楚相公','姚合','唐','御定全唐诗','yuding','','[]','汴水從今不復渾，秋風鼙鼓動城根。梁園台館關東少，',40,'御定全唐詩/json/497.json','["汴水從今不復渾，秋風鼙鼓動城根。梁園台館關東少，", "幾時詔下歸丹闕，還領千官入閣門。"]'),
('yuding-22','寄東都分司白賓客','姚合','唐','御定全唐诗','yuding','','[]','闕下高眠過十旬，南宮印綬乞離身。詩中得意應千首，',40,'御定全唐詩/json/497.json','["闕下高眠過十旬，南宮印綬乞離身。詩中得意應千首，", "竹齋晚起多無事，唯到龍門寺裏頻。"]'),
('yuding-23','寄裴起居','姚合','唐','御定全唐诗','yuding','','[]','千官曉立爐煙裏，立近丹墀是起居。',32,'御定全唐詩/json/497.json','["千官曉立爐煙裏，立近丹墀是起居。", "彩筆專書皇帝語，書成幾卷太平書。"]'),
('yuding-24','寄狄拾遺，時為魏州從事','姚合','唐','御定全唐诗','yuding','','[]','少在兵馬間，長還系戎職。雞飛不得遠，豈要生羽翼。',144,'御定全唐詩/json/497.json','["少在兵馬間，長還系戎職。雞飛不得遠，豈要生羽翼。", "三年城中游，與君最相識。應知我中腸，不苟念衣食。", "主人樹勳名，欲滅天下賊。愚雖乏智謀，願陳一夫力。", "人生須氣健，饑凍縛不得。睡當一席寬，覺乃千里窄。", "古人不懼死，所懼死無益。至交不可合，一合難離坼。", "君嘗相勸勉，苦語毒胸臆。百年心知同，誰限河南北。"]'),
('yuding-25','金州書事寄山中舊友','姚合','唐','御定全唐诗','yuding','','[]','安康雖好郡，刺史是憨翁。買酒終朝飲，吟詩一室空。',120,'御定全唐詩/json/497.json','["安康雖好郡，刺史是憨翁。買酒終朝飲，吟詩一室空。", "自知為政拙，眾亦覺心公。親事星河在，憂人骨肉同。", "簿書嵐色裏，鼓角水聲中。井邑神州接，帆檣海路通。", "野亭晴帶霧，竹寺夏多風。溉稻長洲白，燒林遠岫紅。", "舊山期已失，芳草思何窮。林下無相笑，男兒五馬雄。"]'),
('yuding-26','寄紫閣無名頭陀','姚合','唐','御定全唐诗','yuding','','[]','峭行得如如，誰分聖與愚。不眠知夢妄，無號免人呼。',48,'御定全唐詩/json/497.json','["峭行得如如，誰分聖與愚。不眠知夢妄，無號免人呼。", "山海禪皆遍，華夷佛豈殊。何因接師話，清淨在斯須。"]'),
('yuding-27','寄郁上人','姚合','唐','御定全唐诗','yuding','','[]','此生修道淺，愁見未來身。誰為傳真諦，唯應是上人。',48,'御定全唐詩/json/497.json','["此生修道淺，愁見未來身。誰為傳真諦，唯應是上人。", "自悲年已長，漸覺事難親。不向禪門去，他門無了因。"]'),
('yuding-28','寄孫路秀才','姚合','唐','御定全唐诗','yuding','','[]','幽居鄰里少，江際複山阿。潮去蟬聲出，天晴鶴語多。',48,'御定全唐詩/json/497.json','["幽居鄰里少，江際複山阿。潮去蟬聲出，天晴鶴語多。", "老人能步蹇，才子奈貧何。曾見春官語，年來虛甲科。"]'),
('yuding-29','寄安陸友人','姚合','唐','御定全唐诗','yuding','','[]','別路在春色，故人雲夢中。鳥啼三月雨，蝶舞百花風。',48,'御定全唐詩/json/497.json','["別路在春色，故人雲夢中。鳥啼三月雨，蝶舞百花風。", "煙束遠山碧，霞欹落照紅。想君登此興，回首念飄蓬。"]'),
('yuding-30','寄馬戴','姚合','唐','御定全唐诗','yuding','','[]','天府鹿鳴客，幽山秋未歸。我知方甚愛，眾說以為非。',48,'御定全唐詩/json/497.json','["天府鹿鳴客，幽山秋未歸。我知方甚愛，眾說以為非。", "隔屋聞泉細，和雲見鶴微。新詩此處得，清峭比應稀。"]'),
('yuding-31','寄賈島，時任普州司倉','姚合','唐','御定全唐诗','yuding','','[]','長沙事可悲，普掾罪誰知。千載人空盡，一家冤不移。',48,'御定全唐詩/json/497.json','["長沙事可悲，普掾罪誰知。千載人空盡，一家冤不移。", "吟寒應齒落，才峭自名垂。地遠山重疊，難傳相憶詞。"]'),
('yuding-32','寄楊工部，聞毗陵舍弟自罨溪入茶山','姚合','唐','御定全唐诗','yuding','','[]','採茶溪路好，花影半浮沉。畫舸僧同上，春山客共尋。',72,'御定全唐詩/json/497.json','["採茶溪路好，花影半浮沉。畫舸僧同上，春山客共尋。", "芳新生石際，幽嫩在山陰。色是春光染，香驚日氣侵。", "試嘗應酒醒，封進定恩深。芳貽千裏外，怡怡太府吟。"]'),
('yuding-33','寄陝州王司馬','姚合','唐','御定全唐诗','yuding','','[]','家寄秦城非本心，偶然頭上有朝簪。自當台直無因醉，',40,'御定全唐詩/json/497.json','["家寄秦城非本心，偶然頭上有朝簪。自當台直無因醉，", "欲知居處堪長久，須向山中學煮金。"]'),
('yuding-34','寄賈島','姚合','唐','御定全唐诗','yuding','','[]','寂寞荒原下，南山只隔籬。家貧唯我並，詩好複誰知。',48,'御定全唐詩/json/497.json','["寂寞荒原下，南山只隔籬。家貧唯我並，詩好複誰知。", "草色無窮處，蟲聲少盡時。朝昏鼓不到，閑臥益相宜。"]'),
('yuding-35','寄崔之仁山人','姚合','唐','御定全唐诗','yuding','','[]','百門坡上住，石屋兩三間。日月難教老，妻兒乞與閑。',48,'御定全唐詩/json/497.json','["百門坡上住，石屋兩三間。日月難教老，妻兒乞與閑。", "仙經揀客問，藥債煮金還。何計能相訪，終身得在山。"]'),
('yuding-36','寄嵩岳程光范','姚合','唐','御定全唐诗','yuding','','[]','相別何容易，相逢便歲年。客來嫌路遠，誰得到君邊。',48,'御定全唐詩/json/497.json','["相別何容易，相逢便歲年。客來嫌路遠，誰得到君邊。", "嶽色鳥啼裏，鐘聲竹影前。只應訪支遁，時得話詩篇。"]'),
('yuding-37','洛下夜會寄賈島','姚合','唐','御定全唐诗','yuding','','[]','洛下攻詩客，相逢只是吟。夜觴歡稍靜，寒屋坐多深。',48,'御定全唐詩/json/497.json','["洛下攻詩客，相逢只是吟。夜觴歡稍靜，寒屋坐多深。", "烏府偶為吏，滄江長在心。憶君難就寢，燭滅複星沉。"]'),
('yuding-38','寄華州李中丞','姚合','唐','御定全唐诗','yuding','','[]','毛女峰前郡，煙霞氣轉清。庭分靈掌影，窗度瀑泉聲。',96,'御定全唐詩/json/497.json','["毛女峰前郡，煙霞氣轉清。庭分靈掌影，窗度瀑泉聲。", "蘚徑人稀到，松齋藥自生。常餐亦芝朮，閑客是公卿。", "看水逢仙鶴，登樓見帝城。養生非酒病，難隱是詩名。", "省署嘗連步，江皋欲獨耕。偶題無六義，聊以達微誠。"]'),
('yuding-39','病中辱諫議惠甘菊藥苗，因以詩贈','姚合','唐','御定全唐诗','yuding','','[]','蕭蕭一畝宮，種菊十餘叢。採摘和芳露，封題寄病翁。',48,'御定全唐詩/json/497.json','["蕭蕭一畝宮，種菊十餘叢。採摘和芳露，封題寄病翁。", "熟宜茶鼎裏，餐稱石甌中。香潔將何比，從來味不同。"]'),
('yuding-40','舟行書事，寄杭州崔員外','姚合','唐','御定全唐诗','yuding','','[]','張頤任酒澆，開眼信花燒。舊國歸何滯，新知別又遙。',48,'御定全唐詩/json/497.json','["張頤任酒澆，開眼信花燒。舊國歸何滯，新知別又遙。", "夜行篙觸石，晚泊纜依橋。若未重相見，無門解寂寥。"]'),
('yuding-41','寄元緒上人','姚合','唐','御定全唐诗','yuding','','[]','石窗紫蘚牆，此世此清涼。研露題詩潔，消冰煮茗香。',48,'御定全唐詩/json/497.json','["石窗紫蘚牆，此世此清涼。研露題詩潔，消冰煮茗香。", "閑雲春影薄，孤磬夜聲長。何計休為吏，從師老草堂。"]'),
('yuding-42','寄白閣默然','姚合','唐','御定全唐诗','yuding','','[]','白閣峰頭雪，城中望亦寒。高僧多默坐，清夜到明看。',48,'御定全唐詩/json/497.json','["白閣峰頭雪，城中望亦寒。高僧多默坐，清夜到明看。", "世上無諸苦，林間只一餐。嘗聞南北教，所得比師難。"]'),
('yuding-43','夏日書事寄丘亢處士','姚合','唐','御定全唐诗','yuding','','[]','暑天難可度，豈複更持觴。樹裏鳴蟬咽，宮中午漏長。',48,'御定全唐詩/json/497.json','["暑天難可度，豈複更持觴。樹裏鳴蟬咽，宮中午漏長。", "病夫心益躁，靜者室應涼。幾欲相尋去，紅塵滿路旁。"]'),
('yuding-44','秋中寄崔道士','姚合','唐','御定全唐诗','yuding','','[]','貧居雀喧噪，況乃靜巷陌。夜眠睡不成，空庭聞露滴。',120,'御定全唐詩/json/497.json','["貧居雀喧噪，況乃靜巷陌。夜眠睡不成，空庭聞露滴。", "旁有一杯酒，歡然如對客。月光久逾明，照得筆墨白。", "平生志舒豁，難可似茲夕。四肢得自便，雖勞不為役。", "故人山中住，善治活身策。五穀口不嘗，比僧更閑寂。", "我今暫得安，自謂脫幽戚。君身長逍遙，日月爭老得。"]'),
('yuding-45','寄華州崔中丞','姚合','唐','御定全唐诗','yuding','','[]','蓮華峰下郡，仙洞亦難勝。閭裏蒼苔水，虛空瀑布冰。',48,'御定全唐詩/json/497.json','["蓮華峰下郡，仙洞亦難勝。閭裏蒼苔水，虛空瀑布冰。", "酒香和藥熟，山峭過雲登。清淨黎人泰，唯憂急詔征。"]'),
('yuding-46','秋日書事，寄秘書竇少監','姚合','唐','御定全唐诗','yuding','','[]','秋氣日騷騷，星星雙鬢毛。涼天吟自遠，清夜夢還高。',48,'御定全唐詩/json/497.json','["秋氣日騷騷，星星雙鬢毛。涼天吟自遠，清夜夢還高。", "林下期同去，人間共是勞。頭巾何所直，且漉甕頭糟。"]'),
('yuding-47','友人南游不回因寄','姚合','唐','御定全唐诗','yuding','','[]','相思春樹綠，千里亦依依。鄠杜月頻滿，瀟湘人不歸。',48,'御定全唐詩/json/497.json','["相思春樹綠，千里亦依依。鄠杜月頻滿，瀟湘人不歸。", "桂花風畔落，煙草蝶雙飛。一別無消息，水南車跡稀。"]'),
('yuding-48','早春山居寄城中知己','姚合','唐','御定全唐诗','yuding','','[]','陽和潛發蕩寒陰，便使川原景象深。入戶風泉聲瀝瀝，',40,'御定全唐詩/json/497.json','["陽和潛發蕩寒陰，便使川原景象深。入戶風泉聲瀝瀝，", "雖有眼前詩酒興，邀遊爭得稱閒心。"]'),
('yuding-49','辭白賓客歸後寄','姚合','唐','御定全唐诗','yuding','','[]','千騎紅旗不可攀，水頭獨立暮方還。',32,'御定全唐詩/json/497.json','["千騎紅旗不可攀，水頭獨立暮方還。", "家人怪我渾如病，尊酒休傾筆硯間。"]'),
('yuding-50','寄右史李定言','姚合','唐','御定全唐诗','yuding','','[]','才歸龍尾含雞舌，更立螭頭運兔毫。',32,'御定全唐詩/json/497.json','["才歸龍尾含雞舌，更立螭頭運兔毫。", "閶闔欲開金漏盡，冕旒初坐禦香高。"]'),
('yuding-51','寄絳州李使君','姚合','唐','御定全唐诗','yuding','','[]','獨施清靜化，千里管橫汾。黎庶應深感，朝廷亦細聞。',72,'御定全唐詩/json/497.json','["獨施清靜化，千里管橫汾。黎庶應深感，朝廷亦細聞。", "心期在黃老，家事是功勳。物外須仙侶，人間要使君。", "花多勻地落，山近滿廳雲。戎客無因去，西看白日曛。"]'),
('yuding-52','寄送盧拱秘書游魏州','姚合','唐','御定全唐诗','yuding','','[]','太行山下路，荊棘昨來平。一自開元後，今逢上客行。',96,'御定全唐詩/json/497.json','["太行山下路，荊棘昨來平。一自開元後，今逢上客行。", "地形吞北虜，人事接東京。掃灑氛埃靜，遊從氣概生。", "薊門春不豔，淇水暖還清。看野風情遠，尋花酒病成。", "官閑身自在，詩逸語縱橫。車馬回應晚，煙光滿去程。"]'),
('yuding-53','秋晚夜坐寄院中諸曹長','姚合','唐','御定全唐诗','yuding','','[]','腰間垂印囊，白髮未歸鄉。還往應相責，朝昏亦自傷。',48,'御定全唐詩/json/497.json','["腰間垂印囊，白髮未歸鄉。還往應相責，朝昏亦自傷。", "窮愁山影峭，獨夜漏聲長。寂寞難成寐，寒燈侵曉光。"]'),
('yuding-54','書懷寄友人','姚合','唐','御定全唐诗','yuding','','[]','精心奉北宗，微宦在南宮。舉世勞為適，開門事不窮。',72,'御定全唐詩/json/497.json','["精心奉北宗，微宦在南宮。舉世勞為適，開門事不窮。", "年來複幾日，蟬去又鳴鴻。衰疾誰人問，閒情與酒通。", "四鄰寒稍靜，九陌夜方空。知老何山是，思歸愚穀中。"]'),
('yuding-55','寄無可上人','姚合','唐','御定全唐诗','yuding','','[]','十二門中寺，詩僧寺獨幽。多年松色別，後夜磬聲秋。',48,'御定全唐詩/json/497.json','["十二門中寺，詩僧寺獨幽。多年松色別，後夜磬聲秋。", "見世慮皆盡，來生事更修。終須執瓶缽，相逐入牛頭。"]'),
('yuding-56','寄暉上人','姚合','唐','御定全唐诗','yuding','','[]','日出月複沒，悠悠昏與明。修持經幾劫，清淨到今生。',48,'御定全唐詩/json/497.json','["日出月複沒，悠悠昏與明。修持經幾劫，清淨到今生。", "林下知無相，人間苦是情。終期逐師去，不擬老塵纓。"]'),
('yuding-57','寄李幹','姚合','唐','御定全唐诗','yuding','','[]','尋常自怪詩無味，雖被人吟不喜聞。',32,'御定全唐詩/json/497.json','["尋常自怪詩無味，雖被人吟不喜聞。", "見說與君同一格，數篇到火卻休焚。"]'),
('yuding-58','寄賈島浪仙','姚合','唐','御定全唐诗','yuding','','[]','悄悄掩門扉，窮窘自維縶。世途已昧履，生計複乖緝。',144,'御定全唐詩/json/497.json','["悄悄掩門扉，窮窘自維縶。世途已昧履，生計複乖緝。", "疏我非常性，端峭爾孤立。往還縱雲久，貧蹇豈自習。", "所居率荒野，寧似在京邑。院落夕彌空，蟲聲雁相及。", "衣巾半僧施，蔬藥常自拾。凜凜寢席單，翳翳灶煙濕。", "頹籬裏人度，敗壁鄰燈入。曉思已暫舒，暮愁還更集。", "風淒林葉萎，苔糝行徑澀。海嶠誓同歸，橡栗充朝給。"]'),
('yuding-59','寄九華費冠卿','姚合','唐','御定全唐诗','yuding','','[]','逍遙罾繳外，高鳥與潛魚。闕下無朝籍，林間有詔書。',60,'御定全唐詩/json/497.json','["逍遙罾繳外，高鳥與潛魚。闕下無朝籍，林間有詔書。", "夜眠青玉洞，曉飯白雲蔬。四海人空老，九華君獨居。", "此心誰複識，日與世情疏。"]'),
('yuding-60','寄不疑上人','姚合','唐','御定全唐诗','yuding','','[]','是法修行遍，方棲不二門。隨緣嫌寺著，見性覺經繁。',48,'御定全唐詩/json/497.json','["是法修行遍，方棲不二門。隨緣嫌寺著，見性覺經繁。", "所歎身將老，始聞師一言。塵沙千萬劫，劫盡佛長存。"]'),
('yuding-61','寄主客劉郎中','姚合','唐','御定全唐诗','yuding','','[]','漢朝共許賈生賢，遷謫還應是宿緣。仰德多時方會面，',40,'御定全唐詩/json/497.json','["漢朝共許賈生賢，遷謫還應是宿緣。仰德多時方會面，", "清景早朝吟麗思，題詩應費益州箋。"]'),
('yuding-62','寄周十七起居','姚合','唐','御定全唐诗','yuding','','[]','冬冬九陌鼓聲齊，百辟朝天馬亂嘶。月照濃霜寒更遠，',40,'御定全唐詩/json/497.json','["冬冬九陌鼓聲齊，百辟朝天馬亂嘶。月照濃霜寒更遠，", "莫笑老人多獨出，晴山荒景覓詩題。"]'),
('yuding-63','秋夜寄默然上人','姚合','唐','御定全唐诗','yuding','','[]','霜月靜幽居，閑吟夢覺初。秋深夜迢遞，年長意蕭疏。',48,'御定全唐詩/json/497.json','["霜月靜幽居，閑吟夢覺初。秋深夜迢遞，年長意蕭疏。", "海上歸難遂，人間事盡虛。賴師方便語，漸得識真如。"]'),
('yuding-64','寄王玄伯','姚合','唐','御定全唐诗','yuding','','[]','夜歸曉出滿衣塵，轉覺才名帶累身。',32,'御定全唐詩/json/497.json','["夜歸曉出滿衣塵，轉覺才名帶累身。", "莫覓舊來終日醉，世間杯酒屬閒人。"]'),
('yuding-65','寄山中友人','姚合','唐','御定全唐诗','yuding','','[]','昨秋今複春，役役是非身。海上無歸路，城中作老人。',48,'御定全唐詩/json/497.json','["昨秋今複春，役役是非身。海上無歸路，城中作老人。", "流年何處在，白日每朝新。聞有長生術，將求未有因。"]'),
('yuding-66','寄陝府內兄郭冏端公','姚合','唐','御定全唐诗','yuding','','[]','蹇鈍無大計，酷嗜進士名。為文性不高，三年住西京。',240,'御定全唐詩/json/497.json','["蹇鈍無大計，酷嗜進士名。為文性不高，三年住西京。", "相府執文柄，念其心專精。薄藝不退辱，特列為門生。", "事出自非意，喜常少於驚。春榜四散飛，數日遍八紘。", "眼始見花發，耳得聞鳥鳴。免同去年春，兀兀聾與盲。", "家寄河朔間，道路出陝城。暌違逾十年，一會豁素誠。", "同遊山水窮，狂飲飛大觥。起坐不相離，有若親弟兄。", "中外無親疏，所算在其情。久客貴優饒，一醉舊疾平。", "家遠歸思切，風雨甚亦行。到茲戀仁賢，淹滯一月程。", "新詩忽見示，氣逸言縱橫。纏綿意千里，騷雅文發明。", "永晝吟不休，咽喉幹無聲。羈貧重金玉，今日金玉輕。"]'),
('yuding-67','寄題蔡州蔣亭兼簡田使君','姚合','唐','御定全唐诗','yuding','','[]','幾歲亂軍裏，蔣亭名不銷。無人知舊徑，有藥長新苗。',48,'御定全唐詩/json/497.json','["幾歲亂軍裏，蔣亭名不銷。無人知舊徑，有藥長新苗。", "樹宿山禽靜，池通野水遙。何因同此醉，永望思蕭條。"]'),
('yuding-68','山居寄友人','姚合','唐','御定全唐诗','yuding','','[]','獨在山阿裏，朝朝遂性情。曉泉和雨落，秋草上階生。',48,'御定全唐詩/json/497.json','["獨在山阿裏，朝朝遂性情。曉泉和雨落，秋草上階生。", "因客始沽酒，借書方到城。詩情聊自遣，不是趁聲名。"]'),
('yuding-69','寄崔之仁山人','姚合','唐','御定全唐诗','yuding','','[]','不得之仁消息久，秋來體色複何如。苦將杯酒判身病，',40,'御定全唐詩/json/497.json','["不得之仁消息久，秋來體色複何如。苦將杯酒判身病，", "幾時身計渾無事，揀取深山一處居。"]'),
('yuding-70','寄主客劉員外','姚合','唐','御定全唐诗','yuding','','[]','蟬稀蟲唧唧，露重思悠悠。靜者多便夜，豪家不見秋。',48,'御定全唐詩/json/497.json','["蟬稀蟲唧唧，露重思悠悠。靜者多便夜，豪家不見秋。", "同歸方欲就，微恙幾時瘳。今日滄江上，何人理釣舟。"]'),
('yuding-71','山中寄友人','姚合','唐','御定全唐诗','yuding','','[]','路岐何渺邈，在客易蹉跎。卻是去家遠，因循住日多。',48,'御定全唐詩/json/497.json','["路岐何渺邈，在客易蹉跎。卻是去家遠，因循住日多。", "幾看春草綠，又見塞鴻過。未有進身處，忍教拋薜蘿。"]'),
('yuding-72','寄友人','姚合','唐','御定全唐诗','yuding','','[]','日暮掩重扉，抽簪複解衣。漏聲林下靜，螢色月中微。',48,'御定全唐詩/json/497.json','["日暮掩重扉，抽簪複解衣。漏聲林下靜，螢色月中微。", "秋霽露華結，夜深人語稀。殷勤故山路，誰與我同歸。"]'),
('yuding-73','寄李餘臥疾','姚合','唐','御定全唐诗','yuding','','[]','窮節彌慘栗，我詎自雲樂。伊人嬰疾恙，所對唯苦藥。',72,'御定全唐詩/json/497.json','["窮節彌慘栗，我詎自雲樂。伊人嬰疾恙，所對唯苦藥。", "寂寞行稍稀，清羸餐自薄。幽齋外浮事，夢寐亦簡略。", "雪戶掩複明，風簾卷還落。方持數杯酒，勉子同斟酌。"]'),
('yuding-74','寄白石師','姚合','唐','御定全唐诗','yuding','','[]','白石師何在，師禪白石中。無情雲可比，不食鳥難同。',48,'御定全唐詩/json/497.json','["白石師何在，師禪白石中。無情雲可比，不食鳥難同。", "屨下蒼苔雪，龕前瀑布風。相尋未有計，只是禮虛空。"]'),
('yuding-75','寄賈島','姚合','唐','御定全唐诗','yuding','','[]','疏拙只如此，此身誰與同。高情向酒上，無事在山中。',48,'御定全唐詩/json/497.json','["疏拙只如此，此身誰與同。高情向酒上，無事在山中。", "漸老病難理，久貧吟益空。賴君時訪宿，不避北齋風。"]'),
('yuding-76','寄默然上人','姚合','唐','御定全唐诗','yuding','','[]','晨餐夜複眠，日與月相連。天下誰無病，人間樂是禪。',48,'御定全唐詩/json/497.json','["晨餐夜複眠，日與月相連。天下誰無病，人間樂是禪。", "幾生通佛性，一室但香煙。結得無為社，還應有宿緣。"]'),
('yuding-77','寄不出院僧','姚合','唐','御定全唐诗','yuding','','[]','不行門外地，齋戒得清真。長食施來飯，深居鎖定身。',48,'御定全唐詩/json/497.json','["不行門外地，齋戒得清真。長食施來飯，深居鎖定身。", "朝昏常傍佛，起坐省逢人。非獨心常淨，衣無一點塵。"]'),
('yuding-78','萬年縣中雨夜會宿寄皇甫甸','姚合','唐','御定全唐诗','yuding','','[]','縣齋還寂寞，夕雨洗蒼苔。清氣燈微潤，寒聲竹共來。',48,'御定全唐詩/json/497.json','["縣齋還寂寞，夕雨洗蒼苔。清氣燈微潤，寒聲竹共來。", "蟲移上階近，客起到門回。想得吟詩處，唯應對酒杯。"]'),
('yuding-79','寄舊山隱者','姚合','唐','御定全唐诗','yuding','','[]','別君須臾間，曆日兩度新。念彼白日長，複值人事並。',168,'御定全唐詩/json/497.json','["別君須臾間，曆日兩度新。念彼白日長，複值人事並。", "未改當時居，心事如野雲。朝朝恣行坐，百事都不聞。", "奈何道未盡，出山最艱辛。奔走衢路間，四枝不屬身。", "名在進士場，筆毫爭等倫。我性本樸直，詞理安得文。", "縱然自稱心，又不合眾人。以此名字低，不如風中塵。", "昨逢賣藥客，雲是居山鄰。說君憶我心，憔悴其形神。", "昔是同枝鳥，今作萬里分。萬里亦未遙，喧靜終難群。"]'),
('yuding-80','新居秋夕寄李廓','姚合','唐','御定全唐诗','yuding','','[]','羈滯多共趣，屢屢同室眠。稍暇更訪詣，寧唯候招延。',120,'御定全唐詩/json/497.json','["羈滯多共趣，屢屢同室眠。稍暇更訪詣，寧唯候招延。", "愧君備蔬藥，識我性所便。罷吏童僕去，灑掃或自專。", "古巷人易息，疏迥自江邊。幸當中秋夕，複此無雲天。", "月華更漏清，露葉光彩鮮。四鄰亦悄悄，中懷益纏綿。", "茲境罕能致，居閑得彌偏。數杯罷複飲，共想山中年。"]'),
('yuding-81','贈盧大夫將軍','姚合','唐','御定全唐诗','yuding','','[]','將軍身在城，詎得虜塵清。釀酒邀閑客，吟詩直禁營。',72,'御定全唐詩/json/497.json','["將軍身在城，詎得虜塵清。釀酒邀閑客，吟詩直禁營。", "蒼鷹春不下，戰馬夜空鳴。碣石應無業，皇州獨有名。", "上山嫌髀重，拔劍歎衣生。公議今如此，登壇到即行。"]'),
('yuding-82','贈供奉僧次融','姚合','唐','御定全唐诗','yuding','','[]','會解如來意，僧家獨有君。開經對天子，騎馬過聲聞。',48,'御定全唐詩/json/497.json','["會解如來意，僧家獨有君。開經對天子，騎馬過聲聞。", "本寺遠於日，新詩高似雲。熱時吟一句，涼冷勝秋分。"]'),
('yuding-83','贈王尊師','姚合','唐','御定全唐诗','yuding','','[]','先生自說瀛洲路，多在青松白石間。海岸夜中常見日，',40,'御定全唐詩/json/497.json','["先生自說瀛洲路，多在青松白石間。海岸夜中常見日，", "今日偶聞塵外事，朝簪未擲複何顏。"]'),
('yuding-84','贈常州院僧','姚合','唐','御定全唐诗','yuding','','[]','一住毗陵寺，師應只信緣。院貧人施食，窗靜鳥窺禪。',48,'御定全唐詩/json/497.json','["一住毗陵寺，師應只信緣。院貧人施食，窗靜鳥窺禪。", "古磬聲難盡，秋燈色更鮮。仍聞開講日，湖上少魚船。"]'),
('yuding-85','贈盧沙彌小師','姚合','唐','御定全唐诗','yuding','','[]','怕見世間事，削頭披佛衣。年小未受戒，會解如老師。',120,'御定全唐詩/json/497.json','["怕見世間事，削頭披佛衣。年小未受戒，會解如老師。", "天與出家腸，一食齋不饑。麻履踏雪路，與馬不肯騎。", "嫌我身腥膻，似我見戎夷。彼此見會異，對面成別離。", "我師文宣王，立教垂書詩。但全仁義心，自然便慈悲。", "兩教大體同，無處辨是非。莫以衣服別，到頭不相知。"]'),
('yuding-86','贈張籍太祝','姚合','唐','御定全唐诗','yuding','','[]','絕妙江南曲，淒涼怨女詩。古風無手敵，新語是人知。',120,'御定全唐詩/json/497.json','["絕妙江南曲，淒涼怨女詩。古風無手敵，新語是人知。", "飛動應由格，功夫過卻奇。麟台添集卷，樂府換歌詞。", "李白應先拜，劉禎必自疑。貧須君子救，病合國家醫。", "野客開山借，鄰僧與米炊。甘貧辭聘幣，依選受官資。", "多見愁連曉，稀聞債盡時。聖朝文物盛，太祝獨低眉。"]'),
('yuding-87','贈丘郎中','姚合','唐','御定全唐诗','yuding','','[]','繞籬栽杏種黃精，曉侍爐煙暮出城。',32,'御定全唐詩/json/497.json','["繞籬栽杏種黃精，曉侍爐煙暮出城。", "萬事將身求總易，學君難得是長生。"]'),
('yuding-88','贈王建司馬','姚合','唐','御定全唐诗','yuding','','[]','久向空門隱，交親亦不知。文高輕古意，官冷似前資。',48,'御定全唐詩/json/497.json','["久向空門隱，交親亦不知。文高輕古意，官冷似前資。", "老覺僧齋健，貧還酒債遲。仙方小字寫，行坐把相隨。"]'),
('yuding-89','贈任士曹','姚合','唐','御定全唐诗','yuding','','[]','憲皇十一祀，共得春闈書。道直淹曹掾，命通侍玉除。',48,'御定全唐詩/json/497.json','["憲皇十一祀，共得春闈書。道直淹曹掾，命通侍玉除。", "浮生年月促，九陌笑言疏。何計同歸去，滄江有弊廬。"]'),
('yuding-90','贈劉叉','姚合','唐','御定全唐诗','yuding','','[]','自君離海上，垂釣更何人。獨宿空堂雨，閑行九陌塵。',48,'御定全唐詩/json/497.json','["自君離海上，垂釣更何人。獨宿空堂雨，閑行九陌塵。", "避時曾變姓，救難似嫌身。何處相期宿，咸陽酒市春。"]'),
('yuding-91','贈僧紹明','姚合','唐','御定全唐诗','yuding','','[]','西方清淨路，此路出何門。見說師知處，從來佛不言。',48,'御定全唐詩/json/497.json','["西方清淨路，此路出何門。見說師知處，從來佛不言。", "今生多病惱，自曉至黃昏。唯寐方無事，那堪夢亦喧。"]'),
('yuding-92','贈張質山人','姚合','唐','御定全唐诗','yuding','','[]','先生居處僻，荊棘與牆齊。酒好寧論價，詩狂不著題。',48,'御定全唐詩/json/497.json','["先生居處僻，荊棘與牆齊。酒好寧論價，詩狂不著題。", "燒成度世藥，踏盡上山梯。懶聽閒人語，爭如穀鳥啼。"]'),
('yuding-93','贈少室山麻襦僧','姚合','唐','御定全唐诗','yuding','','[]','只辮麻為衲，此中經幾春。庵前多猛獸，徑小絕行人。',48,'御定全唐詩/json/497.json','["只辮麻為衲，此中經幾春。庵前多猛獸，徑小絕行人。", "泉近濆瓶履，山深少垢塵。想師正法指，喻我獨迷津。"]'),
('yuding-94','贈王山人','姚合','唐','御定全唐诗','yuding','','[]','賢哲論獨誕，吾宗次定今。詩吟天地廣，覺印果因深。',48,'御定全唐詩/json/497.json','["賢哲論獨誕，吾宗次定今。詩吟天地廣，覺印果因深。", "教演歸恭敬，名標中外欽。既能施六度，了悟達雙林。"]'),
('yuding-95','贈終南山傅山人','姚合','唐','御定全唐诗','yuding','','[]','七十未成事，終南蒼鬢翁。老來詩興苦，貧去酒腸空。',96,'御定全唐詩/json/497.json','["七十未成事，終南蒼鬢翁。老來詩興苦，貧去酒腸空。", "蟠蟄身仍病，鵬摶力未通。已無燒藥本，唯有著書功。", "白馬時何晚，青龍歲欲終。生涯枯葉下，家口亂雲中。", "潭靜魚驚水，天晴鶴唳風。悲君還姓傅，獨不夢高宗。"]'),
('yuding-96','使兩浙贈羅隱','姚合','唐','御定全唐诗','yuding','','[]','平日時風好涕流，讒書雖盛一名休。寰區歎屈瞻天問，',40,'御定全唐詩/json/497.json','["平日時風好涕流，讒書雖盛一名休。寰區歎屈瞻天問，", "何當世祖從人望，早以公台命卓侯。"]'),
('yuding-0','閒居遣懷十首','姚合','唐','御定全唐诗','yuding','','[]','身外無徭役，開門百事閑。倚松聽唳鶴，策杖望秋山。',480,'御定全唐詩/json/498.json','["身外無徭役，開門百事閑。倚松聽唳鶴，策杖望秋山。", "萍任連池綠，苔從匝地斑。料無車馬客，何必掃柴關。", "閑臥銷長日，親朋笑我疏。詩篇隨分有，人事度年無。", "情性僻難改，愁懷酒為除。誰能思此計，空備滿床書。", "白日逍遙過，看山複繞池。展書尋古事，翻卷改新詩。", "賒酒風前酌，留僧竹裏棋。同人笑相問，羨我足閒時。", "好景時牽目，茅齋興有餘。遠山經雨後，庭樹得秋初。", "道侶憐栽藥，高人笑養魚。優遊隨本性，甘被棄慵疏。", "永日廚煙絕，何曾暫廢吟。閒時隨思緝，小酒恣情斟。", "看月嫌松密，垂綸愛水深。世間多少事，無事可關心。", "一生能幾日，愁恨也無端。遇酒酕醄飲，逢花爛熳看。", "青雲非失路，白髮未相干。以此多攜解，將心但自寬。", "萬事徒紛擾，難關枕上身。朗吟銷白日，沈醉度青春。", "演步憐山近，閑眠厭客頻。市朝曾不到，長免滿衣塵。", "野性多疏惰，幽棲更稱情。獨行看影笑，閑坐弄琴聲。", "懶拜腰肢硬，慵趨禮樂生。業文隨日遣，不是為求名。", "生計甘寥落，高名愧自由。慣無身外事，不信世間愁。", "好酒盈杯酌，閑詩任筆酬。涼風從入戶，雲水更宜秋。", "拙直難和洽，從人笑掩關。不能行戶外，甯解走塵間。", "被酒長酣思，無愁可上顏。何言歸去事，著處是青山。"]'),
('yuding-1','武功縣中作三十首','姚合','唐','御定全唐诗','yuding','','[]','縣去帝城遠，為官與隱齊。馬隨山鹿放，雞雜野禽棲。',576,'御定全唐詩/json/498.json','["縣去帝城遠，為官與隱齊。馬隨山鹿放，雞雜野禽棲。", "繞舍惟藤架，侵階是藥畦。更師嵇叔夜，不擬作書題。", "方拙天然性，為官是事疏。惟尋向山路，不寄入城書。", "因病多收藥，緣餐學釣魚。養身成好事，此外更空虛。", "微官如馬足，只是在泥塵。到處貧隨我，終年老趁人。", "簿書銷眼力，杯酒耗心神。早作歸休計，深居養此身。", "簿書多不會，薄俸亦難銷。醉臥慵開眼，閑行懶系腰。", "移花兼蝶至，買石得雲饒。且自心中樂，從他笑寂寥。", "曉鐘驚睡覺，事事便相關。小市柴薪貴，貧家砧杵閑。", "讀書多旋忘，賒酒數空還。長羨劉伶輩，高眠出世間。", "性疏常愛臥，親故笑悠悠。縱出多攜枕，因衙始裹頭。", "上山方覺老，過寺暫忘愁。三考千餘日，低腰不擬休。", "客至皆相笑，詩書滿臥床。愛閑求病假，因醉棄官方。", "鬢髮寒唯短，衣衫瘦漸長。自嫌多檢束，不似舊來狂。", "一日看除目，終年損道心。山宜沖雪上，詩好帶風吟。", "野客嫌知印，家人笑買琴。只應隨分過，已是錯彌深。", "鄰里皆相愛，門開數見過。秋涼送客遠，夜靜詠詩多。", "就架題書目，尋欄記藥窠。到官無別事，種得滿庭莎。", "窮達天應與，人間事莫論。微官長似客，遠縣豈勝村。", "竟日多無食，連宵不閉門。齋心調筆硯，唯寫五千言。", "縣僻仍牢落，遊人到便回。路當邊地去，村入郭門來。", "酒戶愁偏長，詩情病不開。可曾衙小吏，恐謂踏青苔。", "自下青山路，三年著綠衣。官卑食肉僭，才短事人非。", "野客教長醉，高僧勸早歸。不知何計是，免與本心違。"]'),
('yuding-2','罷武功縣將入城','姚合','唐','御定全唐诗','yuding','','[]','乍拋衫笏覺身輕，依舊還稱學道名。欲泥山僧分屋住，',80,'御定全唐詩/json/498.json','["乍拋衫笏覺身輕，依舊還稱學道名。欲泥山僧分屋住，", "無奈同官珍重意，幾回臨路卻休行。", "青衫脫下便狂歌，種薤栽莎劚古坡。野客相逢添酒病，", "欲與九衢親故別，明朝拄杖始經過。"]'),
('yuding-3','秋日閒居二首','姚合','唐','御定全唐诗','yuding','','[]','九陌宅重重，何門憐此翁。荒庭唯菊茂，幽徑與山通。',96,'御定全唐詩/json/498.json','["九陌宅重重，何門憐此翁。荒庭唯菊茂，幽徑與山通。", "落葉帶衣上，閑雲來酒中。此心誰得見，林下鹿應同。", "先憶花時節，家山聽更歸。愛詩看古集，憶酒典寒衣。", "睡少身還健，愁多食不肥。自憐疏懶性，無事出門稀。"]'),
('yuding-4','閒居晚夏','姚合','唐','御定全唐诗','yuding','','[]','閒居無事擾，舊病亦多痊。選字詩中老，看山屋外眠。',48,'御定全唐詩/json/498.json','["閒居無事擾，舊病亦多痊。選字詩中老，看山屋外眠。", "片霞侵落日，繁葉咽鳴蟬。對此心還樂，誰知乏酒錢。"]'),
('yuding-5','閒居','姚合','唐','御定全唐诗','yuding','','[]','不自識疏鄙，終年住在城。過門無馬跡，滿宅是蟬聲。',48,'御定全唐詩/json/498.json','["不自識疏鄙，終年住在城。過門無馬跡，滿宅是蟬聲。", "帶病吟雖苦，休官夢已清。何當學禪觀，依止古先生。"]'),
('yuding-6','街西居三首','姚合','唐','御定全唐诗','yuding','','[]','受得山野性，住城多事違。青山在宅南，回首東西稀。',144,'御定全唐詩/json/498.json','["受得山野性，住城多事違。青山在宅南，回首東西稀。", "淺淺一井泉，數家同汲之。獨我惡水濁，鑿井庭之陲。", "自鑿還自飲，亦為眾所非。籲嗟世間事，潔身誠難為。", "日出窮巷喜，溫然勝重衣。重衣豈不暖，所暖人不齊。", "兀兀複行行，不離階與墀。", "丈夫非馬蹄，安得知路岐。窮賤餐茹薄，興與養性宜。", "乃知長生術，豪貴難得之。"]'),
('yuding-7','閒居遣興','姚合','唐','御定全唐诗','yuding','','[]','終年城裏住，門戶似山林。客怪身名晚，妻嫌酒病深。',48,'御定全唐詩/json/498.json','["終年城裏住，門戶似山林。客怪身名晚，妻嫌酒病深。", "寫方多識藥，失譜廢彈琴。文字非經濟，空虛用破心。"]'),
('yuding-8','莊居即事','姚合','唐','御定全唐诗','yuding','','[]','休看小字大書名，向日持經眼卻明。時過無心求富貴，',40,'御定全唐詩/json/498.json','["休看小字大書名，向日持經眼卻明。時過無心求富貴，", "斜月照床新睡覺，西風半夜鶴來聲。"]'),
('yuding-9','親仁裏居','姚合','唐','御定全唐诗','yuding','','[]','三年賃舍親仁裏，寂寞何曾似在城。飲酒自緣防冷病，',40,'御定全唐詩/json/498.json','["三年賃舍親仁裏，寂寞何曾似在城。飲酒自緣防冷病，", "自別青山歸未得，羨君長聽石泉聲。"]'),
('yuding-10','莊居野行','姚合','唐','御定全唐诗','yuding','','[]','客行野田間，比屋皆閉戶。借問屋中人，盡去作商賈。',120,'御定全唐詩/json/498.json','["客行野田間，比屋皆閉戶。借問屋中人，盡去作商賈。", "官家不稅商，稅農服作苦。居人盡東西，道路侵壟畝。", "采玉上山顛，探珠入水府。邊兵索衣食，此物同泥土。", "古來一人耕，三人食猶饑。如今千萬家，無一把鋤犁。", "我倉常空虛，我田生蒺藜。上天不雨粟，何由活烝黎。"]'),
('yuding-11','春日閒居','姚合','唐','御定全唐诗','yuding','','[]','居止日蕭條，庭前唯藥苗。身閑眠自久，眼荖視還遙。',48,'御定全唐詩/json/498.json','["居止日蕭條，庭前唯藥苗。身閑眠自久，眼荖視還遙。", "簷燕酬鶯語，鄰花雜絮飄。客來無酒飲，搔首擲空瓢。"]'),
('yuding-12','獨居','姚合','唐','御定全唐诗','yuding','','[]','深閉柴門長不出，功夫自課少閒時。翻音免問他人字，',40,'御定全唐詩/json/498.json','["深閉柴門長不出，功夫自課少閒時。翻音免問他人字，", "到頭歸向青山是，塵路茫茫欲告誰。"]'),
('yuding-13','早春閒居','姚合','唐','御定全唐诗','yuding','','[]','寂寞日何為，閒居春色遲。驚風起庭雪，寒雨長簷澌。',48,'御定全唐詩/json/498.json','["寂寞日何為，閒居春色遲。驚風起庭雪，寒雨長簷澌。", "強飲樽中酒，嘲山世外詩。此生仍且在，難與老相離。"]'),
('yuding-14','原上新居','姚合','唐','御定全唐诗','yuding','','[]','秋來梨果熟，行哭小兒饑。鄰富雞長往，莊貧客漸稀。',48,'御定全唐詩/json/498.json','["秋來梨果熟，行哭小兒饑。鄰富雞長往，莊貧客漸稀。", "借牛耕地晚，賣樹納錢遲。牆下當官道，依前夾竹籬。"]'),
('yuding-15','將歸山','姚合','唐','御定全唐诗','yuding','','[]','野人慣去山中住，自到城來悶不勝。宮樹蟬聲多卻樂，',40,'御定全唐詩/json/498.json','["野人慣去山中住，自到城來悶不勝。宮樹蟬聲多卻樂，", "聞道舊溪茆屋畔，春風新上數枝藤。"]'),
('yuding-16','山中述懷','姚合','唐','御定全唐诗','yuding','','[]','為客久未歸，寒山獨掩扉。曉來山鳥散，雨過杏花稀。',48,'御定全唐詩/json/498.json','["為客久未歸，寒山獨掩扉。曉來山鳥散，雨過杏花稀。", "天遠雲空積，溪深水自微。此情對春色，盡醉欲忘機。"]'),
('yuding-17','偶然書懷','姚合','唐','御定全唐诗','yuding','','[]','十年通籍入金門，自愧名微枉搢紳。煉得丹砂疑不食，',40,'御定全唐詩/json/498.json','["十年通籍入金門，自愧名微枉搢紳。煉得丹砂疑不食，", "漢有馮唐唐有我，老為郎吏更何人。"]'),
('yuding-18','客舍有懷','姚合','唐','御定全唐诗','yuding','','[]','旅人無事喜，終日思悠悠。逢酒嫌杯淺，尋書怕字稠。',48,'御定全唐詩/json/498.json','["旅人無事喜，終日思悠悠。逢酒嫌杯淺，尋書怕字稠。", "貧來許錢聖，夢覺見身愁。寂寞中林下，饑鷹望到秋。"]'),
('yuding-19','及第後夜中書事','姚合','唐','御定全唐诗','yuding','','[]','夜睡常驚起，春光屬野夫。新銜添一字，舊友遜前途。',72,'御定全唐詩/json/498.json','["夜睡常驚起，春光屬野夫。新銜添一字，舊友遜前途。", "喜過還疑夢，狂來不似儒。愛花持燭看，憶酒犯街沽。", "天上名應定，人間盛更無。報恩丞相合，何啻殺微軀。"]'),
('yuding-20','偶題','姚合','唐','御定全唐诗','yuding','','[]','年年九陌看春還，舊隱空勞夢寐間。遲日逍遙芸草長，',40,'御定全唐詩/json/498.json','["年年九陌看春還，舊隱空勞夢寐間。遲日逍遙芸草長，", "道侶書來相責誚，朝朝欲報作何顏。"]'),
('yuding-21','感時','姚合','唐','御定全唐诗','yuding','','[]','憶昔未出身，索寞無精神。逢人話天命，自賤如埃塵。',72,'御定全唐詩/json/498.json','["憶昔未出身，索寞無精神。逢人話天命，自賤如埃塵。", "君今才出身，颯爽鞍馬春。逢人話天命，自重如千鈞。", "信涉名利道，舉動皆喪真。君今自世情，何況天下人。"]'),
('yuding-22','憶山','姚合','唐','御定全唐诗','yuding','','[]','閑處無人到，乖疏稱野情。日高搔首起，林下散衣行。',48,'御定全唐詩/json/498.json','["閑處無人到，乖疏稱野情。日高搔首起，林下散衣行。", "泉引窗前過，雲看石罅生。別來愁欲老，虛負出山名。"]'),
('yuding-23','客遊旅懷','姚合','唐','御定全唐诗','yuding','','[]','客行無定止，終日路岐間。馬為賒來貴，僮緣借得頑。',48,'御定全唐詩/json/498.json','["客行無定止，終日路岐間。馬為賒來貴，僮緣借得頑。", "詩書愁觸雨，店舍喜逢山。舊業嵩陽下，三年未得還。"]'),
('yuding-24','迎春','姚合','唐','御定全唐诗','yuding','','[]','半年留醉待花開，曉去迎春夜始回。風暖慢行尋曲水，',40,'御定全唐詩/json/498.json','["半年留醉待花開，曉去迎春夜始回。風暖慢行尋曲水，", "今日柳條全弄色，遊人相伴看春來。"]'),
('yuding-25','遊春十二首','姚合','唐','御定全唐诗','yuding','','[]','正月一日後，尋春更不眠。自知還近僻，眾說過於顛。',576,'御定全唐詩/json/498.json','["正月一日後，尋春更不眠。自知還近僻，眾說過於顛。", "看水甯依路，登山欲到天。悠悠芳思起，多是晚風前。", "官卑長少事，縣僻又無城。未曉沖寒起，迎春忍病行。", "樹枝風掉軟，菜甲土浮輕。好個林間鵲，今朝足喜聲。", "詩酒相牽引，朝朝思不窮。苔痕雪水裏，春色竹煙中。", "迎雨緣池草，摧花倚樹風。書非名利事，愛此少人同。", "塵中主印吏，誰遣有高情。趁暖簷前坐，尋芳樹底行。", "土融凝墅色，冰敗滿池聲。漸覺春相泥，朝來睡不輕。", "疏頑無異事，隨例但添年。舊曆藏深篋，新衣薄絮綿。", "暖風渾酒色，晴日暢琴弦。同伴無辭困，遊春貴在先。", "看春長不足，豈更覺身勞。寺裏花枝淨，山中水色高。", "嫩雲輕似絮，新草細如毛。並起詩人思，還應費筆毫。", "悠悠小縣吏，憔悴入新年。遠思遭詩惱，閒情被酒牽。", "戀花林下飲，愛草野中眠。疏懶今成性，誰人肯更憐。", "處處春光遍，遊人亦不稀。向陽傾冷酒，看影試新衣。", "嫩樹行移長，幽禽語旋飛。同來皆去盡，沖夜獨吟歸。", "朝朝看春色，春色似相憐。酒醒鶯啼裏，詩成蝶舞前。", "摘花盈手露，折竹滿庭煙。親故多相笑，疏狂似少年。", "卑官還不惡，行止得逍遙。晴野花侵路，春陂水上橋。", "塵埃生暖色，藥草長新苗。看卻煙光散，狂風處處飄。", "身被春光引，經時更不歸。嚼花香滿口，書竹粉黏衣。", "弄日鶯狂語，迎風蝶倒飛。自知疏懶性，得事亦應稀。", "曉脫青衫出，閑行氣味長。一瓶春酒色，數頃野花香。", "朝客聞應羨，山僧見亦狂。不將僮僕去，恐為損風光。"]'),
('yuding-26','賞春','姚合','唐','御定全唐诗','yuding','','[]','閒人只是愛春光，迎得春來喜欲狂。買酒怕遲教走馬，',40,'御定全唐詩/json/498.json','["閒人只是愛春光，迎得春來喜欲狂。買酒怕遲教走馬，", "顛倒醉眠三數日，人間百事不思量。"]'),
('yuding-27','春日即事','姚合','唐','御定全唐诗','yuding','','[]','春來眠不得，誰複念生涯。夜聽四鄰樂，朝尋九陌花。',48,'御定全唐詩/json/498.json','["春來眠不得，誰複念生涯。夜聽四鄰樂，朝尋九陌花。", "輕煙浮草色，微雨濯年華。乞假非關病，朝衣在酒家。"]'),
('yuding-28','春日江次','姚合','唐','御定全唐诗','yuding','','[]','野步出茆齋，閑行坐石台。久悲鄉路遠，猶喜杏花開。',48,'御定全唐詩/json/498.json','["野步出茆齋，閑行坐石台。久悲鄉路遠，猶喜杏花開。", "鷗鷺皆飛去，帆檣何處來。因凝千里目，落日尚徘徊。"]'),
('yuding-29','揚州春詞三首','姚合','唐','御定全唐诗','yuding','','[]','廣陵寒食天，無霧複無煙。暖日凝花柳，春風散管弦。',144,'御定全唐詩/json/498.json','["廣陵寒食天，無霧複無煙。暖日凝花柳，春風散管弦。", "園林多是宅，車馬少於船。莫喚遊人住，遊人困不眠。", "滿郭是春光，街衢土亦香。竹風輕履舄，花露膩衣裳。", "穀鳥鳴還豔，山夫到更狂。可憐遊賞地，煬帝國傾亡。", "江北煙光裏，淮南勝事多。市鄽持燭入，鄰里漾船過。", "有地惟栽竹，無家不養鵝。春風蕩城郭，滿耳是笙歌。"]'),
('yuding-30','寒食二首','姚合','唐','御定全唐诗','yuding','','[]','今朝一百五，出戶雨初晴。舞愛雙飛蝶，歌聞百囀鶯。',96,'御定全唐詩/json/498.json','["今朝一百五，出戶雨初晴。舞愛雙飛蝶，歌聞百囀鶯。", "江深青草岸，花滿白雲城。為政多孱懦，應無酷吏名。", "出城煙火少，況複是今朝。閑坐將誰語，臨觴只自謠。", "階前春蘚遍，衣上落花飄。伎樂州人戲，使君心寂寥。"]'),
('yuding-31','暮春書事','姚合','唐','御定全唐诗','yuding','','[]','窮巷少芳菲，蒼苔一徑微。酒醒聞客別，年長送春歸。',48,'御定全唐詩/json/498.json','["窮巷少芳菲，蒼苔一徑微。酒醒聞客別，年長送春歸。", "宿願眠雲嶠，浮名系鎖闈。未因丞相庇，難得脫朝衣。"]'),
('yuding-32','春晚雨中','姚合','唐','御定全唐诗','yuding','','[]','寂寂春將老，閒人強自歡。迎風鶯語澀，帶雨蝶飛難。',48,'御定全唐詩/json/498.json','["寂寂春將老，閒人強自歡。迎風鶯語澀，帶雨蝶飛難。", "傍砌木初長，眠花景漸闌。臨軒平目望，情思若為寬。"]'),
('yuding-33','送春','姚合','唐','御定全唐诗','yuding','','[]','昨迎今複送，來晚去逡巡。芳盡空繁樹，愁多獨病身。',48,'御定全唐詩/json/498.json','["昨迎今複送，來晚去逡巡。芳盡空繁樹，愁多獨病身。", "靜思傾酒懶，閑望上樓頻。為向春風道，明年早報春。"]'),
('yuding-34','別春','姚合','唐','御定全唐诗','yuding','','[]','留春不得被春欺，春若無情遣泥誰。寂寞自疑生冷病，',40,'御定全唐詩/json/498.json','["留春不得被春欺，春若無情遣泥誰。寂寞自疑生冷病，", "一去近當三百日，從朝至夜是相思。"]'),
('yuding-35','夏夜','姚合','唐','御定全唐诗','yuding','','[]','閑齋深夜靜，獨坐又閑行。密樹月籠影，疏籬水隔聲。',48,'御定全唐詩/json/498.json','["閑齋深夜靜，獨坐又閑行。密樹月籠影，疏籬水隔聲。", "斷猿時叫穀，棲鳥每搖檉。寂寞求名士，誰知此夕情。"]'),
('yuding-36','秋日有懷','姚合','唐','御定全唐诗','yuding','','[]','秋來不復眠，但覺思悠然。菊色欲經露，蟲聲漸替蟬。',48,'御定全唐詩/json/498.json','["秋來不復眠，但覺思悠然。菊色欲經露，蟲聲漸替蟬。", "詩情生酒裏，心事在山邊。舊裏無因到，西風又一年。"]'),
('yuding-37','秋夕遣懷','姚合','唐','御定全唐诗','yuding','','[]','昨宵白露下，秋氣滿山城。風勁衣巾脆，窗虛筆墨輕。',48,'御定全唐詩/json/498.json','["昨宵白露下，秋氣滿山城。風勁衣巾脆，窗虛筆墨輕。", "臨書愛真跡，避酒怕狂名。只擬隨麋鹿，悠悠過一生。"]'),
('yuding-38','秋中夜坐','姚合','唐','御定全唐诗','yuding','','[]','疏散永無事，不眠常夜分。月中松露滴，風引鶴同聞。',24,'御定全唐詩/json/498.json','["疏散永無事，不眠常夜分。月中松露滴，風引鶴同聞。"]'),
('yuding-39','同衛尉崔少卿九月六日飲','姚合','唐','御定全唐诗','yuding','','[]','酒熟菊還芳，花飄盞亦香。與君先一醉，舉世待重陽。',48,'御定全唐詩/json/498.json','["酒熟菊還芳，花飄盞亦香。與君先一醉，舉世待重陽。", "風色初晴利，蟲聲向晚長。此時如不飲，心事亦應傷。"]'),
('yuding-40','九日憶硯山舊居','姚合','唐','御定全唐诗','yuding','','[]','帝裏閒人少，誰同把酒杯。硯山籬下菊，今日幾枝開。',48,'御定全唐詩/json/498.json','["帝裏閒人少，誰同把酒杯。硯山籬下菊，今日幾枝開。", "曉角驚眠起，秋風引病來。長年歸思切，更值雁聲催。"]'),
('yuding-41','秋晚江次','姚合','唐','御定全唐诗','yuding','','[]','蕭蕭晚景寒，獨立望江壖。沙渚幾行雁，風灣一隻船。',48,'御定全唐詩/json/498.json','["蕭蕭晚景寒，獨立望江壖。沙渚幾行雁，風灣一隻船。", "落霞澄返照，孤嶼隔微煙。極目思無盡，鄉心到眼前。"]'),
('yuding-42','除夜二首','姚合','唐','御定全唐诗','yuding','','[]','衰殘歸未遂，寂寞此宵情。舊國當千里，新年隔數更。',96,'御定全唐詩/json/498.json','["衰殘歸未遂，寂寞此宵情。舊國當千里，新年隔數更。", "寒猶近北峭，風漸向東生。誰見長安陌，晨鐘度火城。", "殷勤惜此夜，此夜在逡巡。燭盡年還別，雞鳴老更新。", "儺聲方去疫，酒色已迎春。明日持杯處，誰為最後人。"]'),
('yuding-43','晦日送窮三首','姚合','唐','御定全唐诗','yuding','','[]','年年到此日，瀝酒拜街中。萬戶千門看，無人不送窮。',72,'御定全唐詩/json/498.json','["年年到此日，瀝酒拜街中。萬戶千門看，無人不送窮。", "送窮窮不去，相泥欲何為。今日官家宅，淹留又幾時。", "古人皆恨別，此別恨消魂。只是空相送，年年不出門。"]'),
('yuding-44','詠雲','姚合','唐','御定全唐诗','yuding','','[]','靄靄紛紛不可窮，戛笙歌處盡隨龍。來依銀漢一千里，',40,'御定全唐詩/json/498.json','["靄靄紛紛不可窮，戛笙歌處盡隨龍。來依銀漢一千里，", "憐君翠染雙蟬鬢，鏡裏朝朝近玉容。"]'),
('yuding-45','詠雪','姚合','唐','御定全唐诗','yuding','','[]','愁雲殘臘下陽臺，混卻乾坤六出開。與月交光呈瑞色，',40,'御定全唐詩/json/498.json','["愁雲殘臘下陽臺，混卻乾坤六出開。與月交光呈瑞色，", "其那知音不相見，剡溪乘興為君來。"]'),
('yuding-46','郡中對雪','姚合','唐','御定全唐诗','yuding','','[]','霏微著草樹，漸布與階平。遠近如空色，飄颺無落聲。',48,'御定全唐詩/json/498.json','["霏微著草樹，漸布與階平。遠近如空色，飄颺無落聲。", "飛鴉疑翅重，去馬覺蹄輕。遙想故山下，樵夫應滯行。"]'),
('yuding-47','對月','姚合','唐','御定全唐诗','yuding','','[]','銀輪玉兔向東流，瑩淨三更正好遊。',32,'御定全唐詩/json/498.json','["銀輪玉兔向東流，瑩淨三更正好遊。", "一片黑雲何處起，皂羅籠卻水精球。"]'),
('yuding-48','八月十五夜看月','姚合','唐','御定全唐诗','yuding','','[]','亭亭千萬里，三五複秋中。此夕光應絕，常時思不同。',48,'御定全唐詩/json/498.json','["亭亭千萬里，三五複秋中。此夕光應絕，常時思不同。", "九霄微有露，四海靜無風。惆悵逡巡別，誰能看碧空。"]'),
('yuding-49','賦月華臨靜夜','姚合','唐','御定全唐诗','yuding','','[]','長空埃壒滅，皎皎月華臨。色正秋將半，光鮮夜自深。',72,'御定全唐詩/json/498.json','["長空埃壒滅，皎皎月華臨。色正秋將半，光鮮夜自深。", "九霄晴更徹，四野氣難侵。靜照遙山出，孤明列宿沉。", "高人應不寐，驚鵲複何心。漏盡東方曉，佳期何處尋。"]'),
('yuding-50','酬任疇協律夏中苦雨見寄','姚合','唐','御定全唐诗','yuding','','[]','銀漢波瀾溢，經旬雨未休。細聽宜隔牖，遠望憶高樓。',264,'御定全唐詩/json/498.json','["銀漢波瀾溢，經旬雨未休。細聽宜隔牖，遠望憶高樓。", "風急飄還斷，雲低落更稠。走童驚掣電，饑鳥啄浮漚。", "絲網張空際，蛛繩續瓦溝。青蛙多入戶，潢潦欲勝舟。", "雷怒疑山破，池渾似土流。灰人漫禳厭，水馬恣沈浮。", "廣陌應翻浪，貧居恐作湫。陽精藏不耀，陰氣盛難收。", "遠色重林暮，繁聲四壁秋。望晴思見日，防冷欲披裘。", "枕潤眠還懶，車羸出轉憂。散空煙漠漠，迸溜竹修修。", "樹暗蟬吟咽，巢傾燕語愁。琴書涼簟淨，燈燭夜窗幽。", "天下那能向，龍邊豈易求。濕煙凝灶額，荒草覆牆頭。", "酒思淒方罷，詩情耿始抽。下床先仗屐，汲井恐飄甌。", "危坐徒相憶，佳期未有由。勞君寄新什，終日不能酬。"]'),
('yuding-51','和座主相公雨中作','姚合','唐','御定全唐诗','yuding','','[]','清氣潤華屋，東風吹雨勻。花低驚豔重，竹淨覺聲真。',72,'御定全唐詩/json/498.json','["清氣潤華屋，東風吹雨勻。花低驚豔重，竹淨覺聲真。", "山際凝如霧，雲中散似塵。蕭蕭下碧落，點點救生民。", "緩灑雷霆細，微沾瓦礫新。詩成難繼和，造化筆通神。"]'),
('yuding-52','惡神行雨','姚合','唐','御定全唐诗','yuding','','[]','凶神扇pQ惡神行，洶湧挨排白霧生。風擊水凹波撲凸，',41,'御定全唐詩/json/498.json','["凶神扇pQ惡神行，洶湧挨排白霧生。風擊水凹波撲凸，", "哮吼忽雷聲揭石，滿天啾唧鬧轟轟。"]'),
('yuding-53','苦雨','姚合','唐','御定全唐诗','yuding','','[]','江昏山半晴，南阻絕人行。葭菼連雲色，松杉共雨聲。',48,'御定全唐詩/json/498.json','["江昏山半晴，南阻絕人行。葭菼連雲色，松杉共雨聲。", "早秋仍燕舞，深夜更鼉鳴。為報迷津客，訛言未可輕。"]'),
('yuding-0','題鳳翔西郭新亭','姚合','唐','御定全唐诗','yuding','','[]','西郭塵埃外，新亭制度奇。地形當要處，人力是閒時。',192,'御定全唐詩/json/499.json','["西郭塵埃外，新亭制度奇。地形當要處，人力是閒時。", "結構方殊絕，高低更合宜。棟樑清俸買，松竹遠山移。", "佛寺幽難敵，仙家景可追。良工慚巧盡，上客恨逢遲。", "兩面寒波漲，當前軟柳垂。清虛宜月入，涼冷勝風吹。", "宴賞軍容靜，登臨妓樂隨。魚龍聽弦管，鳧鶴識旌旗。", "泛鷁春流闊，飛觴白日欹。閑花長在戶，嫩蘚乍緣墀。", "永望情無極，頻來困不辭。雲峰晴轉翠，煙樹曉逾滋。", "向野惟貪靜，臨空遽覺危。行人如不到，遊樂更何為。"]'),
('yuding-1','題金州西園九首：江榭','姚合','唐','御定全唐诗','yuding','','[]','亭亭白雲榭，下有清江流。見江不得親，不如波上鷗。',36,'御定全唐詩/json/499.json','["亭亭白雲榭，下有清江流。見江不得親，不如波上鷗。", "有榭江可見，無榭無雙眸。"]'),
('yuding-2','題金州西園九首：藥堂','姚合','唐','御定全唐诗','yuding','','[]','僮僕不到閾，雙扉常自關。四壁畫遠水，堂前聳秋山。',36,'御定全唐詩/json/499.json','["僮僕不到閾，雙扉常自關。四壁畫遠水，堂前聳秋山。", "時聞有仙鼠，竊藥簷隙間。"]'),
('yuding-3','題金州西園九首：草閣','姚合','唐','御定全唐诗','yuding','','[]','編草覆柏椽，軒扉皆竹織。合成似僧居，學僧居未得。',36,'御定全唐詩/json/499.json','["編草覆柏椽，軒扉皆竹織。合成似僧居，學僧居未得。", "有時公府勞，還複來此息。"]'),
('yuding-4','題金州西園九首：松壇','姚合','唐','御定全唐诗','yuding','','[]','盤盤松上蓋，下覆青石壇。月中零露垂，日出露尚漙。',36,'御定全唐詩/json/499.json','["盤盤松上蓋，下覆青石壇。月中零露垂，日出露尚漙。", "山翁稱絕境，海橋無所觀。"]'),
('yuding-5','題金州西園九首：葼徑','姚合','唐','御定全唐诗','yuding','','[]','藥院徑亦高，往來踏葼影。方當繁暑日，草屩微微冷。',36,'御定全唐詩/json/499.json','["藥院徑亦高，往來踏葼影。方當繁暑日，草屩微微冷。", "愛此不能行，折薪坐煎茗。"]'),
('yuding-6','題金州西園九首：垣竹','姚合','唐','御定全唐诗','yuding','','[]','種竹愛庭際，亦以資玩賞。窮秋雨蕭條，但見牆垣長。',36,'御定全唐詩/json/499.json','["種竹愛庭際，亦以資玩賞。窮秋雨蕭條，但見牆垣長。", "宣尼高數仞，固應非土壤。"]'),
('yuding-7','題金州西園九首：石庭','姚合','唐','御定全唐诗','yuding','','[]','布石滿山庭，磷磷潔還清。幽人常履此，月下屐齒鳴。',36,'御定全唐詩/json/499.json','["布石滿山庭，磷磷潔還清。幽人常履此，月下屐齒鳴。", "藥草枝葉動，似向山中生。"]'),
('yuding-8','題金州西園九首：莓苔','姚合','唐','御定全唐诗','yuding','','[]','茅堂階豈高，數寸是苔蘚。只恐秋雨中，窗戶亦不濺。',36,'御定全唐詩/json/499.json','["茅堂階豈高，數寸是苔蘚。只恐秋雨中，窗戶亦不濺。", "眼前無此物，我情何由遣。"]'),
('yuding-9','題金州西園九首：芭蕉屏','姚合','唐','御定全唐诗','yuding','','[]','芭蕉叢叢生，月照參差影。數葉大如牆，作我門之屏。',36,'御定全唐詩/json/499.json','["芭蕉叢叢生，月照參差影。數葉大如牆，作我門之屏。", "稍稍聞見稀，耳目得安靜。"]'),
('yuding-10','杏溪十首：杏溪','姚合','唐','御定全唐诗','yuding','','[]','桃花四散飛，桃子壓枝垂。寂寂青陰裏，幽人舉步遲。',36,'御定全唐詩/json/499.json','["桃花四散飛，桃子壓枝垂。寂寂青陰裏，幽人舉步遲。", "殷勤念此徑，我去複來誰。"]'),
('yuding-11','杏溪十首：蓮塘','姚合','唐','御定全唐诗','yuding','','[]','方塘菡萏高，繁豔相照耀。幽人夜眠起，忽疑野中燒。',36,'御定全唐詩/json/499.json','["方塘菡萏高，繁豔相照耀。幽人夜眠起，忽疑野中燒。", "曉尋不知休，白石岸亦峭。"]'),
('yuding-12','杏溪十首：架水藤','姚合','唐','御定全唐诗','yuding','','[]','濛濛紫花藤，下複清溪水。若遣隨波流，不如風飄起。',36,'御定全唐詩/json/499.json','["濛濛紫花藤，下複清溪水。若遣隨波流，不如風飄起。", "風飄或近堤，隨波千萬里。"]');
